/**
 * Get field definition by name
 */
export function getFieldDefinition(fieldName: string): FieldDefinition | null {
  return FIELD_DEFINITIONS[fieldName] ?? null;
}

/**
 * Validate a field value
 */
export function validateField(fieldName: string, value: string): boolean {
  const field = FIELD_DEFINITIONS[fieldName];
  if (!field) return true; // Unknown field, allow

  if (field.required && (!value || value.trim() === "")) {
    return false;
  }

  if (field.validation && value) {
    return field.validation.test(value);
  }

  return true;
}

/**
 * Generate field prompt for a template
 * Returns the text to ask the user for missing fields
 */
export function generateFieldPrompt(templateId: string, missingFields: string[]): string {
  const template = TEMPLATE_REGISTRY[templateId.padStart(2, "0")];
  if (!template || missingFields.length === 0) return "";

  const lines: string[] = [];
  lines.push(`I'll create the ${template.name} for you. Please provide:`);
  lines.push("");

  for (const fieldName of missingFields) {
    const field = FIELD_DEFINITIONS[fieldName];
    if (field) {
      lines.push(`**${field.label}** (e.g., ${field.example})`);
      lines.push("");
    }
  }

  return lines.join("\n").trim();
}

/**
 * Get required fields for a template
 */
export function getRequiredFields(templateId: string): FieldDefinition[] {
  const template = TEMPLATE_REGISTRY[templateId.padStart(2, "0")];
  if (!template) return [];

  return template.requiredFields
    .map(name => FIELD_DEFINITIONS[name])
    .filter((f): f is FieldDefinition => f !== undefined);
}

/**
 * Get optional fields for a template
 */
export function getOptionalFields(templateId: string): FieldDefinition[] {
  const template = TEMPLATE_REGISTRY[templateId.padStart(2, "0")];
  if (!template?.optionalFields) return [];

  return template.optionalFields
    .map(name => FIELD_DEFINITIONS[name])
    .filter((f): f is FieldDefinition => f !== undefined);
}

/**
 * Check if all required fields are present in extracted data
 */
export function hasAllRequiredFields(templateId: string, extractedFields: Record<string, string>): boolean {
  const template = TEMPLATE_REGISTRY[templateId.padStart(2, "0")];
  if (!template) return false;

  for (const fieldName of template.requiredFields) {
    const value = extractedFields[fieldName];
    if (!value || value.trim() === "") {
      return false;
    }
  }

  return true;
}

/**
 * Get list of missing required fields
 */
export function getMissingFields(templateId: string, extractedFields: Record<string, string>): string[] {
  const template = TEMPLATE_REGISTRY[templateId.padStart(2, "0")];
  if (!template) return [];

  const missing: string[] = [];
  for (const fieldName of template.requiredFields) {
    const value = extractedFields[fieldName];
    if (!value || value.trim() === "") {
      missing.push(fieldName);
    }
  }

  return missing;
}

/**
 * Sophia Memory Service
 *
 * Provides RAG-based user recognition, conversation memory, and knowledge base search.
 * Uses Supabase pgvector for semantic similarity search.
 */

import { LogCategory, logger } from "../utils/logger.ts";
import { getSupabaseAdmin } from "../../_shared/db.ts";

const supabase = getSupabaseAdmin();

// Google AI API for embeddings (check both possible env var names)
const GOOGLE_API_KEY =
  Deno.env.get("GOOGLE_API_KEY") || Deno.env.get("GEMINI_API_KEY");

// Embedding model configuration
// text-embedding-004 was deprecated Jan 14, 2026 → replaced by gemini-embedding-001
const EMBEDDING_MODEL = "gemini-embedding-001";

// =====================================================
// Embedding Cache (LRU with TTL)
// =====================================================

interface CachedEmbedding {
  embedding: number[];
  timestamp: number;
}

const embeddingCache = new Map<string, CachedEmbedding>();
const CACHE_TTL_MS = 3_600_000; // 1 hour
const MAX_CACHE_SIZE = 1000;

/**
 * LRU-style cache eviction - remove oldest entries when cache is full
 */
function evictOldestCacheEntries(): void {
  if (embeddingCache.size < MAX_CACHE_SIZE) return;

  // Convert to array, sort by timestamp, remove oldest 10%
  const entries = Array.from(embeddingCache.entries());
  entries.sort((a, b) => a[1].timestamp - b[1].timestamp);

  const toRemove = Math.ceil(MAX_CACHE_SIZE * 0.1);
  for (let i = 0; i < toRemove && i < entries.length; i++) {
    embeddingCache.delete(entries[i][0]);
  }
  logger.debug(`[Memory] Cache eviction: removed ${toRemove} oldest entries`, {
    category: LogCategory.CACHE,
  });
}

