// =====================================================
// Embedding Generation
// =====================================================

/**
 * Generate embedding vector for text using Google's text-embedding-004 model.
 * Uses in-memory LRU cache with TTL to reduce API calls.
 * Falls back to null if API key not configured.
 */
export async function generateEmbedding(
  text: string
): Promise<number[] | null> {
  if (!GOOGLE_API_KEY) {
    logger.warn("[Memory] GOOGLE_API_KEY not set - embeddings disabled", {
      category: LogCategory.AI,
    });
    return null;
  }

  // Check cache first (normalize text for consistent keys)
  const cacheKey = text.toLowerCase().trim();
  const cached = embeddingCache.get(cacheKey);

  if (cached && Date.now() - cached.timestamp < CACHE_TTL_MS) {
    logger.debug("[Memory] Embedding cache HIT", {
      category: LogCategory.CACHE,
    });
    return cached.embedding;
  }

  try {
    // P1 FIX: Move API key from URL query parameter to x-goog-api-key header
    // This prevents key exposure in server logs, proxy logs, and error reporting
    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/${EMBEDDING_MODEL}:embedContent`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-goog-api-key": GOOGLE_API_KEY,
        },
        body: JSON.stringify({
          model: `models/${EMBEDDING_MODEL}`,
          content: {
            parts: [{ text }],
          },
          outputDimensionality: 768, // Match existing vector(768) columns
        }),
        signal: AbortSignal.timeout(30_000),
      }
    );

    if (!response.ok) {
      const errorText = await response.text();
      logger.error(
        `[Memory] Embedding API error: ${response.status}`,
        new Error(errorText),
        { category: LogCategory.AI }
      );
      return null;
    }

    const data = await response.json();
    const embedding = data.embedding?.values || null;

    // Cache the result
    if (embedding) {
      evictOldestCacheEntries();
      embeddingCache.set(cacheKey, {
        embedding,
        timestamp: Date.now(),
      });
      logger.debug(
        `[Memory] Embedding cached, cache size: ${embeddingCache.size}`,
        { category: LogCategory.CACHE }
      );
    }

    return embedding;
  } catch (error) {
    logger.error(
      "[Memory] Embedding generation failed",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.AI }
    );
    return null;
  }
}

