// =====================================================
// Conversation Memory
// =====================================================

/**
 * Store a message in conversation memory with embedding.
 */
export async function storeMemory(
  userId: string,
  role: "user" | "assistant",
  content: string,
  options: {
    importance?: number;
    topics?: string[];
    entities?: Record<string, unknown>;
  } = {}
): Promise<boolean> {
  try {
    // Generate embedding for the content
    const embedding = await generateEmbedding(content);

    const { error } = await supabase.from("sophia_conversation_memory").insert({
      user_id: userId,
      role,
      content,
      embedding,
      importance: options.importance || 0.5,
      topics: options.topics || [],
      entities: options.entities || {},
    });

    if (error) {
      logger.error(
        "[Memory] Error storing memory",
        error instanceof Error ? error : new Error(String(error)),
        { category: LogCategory.DATABASE }
      );
      return false;
    }

    return true;
  } catch (error) {
    logger.error(
      "[Memory] Exception in storeMemory",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.DATABASE }
    );
    return false;
  }
}

/**
 * Search conversation memory for semantically similar content.
 */
export async function searchMemory(
  userId: string,
  query: string,
  options: {
    limit?: number;
    minImportance?: number;
  } = {}
): Promise<ConversationMemory[]> {
  try {
    const embedding = await generateEmbedding(query);

    if (!embedding) {
      // Fallback to recent messages if embedding fails
      return getRecentMemories(userId, options.limit || 5);
    }

    return searchMemoryWithEmbedding(userId, embedding, options);
  } catch (error) {
    logger.error(
      "[Memory] Exception in searchMemory",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.DATABASE }
    );
    return [];
  }
}

/**
 * Search conversation memory with pre-computed embedding.
 * Used to avoid duplicate embedding API calls when searching multiple sources.
 */
export async function searchMemoryWithEmbedding(
  userId: string,
  embedding: number[],
  options: {
    limit?: number;
    minImportance?: number;
  } = {}
): Promise<ConversationMemory[]> {
  try {
    const { data, error } = await supabase.rpc("search_sophia_memory", {
      p_user_id: userId,
      query_embedding: embedding,
      match_count: options.limit || 5,
      min_importance: options.minImportance || 0.0,
    });

    if (error) {
      logger.error(
        "[Memory] Error searching memory",
        new Error(
          typeof error === "object" ? JSON.stringify(error) : String(error)
        ),
        { category: LogCategory.DATABASE }
      );
      return [];
    }

    return data || [];
  } catch (error) {
    logger.error(
      "[Memory] Exception in searchMemoryWithEmbedding",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.DATABASE }
    );
    return [];
  }
}

