): Promise<KnowledgeResult[]> {
  try {
    const embedding = await generateEmbedding(query);

    if (!embedding) {
      logger.warn("[Memory] Knowledge search skipped - no embedding", {
        category: LogCategory.AI,
      });
      return [];
