    return searchKnowledgeWithEmbedding(embedding, options);
  } catch (error) {
    logger.error(
      "[Memory] Exception in searchKnowledge",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.DATABASE }
    );
    return [];
  }
}

/**
 * Search knowledge base with pre-computed embedding.
 * Used to avoid duplicate embedding API calls when searching multiple sources.
 */
export async function searchKnowledgeWithEmbedding(
  embedding: number[],
  options: {
    limit?: number;
    category?: string;
    language?: string;
  } = {}
): Promise<KnowledgeResult[]> {
  try {
    const { data, error } = await supabase.rpc("search_sophia_knowledge", {
      query_embedding: embedding,
      match_count: options.limit || 5,
      filter_category: options.category || null,
      filter_language: options.language || null,
    });

    if (error) {
      logger.error(
        "[Memory] Error searching knowledge",
        new Error(
          typeof error === "object" ? JSON.stringify(error) : String(error)
        ),
        { category: LogCategory.DATABASE }
      );
      return [];
    }

    return data || [];
  } catch (error) {
    logger.error(
      "[Memory] Exception in searchKnowledgeWithEmbedding",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.DATABASE }
    );
    return [];
  }
}

// =====================================================
// User Context Builder
// =====================================================

/**
 * Build complete user context for AI prompt enhancement.
 * Includes profile, relevant memories, and knowledge base results.
 *
 * P1 FIX: Parallelized operations to reduce latency from 700-1200ms to ~300-500ms
 * - Generate embedding ONCE and share across searches
 * - Run independent operations in parallel with Promise.all
 */
export async function buildUserContext(
  phoneNumber: string,
  currentMessage: string,
  userName?: string
): Promise<UserContext | null> {
  try {
    const startTime = Date.now();

    // PHASE 1: Generate embedding ONCE (will be reused for both searches)
    // This also benefits from the new cache
    const messageEmbedding = await generateEmbedding(currentMessage);

    // PHASE 2: Get user profile (needed before we can query their memories)
    const profile = await getOrCreateUser(phoneNumber, userName);

    if (!profile) {
      logger.warn("[Memory] Could not get/create user profile", {
        category: LogCategory.DATABASE,
      });
      return null;
    }

    // PHASE 3: Parallelize semantic searches with shared embedding
    // Also fetch recent memories now that we have profile.id
    let relevantMemories: ConversationMemory[] = [];
    let relevantKnowledge: KnowledgeResult[] = [];
    let fetchedRecentMemories: ConversationMemory[] = [];

    if (messageEmbedding) {
      // Run semantic searches in parallel with recent memories fetch
      [relevantMemories, relevantKnowledge, fetchedRecentMemories] =
        await Promise.all([
          searchMemoryWithEmbedding(profile.id, messageEmbedding, {
            limit: 5,
            minImportance: 0.3,
          }),
          searchKnowledgeWithEmbedding(messageEmbedding, {
            limit: 3,
            language: profile.preferred_language,
          }),
          getRecentMemories(profile.id, 5),
        ]);
    } else {
      // Fallback: just get recent memories if embedding failed
      fetchedRecentMemories = await getRecentMemories(profile.id, 5);
    }

    // Combine and deduplicate memories
    const allMemories = [...relevantMemories];
    for (const recent of fetchedRecentMemories) {
      if (!allMemories.find((m) => m.id === recent.id)) {
        allMemories.push(recent);
      }
    }

    const duration = Date.now() - startTime;
    logger.debug(`[Memory] buildUserContext completed in ${duration}ms`, {
      category: LogCategory.DATABASE,
      duration,
    });

    return {
      profile,
      recentMemories: allMemories.slice(0, 10),
      relevantKnowledge,
    };
  } catch (error) {
    logger.error(
      "[Memory] Exception in buildUserContext",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.DATABASE }
    );
    return null;
  }
}

// =====================================================
// Context Formatting for Prompts
// =====================================================

/**
 * Format user context as a string to append to system prompt.
 *
 * P2 FIX: Removed phone number from context to prevent PII exposure to AI providers.
 * Phone numbers should not be sent to third-party AI APIs (OpenRouter/Gemini).
 */
export function formatContextForPrompt(context: UserContext): string {
  const lines: string[] = [];

  // User profile section
  lines.push("---");
  lines.push("## 🧠 PERSONALIZATION CONTEXT (RAG-Enhanced)");
  lines.push("");
  lines.push("### User Profile");
  lines.push(`- **Name**: ${context.profile.name || "Unknown"}`);
  // P2 FIX: Phone number removed - PII should not be sent to AI providers
  lines.push(`- **User ID**: ${context.profile.id.slice(0, 8)}...`);
  lines.push(`- **Preferred Language**: ${context.profile.preferred_language}`);
  lines.push(
    `- **Communication Style**: ${context.profile.communication_style}`
  );
  lines.push(`- **Total Messages**: ${context.profile.total_messages}`);
  lines.push(`- **First Contact**: ${context.profile.first_contact}`);

  // Interests if available
  if (Object.keys(context.profile.interests).length > 0) {
    lines.push(`- **Interests**: ${JSON.stringify(context.profile.interests)}`);
  }

  // Relevant memories section
  if (context.recentMemories.length > 0) {
    lines.push("");
    lines.push("### Relevant Past Conversations");
    lines.push("(Use these to personalize your response and maintain context)");
    lines.push("");

    for (const memory of context.recentMemories.slice(0, 5)) {
      const role = memory.role === "user" ? "User" : "SOPHIA";
      const preview =
        memory.content.length > 200
          ? memory.content.substring(0, 200) + "..."
          : memory.content;
      lines.push(`- **${role}**: "${preview}"`);
    }
  }

  // Relevant knowledge section
  if (context.relevantKnowledge.length > 0) {
    lines.push("");
    lines.push("### Relevant Knowledge Base Entries");
    lines.push("(Reference these when answering related questions)");
    lines.push("");

    for (const knowledge of context.relevantKnowledge) {
      lines.push(`**${knowledge.title}** (${knowledge.category})`);
      const preview =
        knowledge.content.length > 300
          ? knowledge.content.substring(0, 300) + "..."
          : knowledge.content;
      lines.push(`> ${preview}`);
      lines.push("");
    }
  }

  lines.push("---");

  return lines.join("\n");
}

// =====================================================
// Language Detection
// =====================================================

/**
 * Detect the language of a message.
 * Returns language code: 'en', 'ar', 'el'
 */
export function detectLanguage(text: string): "en" | "ar" | "el" {
  // Check for Arabic characters
  if (/[\u0600-\u06FF]/.test(text)) {
    return "ar";
  }

  // Check for Greek characters
  if (/[\u0370-\u03FF]/.test(text)) {
    return "el";
  }

  // Default to English
  return "en";
}

// =====================================================
// Topic Extraction
// =====================================================

/**
 * Extract topics from a message for tagging.
 */
export function extractTopics(text: string): string[] {
  const topics: string[] = [];
  const lowerText = text.toLowerCase();

  // Real estate topics
  const topicPatterns: Record<string, string[]> = {
    "property-search": [
      "looking for",
      "searching for",
      "want to buy",
      "want to rent",
    ],
    "property-sale": ["selling", "sell my", "list my property", "want to sell"],
    mortgage: ["mortgage", "loan", "financing", "bank"],
    legal: ["lawyer", "solicitor", "contract", "title deed", "legal"],
    tax: ["tax", "vat", "transfer fee", "capital gains"],
    residency: ["residency", "pr", "permanent resident", "immigration"],
    viewing: ["viewing", "visit", "see the property", "schedule"],
    documents: ["document", "form", "agreement", "contract"],
    pricing: ["price", "cost", "how much", "budget", "afford"],
    location: [
      "nicosia",
      "limassol",
      "paphos",
      "larnaca",
      "famagusta",
      "ayia napa",
    ],
    "property-type": ["apartment", "villa", "house", "land", "office", "shop"],
  };

  for (const [topic, patterns] of Object.entries(topicPatterns)) {
    for (const pattern of patterns) {
      if (lowerText.includes(pattern)) {
        topics.push(topic);
        break;
      }
    }
  }

  return [...new Set(topics)]; // Remove duplicates
}

/**
 * Calculate importance score for a message.
 * Higher for messages with important topics or explicit importance markers.
 */
export function calculateImportance(text: string, topics: string[]): number {
  let score = 0.5; // Base score

  // Important topics boost
  const importantTopics = [
    "legal",
    "tax",
    "residency",
    "mortgage",
    "property-sale",
  ];
  for (const topic of topics) {
    if (importantTopics.includes(topic)) {
      score += 0.1;
    }
  }

  // Question marks indicate queries - moderately important
  if (text.includes("?")) {
    score += 0.1;
  }

  // Exclamation marks may indicate urgency
  if (text.includes("!")) {
    score += 0.05;
  }

  // Long messages are often more detailed
  if (text.length > 200) {
    score += 0.1;
  }

  // Cap at 1.0
  return Math.min(score, 1.0);
}

/**
 * WaSend Webhook TypeScript Interfaces
 *
 * Type-safe definitions for WaSend webhook payloads.
 * Based on actual payload structures observed in production.
 */

/**
 * Message identification structure
 * Contains phone numbers and message IDs for routing
 */
export interface WaSendKey {
  /** Cleaned sender phone number (recommended for private chats) */
  cleanedSenderPn?: string;
  /** Cleaned participant phone number (for group chats) */
  cleanedParticipantPn?: string;
  /** Remote JID (can be LID format like "520:123456@lid") */
  remoteJid?: string;
  /** Message ID for deduplication */
  id?: string;
  /** Whether message is outgoing (fromMe=true) */
  fromMe?: boolean;
}

/**
 * Encrypted WhatsApp image message structure
 * Images are encrypted by WhatsApp and must be decrypted via WaSend API
 */
export interface WaSendImageMessage {
  /** Encrypted image URL (mmg.whatsapp.net) */
  url: string;
  /** MIME type (e.g., "image/jpeg") */
  mimetype?: string;
  /** Encryption key (required for decryption) */
  mediaKey?: string;
  /** File SHA-256 hash */
  fileSha256?: string;
  /** File length in bytes */
  fileLength?: number | string;
  /** Image caption */
  caption?: string;
}

/**
 * Document message structure (PDF, DOCX, etc.)
 * Can also contain images sent as documents
 */
export interface WaSendDocumentMessage {
  /** Document URL (encrypted if from WhatsApp) */
  url: string;
  /** MIME type (e.g., "application/pdf", "image/jpeg") */
  mimetype?: string;
  /** File name */
  fileName?: string;
  /** Encryption key (required for decryption) */
  mediaKey?: string;
  /** File SHA-256 hash */
  fileSha256?: string;
  /** File length in bytes */
  fileLength?: number | string;
}

/**
 * Extended text message structure
 * Used for messages with additional formatting
 */
export interface WaSendExtendedTextMessage {
  /** Message text content */
  text: string;
}

/**
 * Nested message content structure
 * Contains the actual message payload (text, image, document, etc.)
 */
export interface WaSendMessageContent {
  /** Plain text message */
  conversation?: string;
  /** Extended/formatted text message */
  extendedTextMessage?: WaSendExtendedTextMessage;
  /** Image message (encrypted) */
  imageMessage?: WaSendImageMessage;
  /** Document message (PDF, DOCX, etc.) */
  documentMessage?: WaSendDocumentMessage;
}

/**
 * Core message structure
 * Top-level message object in WaSend webhook payloads
 */
export interface WaSendMessage {
  /** Message identification (phone numbers, IDs) */
  key?: WaSendKey;
  /** Nested message content */
  message?: WaSendMessageContent;
  /** Unified message body field (WaSend convenience field) */
  messageBody?: string;
  /** Message timestamp */
  messageTimestamp?: number;
  /** Message ID (alternative location) */
  id?: string;
  messageId?: string;
  /** Whether message is outgoing */
  fromMe?: boolean;
  /** Remote JID (alternative location) */
  remoteJid?: string;
  /** Sender phone number (alternative locations) */
  from?: string;
  to?: string;
  phone?: string;
  /** Message text (alternative locations) */
  text?: string;
  body?: string;
  content?: string;
  /** Image message (alternative location) */
  imageMessage?: WaSendImageMessage;
  /** Pre-decrypted media URL (if WaSend provides it) */
  decryptedMediaUrl?: string;
  /** Media URL (alternative location) */
  mediaUrl?: string;
  /** Test/simple webhook format - array of public image URLs */
  media?: string[];
  /** Nested data object (alternative location) */
  data?: {
    imageMessage?: WaSendImageMessage;
  };
}

/**
 * WaSend webhook data wrapper
 * Can contain a single message object or an array of messages
 */
export interface WaSendData {
  /** Message object (can be single object OR array) */
  messages?: WaSendMessage | WaSendMessage[];
  /** Alternative message field */
  message?: WaSendMessage;
  /** Image message (alternative location) */
  imageMessage?: WaSendImageMessage;
}

/**
 * Top-level WaSend webhook payload
 * Sent by WaSend webhook to sophia-bot Edge Function
 */
export interface WaSendWebhookPayload {
  /** Event type */
  event:
    | "messages.upsert"
    | "messages.received"
    | "message"
    | "messages"
    | string;
  /** Webhook data */
  data: WaSendData;
}

