/**
 * Agent Identifier Module
 * Matches WhatsApp phone numbers to agents in the database
 */

import { LogCategory, logger } from "../utils/logger.ts";
import { getSupabaseAdmin } from "../../_shared/db.ts";

export interface Agent {
  id: string;
  fullName: string;
  mobile: string;
  communicationEmail: string;
  listingOwnerEmail: string;
  region: "paphos" | "limassol" | "larnaca" | "nicosia" | "famagusta" | "all";
  role: "management" | "manager" | "agent";
  canUpload: boolean;
  landline?: string; // Office landline for CREA compliance
}

/**
 * Normalize phone number for comparison
 * Removes spaces, dashes, and +357 prefix
 */
export function normalizePhone(phone: string): string {
  // Remove all non-digit characters
  let normalized = phone.replace(/\D/g, "");

  // Remove Cyprus country code if present
  if (normalized.startsWith("357")) {
    normalized = normalized.slice(3);
  }

  // Remove leading zero if present
  if (normalized.startsWith("0")) {
    normalized = normalized.slice(1);
  }

  return normalized;
}

/**
 * Identify agent by their WhatsApp phone number
 * Uses normalized phone matching to handle various formats
 */
export async function identifyAgentByPhone(
  phone: string
): Promise<Agent | null> {
  const supabase = getSupabaseAdmin();
  const normalized = normalizePhone(phone);

  // Validate normalized phone contains only digits (defense in depth)
  if (!/^\d+$/.test(normalized) || normalized.length < 6) {
    logger.debug("[AgentIdentifier] Invalid normalized phone", {
      category: LogCategory.DATABASE,
    });
    return null;
  }

  // Try using the last 8 digits for matching (normalized is already digit-only, safe for filter)
  const last8 = normalized.slice(-8);

  // Use separate ilike queries to avoid filter injection with .or() string interpolation
  // First try with last 8 digits
  const { data: partialData, error: partialError } = await supabase
    .from("agents")
    .select("*")
    .ilike("mobile", `%${last8}%`)
    .limit(1)
    .maybeSingle();

  if (!partialError && partialData) {
    logger.debug(
      `[AgentIdentifier] Found agent: ${partialData.full_name} (${partialData.region})`,
      { category: LogCategory.DATABASE }
    );
    return mapAgentData(partialData);
  }

  // Try with full normalized number
  const { data: fullData, error: fullError } = await supabase
    .from("agents")
    .select("*")
    .ilike("mobile", `%${normalized}%`)
    .limit(1)
    .maybeSingle();

  if (!fullError && fullData) {
    logger.debug(
      `[AgentIdentifier] Found agent: ${fullData.full_name} (${fullData.region})`,
      { category: LogCategory.DATABASE }
    );
    return mapAgentData(fullData);
  }

  logger.debug("[AgentIdentifier] No agent found for phone", {
    category: LogCategory.DATABASE,
    normalized,
  });
  return null;
}

/**
 * Sanitize email input for use in filter queries
 * Prevents filter injection by only allowing valid email characters
 */
function sanitizeEmailForFilter(email: string): string {
  // Only allow alphanumeric, @, ., _, -, and +
  return email
    .replace(/[^a-zA-Z0-9@._+-]/g, "")
    .toLowerCase()
    .trim();
}

/**
 * Get agent by email address
 * Uses separate queries to avoid filter injection vulnerabilities
 */
export async function getAgentByEmail(
  email: string
): Promise<Agent | null> {
  const supabase = getSupabaseAdmin();

  // Sanitize email to prevent filter injection
  const sanitizedEmail = sanitizeEmailForFilter(email);
  if (!sanitizedEmail || !sanitizedEmail.includes("@")) {
    logger.debug("[AgentIdentifier] Invalid email format", {
      category: LogCategory.DATABASE,
    });
    return null;
  }

  // Use separate queries to avoid filter injection with .or() string interpolation
  // First try communication_email
  const { data: commData, error: commError } = await supabase
    .from("agents")
    .select("*")
    .eq("communication_email", sanitizedEmail)
    .limit(1)
    .maybeSingle();

  if (!commError && commData) {
    return mapAgentData(commData);
  }

  // Then try listing_owner_email
  const { data: ownerData, error: ownerError } = await supabase
    .from("agents")
    .select("*")
    .eq("listing_owner_email", sanitizedEmail)
    .limit(1)
    .maybeSingle();

  if (!ownerError && ownerData) {
    return mapAgentData(ownerData);
  }

  return null;
}

/**
 * Map database row to Agent interface
 */
function mapAgentData(data: Record<string, unknown>): Agent {
  return {
    id: data.id as string,
    fullName: data.full_name as string,
    mobile: data.mobile as string,
    communicationEmail: data.communication_email as string,
    listingOwnerEmail: data.listing_owner_email as string,
    region: data.region as Agent["region"],
    role: data.role as Agent["role"],
    canUpload: data.can_upload as boolean,
    landline: data.landline as string | undefined,
  };
}

/**
 * Get all agents in a specific region
 */
export async function getAgentsByRegion(
  region: string
): Promise<Agent[]> {
  const supabase = getSupabaseAdmin();

  const { data, error } = await supabase
    .from("agents")
    .select("*")
    .eq("region", region)
    .eq("can_upload", true);

  if (error || !data) {
    return [];
  }

  return data.map((d: Record<string, unknown>) => mapAgentData(d));
}

/**
 * Amenities & Features Taxonomy Lookups
 * Extracted from taxonomy-cache.ts for better modularity
 */

import {
  INDOOR_FEATURE_ALIASES,
  INDOOR_FEATURE_FALLBACKS,
  OPPOSITE_MODIFIERS,
  OUTDOOR_FEATURE_ALIASES,
  OUTDOOR_FEATURE_FALLBACKS,
  VIEW_FALLBACKS,
} from "../config/business-rules.ts";
import { LogCategory, logger } from "../utils/logger.ts";
import { loadTaxonomy } from "./taxonomy-cache.ts";

/**
 * Resolve user input to canonical taxonomy term using aliases
 * Returns the canonical term if found, otherwise returns the original input
 */
function resolveFeatureAlias(
  input: string,
  aliasMap: Record<string, string[]>
): string {
  const normalized = input.toLowerCase().trim();

  // Check if input matches any alias
  for (const [canonical, aliases] of Object.entries(aliasMap)) {
    if (
      aliases.some(
        (alias) =>
          alias === normalized ||
          normalized.includes(alias) ||
          alias.includes(normalized)
      )
    ) {
      logger.debug(`[Taxonomy] ALIAS: "${input}" -> "${canonical}"`);
      return canonical;
    }
  }

  return normalized;
}

/**
 * Find feature UUIDs by names
 */
export async function findFeatureUuids(
  featureNames: string[]
): Promise<string[]> {
  const taxonomy = await loadTaxonomy();
  const allFeatures = [
    ...taxonomy.features,
    ...taxonomy.indoorFeatures,
    ...taxonomy.outdoorFeatures,
  ];

  const uuids: string[] = [];

  for (const name of featureNames) {
    const normalized = name.toLowerCase().trim();

    const match = allFeatures.find(
      (f) =>
        f.name.toLowerCase() === normalized ||
        f.name.toLowerCase().includes(normalized) ||
        normalized.includes(f.name.toLowerCase())
    );

    if (match && !uuids.includes(match.id)) {
      uuids.push(match.id);
    }
  }

  return uuids;
}

/**
 * Find indoor feature UUIDs from feature names
 * IMPROVED: Uses exact matching against taxonomy, with hardcoded fallbacks
 * @param featureNames - Array of feature names to look up
 * @param bathrooms - Optional bathroom count. If >= 2, auto-adds "guest toilet" and "master bed"
 */
export async function findIndoorFeatureUuids(
  featureNames: string[],
  bathrooms?: number
): Promise<string[]> {
  const taxonomy = await loadTaxonomy();
  const uuids: string[] = [];

  // Auto-add features based on bathroom count
  const effectiveFeatures = [...featureNames];
  if (bathrooms && bathrooms >= 2) {
    logger.debug(
      `[Taxonomy] Bathrooms >= 2 (${bathrooms}), auto-adding guest toilet and master bed`
    );
    if (!effectiveFeatures.some((f) => f.toLowerCase().includes("guest"))) {
      effectiveFeatures.push("guest toilet");
    }
    if (!effectiveFeatures.some((f) => f.toLowerCase().includes("master"))) {
      effectiveFeatures.push("master bed");
    }
  }

  logger.debug(
    `[Taxonomy] Finding indoor features from: ${effectiveFeatures.join(", ")}`
  );
  logger.debug(
    `[Taxonomy] Available indoor features (${taxonomy.indoorFeatures.length}): ${taxonomy.indoorFeatures.map((f) => f.name).join(", ")}`
  );

  for (const name of effectiveFeatures) {
    if (!name) continue;

    // First resolve any aliases (e.g., "laundry room" -> "utility room")
    const normalized = resolveFeatureAlias(name, INDOOR_FEATURE_ALIASES);
    if (!normalized) continue;

    // Skip features that are clearly outdoor-only (pool, garden, etc.)
    // But be careful - "covered parking" is INDOOR in Zyprus taxonomy!
    const isOutdoorOnly = [
      "pool",
      "private pool",
      "communal pool",
      "swimming pool",
      "heated swimming pool",
      "landscape garden",
      "standard garden",
      "rear garden",
      "roof garden",
      "barbecue",
      "bbq",
      "outdoor shower",
      "bore hole",
      "photovoltaic",
      "solar system",
      "solar panels",
      "irrigation",
      "garage",
      "single garage",
      "double garage",
      "electric shutters",
      "carport",
    ].some((kw) => normalized === kw || normalized.includes(kw));

    if (isOutdoorOnly) continue;

    // Strategy 1: Try EXACT match in taxonomy (case-insensitive)
    let match = taxonomy.indoorFeatures.find(
      (f) => f.name.toLowerCase() === normalized
    );

    if (!match) {
      // Strategy 2: Try normalized match (remove hyphens, slashes)
      const normalizedClean = normalized
        .replace(/[-/]/g, " ")
        .replace(/\s+/g, " ");
      match = taxonomy.indoorFeatures.find((f) => {
        const taxClean = f.name
          .toLowerCase()
          .replace(/[-/]/g, " ")
          .replace(/\s+/g, " ");
        return taxClean === normalizedClean;
      });
    }

    if (!match) {
      // Strategy 3: Check if taxonomy item contains our input (e.g., "parking" in "Covered Parking")
      match = taxonomy.indoorFeatures.find((f) => {
        const taxLower = f.name.toLowerCase();
        // Must be an exact word match, not substring
        return (
          taxLower === normalized ||
          (taxLower.includes(normalized) &&
            !hasContradictoryModifiers(normalized, f.name))
        );
      });
    }

    if (match && !uuids.includes(match.id)) {
      logger.debug(
        `[Taxonomy] INDOOR MATCHED: "${name}" -> "${match.name}" (${match.id})`
      );
      uuids.push(match.id);
    } else if (!match) {
      // Strategy 4: Use hardcoded fallback
      const fallbackUuid = INDOOR_FEATURE_FALLBACKS[normalized];
      if (
        fallbackUuid &&
        !fallbackUuid.includes("placeholder") &&
        !uuids.includes(fallbackUuid)
      ) {
        logger.debug(
          `[Taxonomy] INDOOR FALLBACK: "${name}" -> ${fallbackUuid}`
        );
        uuids.push(fallbackUuid);
      } else {
        logger.warn(`[Taxonomy] INDOOR NO MATCH: "${name}" (resolved: "${normalized}")`, {
          category: LogCategory.ZYPRUS,
          operation: "findIndoorFeatureUuids",
        });
      }
    }
  }

  logger.debug(`[Taxonomy] Found ${uuids.length} indoor feature UUIDs`);
  return uuids;
}

/**
 * Check if input and taxonomy term have contradictory modifiers
 * Returns true if they contradict (should NOT match)
 */
function hasContradictoryModifiers(
  input: string,
  taxonomyTerm: string
): boolean {
  const inputLower = input.toLowerCase();
  const taxLower = taxonomyTerm.toLowerCase();

  for (const [mod1, mod2] of OPPOSITE_MODIFIERS) {
    // Check both directions: input has mod1 & tax has mod2, or input has mod2 & tax has mod1
    if (
      (inputLower.includes(mod1) && taxLower.includes(mod2)) ||
      (inputLower.includes(mod2) && taxLower.includes(mod1))
    ) {
      logger.debug(
        `[Taxonomy] REJECTED: "${input}" vs "${taxonomyTerm}" - contradictory modifiers (${mod1}/${mod2})`
      );
      return true;
    }
  }
  return false;
}

/**
 * Find outdoor feature UUIDs from feature names
 * IMPROVED: Uses exact matching against taxonomy, with hardcoded fallbacks
 */
export async function findOutdoorFeatureUuids(
  featureNames: string[]
): Promise<string[]> {
  const taxonomy = await loadTaxonomy();
  const uuids: string[] = [];

  logger.debug(
    `[Taxonomy] Finding outdoor features from: ${featureNames.join(", ")}`
  );
  logger.debug(
    `[Taxonomy] Available outdoor features (${taxonomy.outdoorFeatures.length}): ${taxonomy.outdoorFeatures.map((f) => f.name).join(", ")}`
  );

  for (const name of featureNames) {
    if (!name) continue;

    // First resolve any aliases (e.g., "swimming pool" -> "private pool")
    const normalized = resolveFeatureAlias(name, OUTDOOR_FEATURE_ALIASES);
    if (!normalized) continue;

    // Skip features that are clearly indoor-only
    const isIndoorOnly = [
      "air conditioning",
      "central heating",
      "under floor heating",
      "fireplace",
      "elevator",
      "fitted kitchen",
      "electrical appliances",
      "water heater",
      "guest toilet",
      "basement",
      "mezzanine",
      "jacuzzi",
      "internal pool",
      "playroom",
      "conference room",
      "cctv",
      "security system",
      "fire alarm",
      "open-plan",
      "utility room",
      "master bed",
      "fly screens",
      "covered parking",
      "underground parking",
      "furnished",
      "unfurnished",
    ].some((kw) => normalized.includes(kw));

    if (isIndoorOnly) continue;

    // Skip views - they go in property_views, not outdoor features
    const isView = [
      "view",
      "sea view",
      "mountain view",
      "city view",
      "green area view",
    ].some((kw) => normalized.includes(kw));
    if (isView) continue;

    // Strategy 1: Try EXACT match in taxonomy (case-insensitive)
    let match = taxonomy.outdoorFeatures.find(
      (f) => f.name.toLowerCase() === normalized
    );

    if (!match) {
      // Strategy 2: Try normalized match (remove hyphens, slashes)
      const normalizedClean = normalized
        .replace(/[-/]/g, " ")
        .replace(/\s+/g, " ");
      match = taxonomy.outdoorFeatures.find((f) => {
        const taxClean = f.name
          .toLowerCase()
          .replace(/[-/]/g, " ")
          .replace(/\s+/g, " ");
        return taxClean === normalizedClean;
      });
    }

    if (!match) {
      // Strategy 3: Check if taxonomy item contains our input
      match = taxonomy.outdoorFeatures.find((f) => {
        const taxLower = f.name.toLowerCase();
        return (
          taxLower === normalized ||
          (taxLower.includes(normalized) &&
            !hasContradictoryModifiers(normalized, f.name))
        );
      });
    }

    if (match && !uuids.includes(match.id)) {
      logger.debug(
        `[Taxonomy] OUTDOOR MATCHED: "${name}" -> "${match.name}" (${match.id})`
      );
      uuids.push(match.id);
    } else if (!match) {
      // Strategy 4: Use hardcoded fallback
      const fallbackUuid = OUTDOOR_FEATURE_FALLBACKS[normalized];
      if (
        fallbackUuid &&
        !fallbackUuid.includes("placeholder") &&
        !uuids.includes(fallbackUuid)
      ) {
        logger.debug(
          `[Taxonomy] OUTDOOR FALLBACK: "${name}" -> ${fallbackUuid}`
        );
        uuids.push(fallbackUuid);
      } else {
        logger.warn(`[Taxonomy] OUTDOOR NO MATCH: "${name}" (resolved: "${normalized}")`, {
          category: LogCategory.ZYPRUS,
          operation: "findOutdoorFeatureUuids",
        });
      }
    }
  }

  logger.debug(`[Taxonomy] Found ${uuids.length} outdoor feature UUIDs`);
  return uuids;
}

/**
 * Find view UUIDs from feature names (sea view, mountain view, etc.)
 * Views have their own taxonomy: taxonomy_term--property_views
