/**
 * Add privacy offset to coordinates (at least 1km away)
 * Per spec: NEVER place pin at exact property address
 * Pin should land on a general area like a roundabout or supermarket nearby
 */
function addPrivacyOffset(coords: { lat: number; lon: number }): {
  lat: number;
  lon: number;
} {
  // ~0.008 degrees ≈ 900m offset — pin should NOT be near the actual property
  // Must be far enough that the property location is NOT identifiable
  const minOffset = 0.007;
  const range = 0.005;

  // Cyprus center of mass (Troodos area) — always offset TOWARD this point
  const CYPRUS_CENTER = { lat: 35.0, lon: 33.0 };

  // Calculate direction toward inland center
  const dirLat = CYPRUS_CENTER.lat - coords.lat; // positive = north (inland for south coast)
  const dirLon = CYPRUS_CENTER.lon - coords.lon;
  const dirMag = Math.hypot(dirLat, dirLon);

  if (dirMag === 0) {
    // Already at center (unlikely), small random offset
    return {
      lat: coords.lat + (minOffset + Math.random() * range),
      lon:
        coords.lon +
        (Math.random() > 0.5 ? 1 : -1) * (minOffset + Math.random() * range),
    };
  }

  // Normalize direction toward center
  const normLat = dirLat / dirMag;
  const normLon = dirLon / dirMag;

  // Offset magnitude with some randomness
  const offsetMag = minOffset + Math.random() * range;

  // Add perpendicular jitter so pins aren't all on the same line toward center
  const jitterAngle = (Math.random() - 0.5) * Math.PI * 0.6; // ±54 degrees jitter
  const cosJ = Math.cos(jitterAngle);
  const sinJ = Math.sin(jitterAngle);
  const jitteredLat = normLat * cosJ - normLon * sinJ;
  const jitteredLon = normLat * sinJ + normLon * cosJ;

  return {
    lat: coords.lat + jitteredLat * offsetMag,
    lon: coords.lon + jitteredLon * offsetMag,
  };
}

/**
 * Generate Own Reference ID for quick reviewer reference
 * Format: Owner - {Agent Name} - {Seller Name} - {Seller Phone} - {Seller Email}
 * Example: Owner - Evelina Neophytou - Jane Smith - 99123456 - seller@email.com
 * Per Lauren feedback Jan 2026: Include owner email when provided
 */
function generateOwnReferenceId(
  agentName?: string,
  ownerName?: string,
  ownerPhone?: string,
  ownerEmail?: string,
  registrationNumber?: string,
  buildingName?: string
): string {
  const parts: string[] = ["Owner"];

  if (agentName) {
    parts.push(agentName);
  }

  // Building/complex name (e.g., "Flow Residence") for quick identification
  if (buildingName) {
    parts.push(buildingName);
  }

  if (ownerName) {
    parts.push(ownerName);
  }

  if (ownerPhone) {
    // Clean phone number - remove spaces, +357, etc.
    const cleanPhone = ownerPhone.replace(/[\s\-+]/g, "").replace(/^357/, "");
    parts.push(cleanPhone);
  }

  // Add owner email when provided (per Lauren feedback Jan 2026)
  if (ownerEmail) {
    parts.push(ownerEmail);
  }

  if (registrationNumber) {
    parts.push(`Reg No.${registrationNumber}`);
  }

  return parts.join(" - ");
}

/**
 * Build JSON:API payload for property creation
 */
function buildJsonApiPayload(
  listing: ListingData,
  imageFileIds: string[],
  listingTypeUuid: string,
  propertyTypeUuid: string,
  priceModifierUuid: string,
  titleDeedUuid: string,
  instructorUuid: string,
  reviewerUuids: string[],
  listingOwnerUuid: string,
  indoorFeatureUuids: string[],
  outdoorFeatureUuids: string[],
  viewUuids: string[],
  floorPlanFileIds: string[] = [],
  titleDeedFileIds: string[] = []
): Record<string, unknown> {
  // Generate Own Reference ID for quick reviewer reference
  // Format: Owner - {Agent Name} - {Seller Name} - {Seller Phone} - {Email}
  const ownReferenceId = generateOwnReferenceId(
    listing.agentName,
    listing.ownerName,
    listing.ownerPhone,
    listing.ownerEmail,
    listing.registrationNumber,
    listing.buildingName
  );

  // Build proper title: "2 Bedroom Bungalow (125m²) For Sale in Kamares, Tala"
  // If there's a covered veranda, include total area (Net Indoor Area + Covered Veranda only)
  const bedroomText =
    listing.bedrooms === 1 ? "1 Bedroom" : `${listing.bedrooms} Bedroom`;
  const listingTypeText =
    listing.listingType === "rent" ? "For Rent" : "For Sale";
  const propertyTypeCapitalized =
    listing.propertyType.charAt(0).toUpperCase() +
    listing.propertyType.slice(1).toLowerCase();

  // Calculate title area text: Show covered area + covered veranda separately (not summed)
  const hasCoveredVeranda =
    listing.coveredVeranda && listing.coveredVeranda > 0;
  let titleAreaText = "";
  if (hasCoveredVeranda) {
    titleAreaText = ` (${listing.coveredArea}m² + ${listing.coveredVeranda}m² covered veranda)`;
    logger.info(
      `Title area calculation: ${listing.coveredArea}m² + ${listing.coveredVeranda}m² covered veranda`,
      {
        category: LogCategory.ZYPRUS,
        operation: "createDraftListing",
      }
    );
  } else {
    titleAreaText = ` (${listing.coveredArea}m²)`;
    logger.info(
      `Title area calculation: ${listing.coveredArea}m² (no covered veranda)`,
      {
        category: LogCategory.ZYPRUS,
        operation: "createDraftListing",
      }
    );
  }

  const generatedTitle = `${bedroomText} ${propertyTypeCapitalized}${titleAreaText} ${listingTypeText} in ${listing.location}`;
  logger.info(`Generated title: ${generatedTitle}`, {
    category: LogCategory.ZYPRUS,
    operation: "createDraftListing",
  });

  const attributes: Record<string, unknown> = {
    title: generatedTitle,
    status: false, // Always unpublished draft
    field_price: listing.price,
    field_no_bedrooms: listing.bedrooms,
    ...(listing.bathrooms > 0 ? { field_no_bathrooms: listing.bathrooms } : {}),
    // NOTE: field_no_kitchens and field_no_living_rooms intentionally NOT set
    // Zyprus auto-generates titles from room counts — only bedrooms/bathrooms are standard
    field_covered_area: listing.coveredArea,
    body: {
      value: listing.description,
      format: "plain_text",
    },
    // NOTE: field_my_notes was removed - location URL now goes to field_property_notes instead
    // NOTE: field_ai_assistant_notes does NOT exist on live API (verified Feb 2026)
    // aiNotes content is merged into field_ai_message instead
    field_ai_generated: true,
    field_ai_state: "draft",
    // Price negotiable: default TRUE unless explicitly set to false
    // NOTE: Drupal list fields may expect integer (1/0) instead of boolean (true/false)
    // NOTE: field_negotiable does NOT exist in Zyprus API (not in Postman spec)
    // "Negotiable" display is controlled by field_price_modifier taxonomy term
    // Own Reference ID: Owner - {Agent} - {Seller} - {Phone} - Reg No.{Reg}
    field_own_reference_id: ownReferenceId,
    field_ai_draft_own_reference_id: ownReferenceId,
  };

  // field_property_notes: Location URL goes here (for agent/reviewer reference)
  // This is the "Property Notes / My notes" field on the edit form
  if (listing.myNotes) {
    attributes.field_property_notes = listing.myNotes;
  }

  // Optional fields
  if (listing.plotSize) {
    attributes.field_land_size = listing.plotSize; // API field is field_land_size, not field_plot_size
  }
  if (listing.coveredVeranda) {
    attributes.field_no_covered_verandas = listing.coveredVeranda;
  }
  if (listing.uncoveredVeranda) {
    attributes.field_no_uncovered_verandas = listing.uncoveredVeranda;
  }
  if (listing.yearBuilt) {
    attributes.field_year_built = listing.yearBuilt;
  }
  if (listing.floor) {
    attributes.field_floor = listing.floor;
  }
  if (listing.potentialDuplicate) {
    attributes.field_ai_probably_exists = true;
  }
  // Merge aiNotes and aiMessage into field_ai_message
  // NOTE: myNotes is NOT included here - it goes to field_property_notes instead
  const aiMessageParts = [listing.aiMessage, listing.aiNotes].filter(Boolean);
  if (aiMessageParts.length > 0) {
    attributes.field_ai_message = aiMessageParts.join("\n\n");
  }
  // New build flag — ONLY set when VAT applies (+VAT)
  // For No VAT new builds (resale), don't set this flag because
  // Zyprus shows "New Build +VAT" badge which implies buyer pays VAT
  if (listing.isNewBuild && listing.priceModifier !== "no_vat") {
    attributes.field_new_build = true;
  }

  // Energy class (A, B, C, D) — dedicated field, NOT in description
  if (listing.energyClass) {
    attributes.field_energy_class = listing.energyClass;
  }

  // Coordinates - Full object format per Postman spec
  // Apply privacy offset per meeting spec (2-3 streets away)
  if (listing.coordinates) {
    const offsetCoords = addPrivacyOffset(listing.coordinates);
    attributes.field_map = {
      value: `POINT (${offsetCoords.lon} ${offsetCoords.lat})`,
      geo_type: "Point",
      lat: offsetCoords.lat,
      lon: offsetCoords.lon,
      latlon: `${offsetCoords.lat},${offsetCoords.lon}`,
    };
  }

  // Build relationships
  const relationships: Record<string, unknown> = {};

  // MANDATORY: Listing type (sale/rent)
  relationships.field_listing_type = {
    data: { type: "taxonomy_term--listing_type", id: listingTypeUuid },
  };

  // MANDATORY: Property type (apartment, villa, etc.)
  relationships.field_property_type = {
    data: { type: "taxonomy_term--property_type", id: propertyTypeUuid },
  };

  // MANDATORY: Price modifier (VAT context)
  relationships.field_price_modifier = {
    data: { type: "taxonomy_term--price_modifier", id: priceModifierUuid },
  };

  // MANDATORY: Title deed status
  relationships.field_title_deed = {
    data: { type: "taxonomy_term--title_deed", id: titleDeedUuid },
  };

  // Location (NOTE: Zyprus uses node--location, NOT taxonomy_term)
  // MANDATORY: API requires field_location to be non-null (422 error if missing)
  // Since Zyprus only has Nicosia locations, non-Nicosia properties will get Nicosia location
  // The AI message will warn about this mismatch for manual correction
  if (listing.locationUuid) {
    relationships.field_location = {
      data: { type: "node--location", id: listing.locationUuid },
    };
  }

  // Images (NOTE: Zyprus uses field_gallery_ with trailing underscore)
  if (imageFileIds.length > 0) {
    relationships.field_gallery_ = {
      data: imageFileIds.map((id) => ({
        type: "file--file",
        id,
      })),
    };
  }

  // Floor plan images (separate from gallery)
  if (floorPlanFileIds.length > 0) {
    relationships.field_floor_plan = {
      data: floorPlanFileIds.map((id) => ({
        type: "file--file",
        id,
      })),
    };
  }

  // Title deed files — include in initial POST (same pattern as floor plans).
  // Previously excluded and attached via PATCH, but PATCH returns 403.
  // Including in initial POST may succeed since node creation has different permissions.
  // PATCH fallback still exists in createDraftListing() if this doesn't work.
  if (titleDeedFileIds.length > 0) {
    relationships.field_title_deed_file = {
      data: titleDeedFileIds.map((id) => ({
        type: "file--file",
        id,
      })),
    };
  }

  // Indoor features (AC, heating, etc.)
  // Note: field is field_indoor_property_features but references taxonomy_term--indoor_property_views
  if (indoorFeatureUuids.length > 0) {
    relationships.field_indoor_property_features = {
      data: indoorFeatureUuids.map((id) => ({
        type: "taxonomy_term--indoor_property_views",
        id,
      })),
    };
  }

  // Outdoor features (pool, garden, parking, etc.)
  if (outdoorFeatureUuids.length > 0) {
    relationships.field_outdoor_property_features = {
      data: outdoorFeatureUuids.map((id) => ({
        type: "taxonomy_term--outdoor_property_features",
        id,
      })),
    };
  }

  // Listing instructor - person who requested upload (resolved from email)
  relationships.field_ai_listing_instructor = {
    data: { type: "user--user", id: instructorUuid },
  };

  // Listing reviewers - people who will review the listing (resolved from emails)
  if (reviewerUuids.length > 0) {
    relationships.field_ai_listing_reviewer = {
      data: reviewerUuids.map((id) => ({ type: "user--user", id })),
    };
  }

  // Listing owner/author - set via uid to override the OAuth service account
  // NOTE: field_listing_owner does NOT exist on live API (verified Feb 2026)
  // The CMS "Listing Owner" is determined by the uid (author) relationship
  relationships.uid = {
    data: { type: "user--user", id: listingOwnerUuid },
  };

  // Property views (sea view, mountain view, etc.)
  // Per Postman spec: taxonomy_term--property_views
  if (viewUuids.length > 0) {
    relationships.field_property_views = {
      data: viewUuids.map((id) => ({
        type: "taxonomy_term--property_views",
        id,
      })),
    };
  }

  return {
    data: {
      type: "node--property",
      attributes,
      relationships,
    },
  };
}

/**
 * Upload a single image to Zyprus
 */
export async function uploadSingleImage(
  url: string,
  index: number,
  token: string,
  config: ZyprusConfig
): Promise<string | null> {
  try {
    // P0 SECURITY: Validate image URL before fetching (SSRF prevention)
    const urlValidation = validateImageUrl(url);
    if (!urlValidation.valid) {
      logger.warn("SSRF blocked - invalid image URL", {
        category: LogCategory.ZYPRUS,
        operation: "uploadSingleImage",
        imageIndex: index,
        urlPreview: url.substring(0, 100),
        validationError: urlValidation.error,
      });
      return null;
    }

    // P1 SECURITY: Maximum image size (10MB) to prevent DoS
    const MAX_IMAGE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB

    // Download image
    const imageResponse = await fetch(url, {
      signal: AbortSignal.timeout(30_000),
    });
    if (!imageResponse.ok) {
      logger.error("Failed to download image for Zyprus upload", undefined, {
        category: LogCategory.ZYPRUS,
        operation: "uploadSingleImage",
        imageIndex: index,
        status: imageResponse.status,
        urlPreview: url.substring(0, 100),
      });
      return null;
    }

    // P1 SECURITY: Check Content-Length header before downloading full content
    const contentLength = imageResponse.headers.get("content-length");
    if (contentLength) {
      const sizeBytes = Number.parseInt(contentLength, 10);
      if (sizeBytes > MAX_IMAGE_SIZE_BYTES) {
        logger.warn("Image exceeds maximum size limit - rejecting", {
          category: LogCategory.ZYPRUS,
          operation: "uploadSingleImage",
          imageIndex: index,
          sizeBytes,
          maxSizeBytes: MAX_IMAGE_SIZE_BYTES,
          urlPreview: url.substring(0, 100),
        });
        return null;
      }
    }

    const imageBlob = await imageResponse.blob();

    // P1 SECURITY: Double-check actual blob size (Content-Length may be absent or incorrect)
    if (imageBlob.size > MAX_IMAGE_SIZE_BYTES) {
      logger.warn("Image blob exceeds maximum size limit - rejecting", {
        category: LogCategory.ZYPRUS,
        operation: "uploadSingleImage",
        imageIndex: index,
        actualSize: imageBlob.size,
        maxSizeBytes: MAX_IMAGE_SIZE_BYTES,
        urlPreview: url.substring(0, 100),
      });
      return null;
    }

    const imageBuffer = await imageBlob.arrayBuffer();

    // Get filename from URL
    const urlParts = url.split("/");
    let filename = urlParts[urlParts.length - 1].split("?")[0];
    if (!filename.match(/\.(jpg|jpeg|png|gif|webp)$/i)) {
      filename = `property_image_${index + 1}.jpg`;
    }

    // Upload to Zyprus (NOTE: field_gallery_ with trailing underscore)
    const uploadResponse = await withRetry(
      async () => {
        const res = await fetch(
          `${config.apiUrl}/jsonapi/node/property/field_gallery_`,
          {
            method: "POST",
            headers: {
              Authorization: `Bearer ${token}`,
              "Content-Type": "application/octet-stream",
              "Content-Disposition": `file; filename="${filename}"`,
              "User-Agent": "SophiaAI",
            },
            body: imageBuffer,
            signal: AbortSignal.timeout(30_000),
          }
        );

        if (!res.ok && res.status >= 500) {
          throw new Error(`Image upload failed: ${res.status}`);
        }
        return res;
      },
      { maxRetries: 2, baseDelayMs: 500 },
      "uploadSingleImage"
    );

    if (!uploadResponse.ok) {
      logger.error("Failed to upload image to Zyprus", undefined, {
        category: LogCategory.ZYPRUS,
        operation: "uploadSingleImage",
        imageIndex: index,
        status: uploadResponse.status,
      });
      return null;
    }

    const uploadResult = await uploadResponse.json();
    if (uploadResult.data?.id) {
      logger.info("Image uploaded to Zyprus successfully", {
        category: LogCategory.ZYPRUS,
        operation: "uploadSingleImage",
        imageIndex: index + 1,
        fileId: uploadResult.data.id,
      });
      return uploadResult.data.id;
    }
    return null;
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    logClassifiedError("Image upload error", err, {
      category: LogCategory.ZYPRUS,
      operation: "uploadSingleImage",
      imageIndex: index,
      urlPreview: url.substring(0, 100),
    });
    return null;
  }
}

/**
 * Upload images to Zyprus and get file IDs (PARALLEL)
 */
async function uploadImages(
  imageUrls: string[],
  token: string,
  config: ZyprusConfig
): Promise<string[]> {
  logger.info("Uploading images to Zyprus in parallel", {
    category: LogCategory.ZYPRUS,
    operation: "uploadImages",
    imageCount: imageUrls.length,
  });

  // Upload all images in parallel
  const results = await Promise.all(
    imageUrls.map((url, index) => uploadSingleImage(url, index, token, config))
  );

  // Filter out failed uploads (nulls)
  const fileIds = results.filter((id): id is string => id !== null);

  logger.info("Image upload to Zyprus completed", {
    category: LogCategory.ZYPRUS,
    operation: "uploadImages",
    successCount: fileIds.length,
    totalCount: imageUrls.length,
  });
  return fileIds;
}

/**
 * Upload floor plan images to Zyprus (uses field_floor_plan endpoint)
 */
async function uploadFloorPlans(
  floorPlanUrls: string[],
  token: string,
  config: ZyprusConfig
): Promise<string[]> {
  logger.info("Uploading floor plans to Zyprus", {
    category: LogCategory.ZYPRUS,
    operation: "uploadFloorPlans",
    count: floorPlanUrls.length,
  });

  const results = await Promise.all(
    floorPlanUrls.map(async (url, index) => {
      try {
        // Download the floor plan image
        const imageResponse = await fetch(url, {
          signal: AbortSignal.timeout(30_000),
        });
        if (!imageResponse.ok) {
          logger.warn("Failed to download floor plan", {
            category: LogCategory.ZYPRUS,
            operation: "uploadFloorPlan",
            imageIndex: index,
            status: imageResponse.status,
          });
          return null;
        }

        const imageBlob = await imageResponse.blob();
        const imageBuffer = await imageBlob.arrayBuffer();
        let filename =
          url.split("/").pop()?.split("?")[0] || `floor_plan_${index + 1}.jpg`;
        if (!filename.match(/\.(jpg|jpeg|png|gif|webp|pdf)$/i)) {
          filename = `floor_plan_${index + 1}.jpg`;
        }

        const response = await withRetry(
          async () => {
            const res = await fetch(
              `${config.apiUrl}/jsonapi/node/property/field_floor_plan`,
              {
                method: "POST",
                headers: {
                  Authorization: `Bearer ${token}`,
                  "Content-Type": "application/octet-stream",
                  "Content-Disposition": `file; filename="${filename}"`,
                  "User-Agent": "SophiaAI",
                },
                body: imageBuffer,
                signal: AbortSignal.timeout(30_000),
              }
            );
            if (!res.ok && res.status >= 500) {
              throw new Error(`Floor plan upload failed: ${res.status}`);
            }
            return res;
          },
          { maxRetries: 2, baseDelayMs: 500 },
          "uploadFloorPlan"
        );

        if (!response.ok) {
          const errorBody = await response.text().catch(() => "");
          logger.error("Floor plan upload failed", undefined, {
            category: LogCategory.ZYPRUS,
            operation: "uploadFloorPlan",
            imageIndex: index,
            status: response.status,
            statusText: response.statusText,
            errorBody: errorBody.substring(0, 500),
            url: url.substring(0, 100),
          });
          // If field_floor_plan endpoint fails, try uploading via field_gallery_ as fallback
          // The file ID can still be referenced in field_floor_plan relationship
          const fallbackRes = await fetch(
            `${config.apiUrl}/jsonapi/node/property/field_gallery_`,
            {
              method: "POST",
              headers: {
                Authorization: `Bearer ${token}`,
                "Content-Type": "application/octet-stream",
                "Content-Disposition": `file; filename="${filename}"`,
                "User-Agent": "SophiaAI",
              },
              body: imageBuffer,
              signal: AbortSignal.timeout(30_000),
            }
          );
          if (fallbackRes.ok) {
            const fallbackResult = await fallbackRes.json();
            logger.info("Floor plan uploaded via gallery fallback", {
              category: LogCategory.ZYPRUS,
              operation: "uploadFloorPlan",
              imageIndex: index,
              fileId: fallbackResult.data?.id,
            });
            return fallbackResult.data?.id || null;
          }
          return null;
        }

        const result = await response.json();
        return result.data?.id || null;
      } catch (error) {
        const err = error instanceof Error ? error : new Error(String(error));
        logger.error("Floor plan upload error", err, {
          category: LogCategory.ZYPRUS,
          operation: "uploadFloorPlan",
          imageIndex: index,
        });
        return null;
      }
    })
  );

  return results.filter((id): id is string => id !== null);
}

/**
 * Upload title deed files to Zyprus (uses field_title_deed_file endpoint)
 * Falls back gracefully if the field doesn't exist on property nodes
 */
async function uploadTitleDeedFiles(
  fileUrls: string[],
  token: string,
  config: ZyprusConfig
): Promise<string[]> {
  logger.info("Uploading title deed files to Zyprus", {
    category: LogCategory.ZYPRUS,
    operation: "uploadTitleDeedFiles",
    count: fileUrls.length,
  });

  const results = await Promise.all(
    fileUrls.map(async (url, index) => {
      try {
        const fileResponse = await fetch(url, {
          signal: AbortSignal.timeout(30_000),
        });
        if (!fileResponse.ok) {
          logger.warn("Failed to download title deed file", {
            category: LogCategory.ZYPRUS,
            operation: "uploadTitleDeedFile",
            imageIndex: index,
            status: fileResponse.status,
          });
          return null;
        }

        const fileBlob = await fileResponse.blob();
        const fileBuffer = await fileBlob.arrayBuffer();
        // Detect actual file type from Content-Type header or blob type
        const contentType =
          fileResponse.headers.get("content-type") || fileBlob.type || "";
        const extFromMime: Record<string, string> = {
          "image/jpeg": ".jpg",
          "image/png": ".png",
          "image/gif": ".gif",
          "image/webp": ".webp",
          "application/pdf": ".pdf",
          "application/msword": ".doc",
          "application/vnd.openxmlformats-officedocument.wordprocessingml.document":
            ".docx",
        };
        const detectedExt =
          extFromMime[contentType.split(";")[0].trim().toLowerCase()];
        let filename =
          url.split("/").pop()?.split("?")[0] || `title_deed_${index + 1}`;
        if (!filename.match(/\.(jpg|jpeg|png|gif|webp|pdf|doc|docx)$/i)) {
          // Use detected extension from content-type, default to .jpg for images
          filename = `title_deed_${index + 1}${detectedExt || ".jpg"}`;
        }
        logger.info("Title deed file type detected", {
          category: LogCategory.ZYPRUS,
          operation: "uploadTitleDeedFile",
          imageIndex: index,
          contentType,
          filename,
        });

        const response = await withRetry(
          async () => {
            const res = await fetch(
              `${config.apiUrl}/jsonapi/node/property/field_title_deed_file`,
              {
                method: "POST",
                headers: {
                  Authorization: `Bearer ${token}`,
                  "Content-Type": "application/octet-stream",
                  "Content-Disposition": `file; filename="${filename}"`,
                  "User-Agent": "SophiaAI",
                },
                body: fileBuffer,
                signal: AbortSignal.timeout(30_000),
              }
            );
            if (!res.ok && res.status >= 500) {
              throw new Error(`Title deed upload failed: ${res.status}`);
            }
            return res;
          },
          { maxRetries: 2, baseDelayMs: 500 },
          "uploadTitleDeedFile"
        );

        if (!response.ok) {
          let errorBody = "";
          try {
            errorBody = await response.text();
          } catch {
            /* ignore */
          }
          logger.warn("Title deed upload to Zyprus failed", {
            category: LogCategory.ZYPRUS,
            operation: "uploadTitleDeedFile",
            status: response.status,
            filename,
            contentType,
            errorBody: errorBody.substring(0, 500),
          });
          return null;
        }

        const result = await response.json();
        return result.data?.id || null;
      } catch (error) {
        const err = error instanceof Error ? error : new Error(String(error));
        logger.error("Title deed upload error", err, {
          category: LogCategory.ZYPRUS,
          operation: "uploadTitleDeedFile",
          imageIndex: index,
        });
        return null;
      }
    })
  );

  return results.filter((id): id is string => id !== null);
}

/**
 * Create a property listing draft
 */
export async function createDraftListing(
  listing: ListingData
): Promise<CreateResult> {
  const config = getZyprusConfig();
  const token = await getAccessToken(config);

  logger.info("Creating draft listing on Zyprus", {
    category: LogCategory.ZYPRUS,
    operation: "createDraftListing",
    listingType: listing.listingType,
    propertyType: listing.propertyType,
    location: listing.location,
  });

  // Log incoming values for debugging
  logger.info("Listing assignment values (incoming)", {
    category: LogCategory.ZYPRUS,
    operation: "createDraftListing",
    listingOwner: listing.listingOwner,
    listingInstructor: listing.listingInstructor,
    reviewer1: listing.reviewer1,
    reviewer2: listing.reviewer2,
    match: listing.listingOwner === listing.listingInstructor,
  });

  // Collect all reviewer emails for UUID resolution
  const reviewerEmails: string[] = [];
  if (listing.reviewer1) reviewerEmails.push(listing.reviewer1);
  if (listing.reviewer2) reviewerEmails.push(listing.reviewer2);

  // Resolve all taxonomy UUIDs, user UUIDs, and feature UUIDs in parallel
  // CRITICAL: listingOwner and listingInstructor should be the SAME person (same UUID)
  // We resolve listingOwner first, then use that UUID for both fields
  const [
    listingTypeUuid,
    propertyTypeUuid,
    priceModifierUuid,
    titleDeedUuid,
    listingOwnerUuid,
    reviewerUuids,
    indoorFeatureUuids,
    outdoorFeatureUuids,
    viewUuids,
  ] = await Promise.all([
    findListingTypeUuid(listing.listingType),
    findPropertyTypeUuid(listing.propertyType),
    findPriceModifierUuid(listing.priceModifier, listing.priceNegotiable), // Default "Negotiable" unless explicitly non-negotiable
    findTitleDeedUuid(listing.titleDeedStatus), // Maps status to Zyprus taxonomy (permits_only → "not available")
    findUserUuid(listing.listingOwner), // CRITICAL: Resolve listing owner email to UUID
    findUserUuids(reviewerEmails), // Resolve reviewer emails to UUIDs
    findIndoorFeatureUuids(listing.features || [], listing.bathrooms), // Resolve indoor features (auto-adds guest toilet + master bed if bathrooms >= 2)
    findOutdoorFeatureUuids(listing.features || []), // Resolve outdoor features
    findPropertyViewUuids(listing.features || []), // Resolve property views (sea view, etc.)
  ]);

  // Note: All taxonomy/user functions now have hardcoded fallbacks, so they cannot fail

  // CRITICAL: listingInstructor MUST be the same UUID as listingOwner
  const instructorUuid = listingOwnerUuid;

  logger.info("Resolved Zyprus UUIDs for listing", {
    category: LogCategory.ZYPRUS,
    operation: "createDraftListing",
    listingTypeUuid,
    propertyTypeUuid,
    priceModifierUuid,
    titleDeedUuid,
    instructorUuid,
    listingOwnerUuid,
    reviewerCount: reviewerUuids.length,
    indoorFeatureCount: indoorFeatureUuids.length,
    outdoorFeatureCount: outdoorFeatureUuids.length,
    viewCount: viewUuids.length,
  });

  // Upload all file types in parallel (gallery, floor plans, title deeds)
  const [imageFileIds, floorPlanFileIds, titleDeedFileIds] = await Promise.all([
    uploadImages(listing.images, token, config),
    listing.floorPlanUrls && listing.floorPlanUrls.length > 0
      ? uploadFloorPlans(listing.floorPlanUrls, token, config)
      : Promise.resolve([] as string[]),
    listing.titleDeedFileUrls && listing.titleDeedFileUrls.length > 0
      ? uploadTitleDeedFiles(listing.titleDeedFileUrls, token, config)
      : Promise.resolve([] as string[]),
  ]);

  logger.info("All files uploaded for listing", {
    category: LogCategory.ZYPRUS,
    operation: "createDraftListing",
    galleryUploaded: imageFileIds.length,
    galleryTotal: listing.images.length,
    floorPlansUploaded: floorPlanFileIds.length,
    titleDeedsUploaded: titleDeedFileIds.length,
  });

  // Build and send listing payload
  const payload = buildJsonApiPayload(
    listing,
    imageFileIds,
    listingTypeUuid,
    propertyTypeUuid,
    priceModifierUuid,
    titleDeedUuid,
    instructorUuid,
    reviewerUuids,
    listingOwnerUuid,
    indoorFeatureUuids,
    outdoorFeatureUuids,
    viewUuids,
    floorPlanFileIds,
    titleDeedFileIds
  );

  const response = await withRetry(
    async () => {
      const res = await fetch(`${config.apiUrl}/jsonapi/node/property`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/vnd.api+json",
          Accept: "application/vnd.api+json",
          "User-Agent": "SophiaAI",
        },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(30_000),
      });

      // Only retry on server errors, not client errors (4xx)
      if (!res.ok && res.status >= 500) {
        throw new Error(`Listing creation failed: ${res.status}`);
      }
      return res;
    },
    { maxRetries: 2, baseDelayMs: 1000 },
    "createDraftListing"
  );

  if (!response.ok) {
    const errorText = await response.text();
    // Include error details in the exception for debugging
    let errorDetail = "";
    try {
      const errorJson = JSON.parse(errorText);
      if (errorJson.errors) {
        errorDetail = errorJson.errors
          .map((e: { detail?: string; title?: string }) =>
            e.detail || e.title || JSON.stringify(e)
          )
          .join("; ");
      }
    } catch {
      errorDetail = errorText.substring(0, 200);
    }
    // Log full error details internally for debugging
    logClassifiedError(
      "Failed to create Zyprus listing",
      new Error(
        `API error: ${response.status} - ${errorDetail || "Unknown error"}`
      ),
      {
        category: LogCategory.ZYPRUS,
        operation: "createDraftListing",
        status: response.status,
        errorDetail,
      }
    );
    // Include status and error detail in thrown error so executor can log the root cause
    throw new Error(
      `Zyprus API ${response.status}: ${errorDetail || "Unknown error"}`
    );
  }

  const result = await response.json();
  const listingId = result.data.id;

  logger.info("Zyprus listing created successfully", {
    category: LogCategory.ZYPRUS,
    operation: "createDraftListing",
    listingId,
  });

  // Title deed files: Check if they were included in the initial POST payload.
  // If the POST succeeded with title deeds in relationships, they're already attached.
  // The PATCH fallback only runs if we need to retry attachment separately.
  let titleDeedAttached = titleDeedFileIds.length > 0; // Assume attached via POST
  if (titleDeedFileIds.length > 0) {
    // Verify attachment by checking if the POST response includes the relationship
    // If not present, fall back to PATCH
    const hasRelationship = result.data?.relationships?.field_title_deed_file?.data;
    if (hasRelationship) {
      logger.info("Title deed files attached via initial POST", {
        category: LogCategory.ZYPRUS,
        operation: "createDraftListing",
        listingId,
        fileCount: titleDeedFileIds.length,
      });
    } else {
      // POST didn't include title deeds (possibly 403 on that field) — fall back to PATCH
      titleDeedAttached = false;
      logger.warn("Title deed files NOT in POST response — falling back to PATCH", {
        category: LogCategory.ZYPRUS,
        operation: "patchTitleDeedFiles",
        listingId,
      });
    }
  }
  if (titleDeedFileIds.length > 0 && !titleDeedAttached) {
    const patchPayload = {
      data: {
        type: "node--property",
        id: listingId,
        relationships: {
          field_title_deed_file: {
            data: titleDeedFileIds.map((id) => ({
              type: "file--file",
              id,
            })),
          },
        },
      },
    };

    // Retry up to 3 times with increasing delay
    for (let attempt = 1; attempt <= 3; attempt++) {
      try {
        const patchRes = await fetch(
          `${config.apiUrl}/jsonapi/node/property/${listingId}`,
          {
            method: "PATCH",
            headers: {
              Authorization: `Bearer ${token}`,
              "Content-Type": "application/vnd.api+json",
              Accept: "application/vnd.api+json",
              "User-Agent": "SophiaAI",
            },
            body: JSON.stringify(patchPayload),
            signal: AbortSignal.timeout(30_000),
          }
        );
        if (patchRes.ok) {
          titleDeedAttached = true;
          logger.info("Title deed files attached to listing via PATCH", {
            category: LogCategory.ZYPRUS,
            operation: "patchTitleDeedFiles",
            listingId,
            fileCount: titleDeedFileIds.length,
            attempt,
          });
          break;
        } else {
          let patchErrorBody = "";
          try {
            patchErrorBody = await patchRes.text();
          } catch {
            /* ignore */
          }
          logger.error(
            `Title deed PATCH failed (attempt ${attempt}/3)`,
            undefined,
            {
              category: LogCategory.ZYPRUS,
              operation: "patchTitleDeedFiles",
              listingId,
              status: patchRes.status,
              errorBody: patchErrorBody.substring(0, 500),
              attempt,
            }
          );
          // Only retry on 5xx errors
          if (patchRes.status < 500 && attempt < 3) {
            // 4xx error — likely permissions. Try without delay.
            continue;
          }
        }
      } catch (patchError) {
        logger.error(
          `Title deed PATCH exception (attempt ${attempt}/3)`,
          patchError instanceof Error
            ? patchError
            : new Error(String(patchError)),
          {
            category: LogCategory.ZYPRUS,
            operation: "patchTitleDeedFiles",
            listingId,
            attempt,
          }
        );
      }
      // Wait before retry (500ms, 1s, 2s)
      if (attempt < 3) {
        await new Promise((r) => setTimeout(r, 500 * attempt));
      }
    }

    if (!titleDeedAttached) {
      logger.error(
        "CRITICAL: Title deed files could NOT be attached after 3 attempts",
        undefined,
        {
          category: LogCategory.ZYPRUS,
          operation: "patchTitleDeedFiles",
          listingId,
          fileCount: titleDeedFileIds.length,
        }
      );
    }
  }

  return {
    listingId,
    listingUrl: `${config.siteUrl}/property/${listingId}`,
    titleDeedAttached: titleDeedFileIds.length > 0 ? titleDeedAttached : undefined,
  };
}

/**
 * Search for existing properties
 */
export async function searchProperties(
  query: string,
  filters?: Record<string, string>
): Promise<unknown[]> {
  const config = getZyprusConfig();
  const token = await getAccessToken(config);

  let url = `${config.apiUrl}/jsonapi/node/property?page[limit]=10`;

  if (query) {
    url += `&filter[title][operator]=CONTAINS&filter[title][value]=${encodeURIComponent(query)}`;
  }

  if (filters) {
    for (const [key, value] of Object.entries(filters)) {
      url += `&filter[${key}]=${encodeURIComponent(value)}`;
    }
  }

  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/vnd.api+json",
      "User-Agent": "SophiaAI",
    },
    signal: AbortSignal.timeout(30_000),
  });

  if (!response.ok) {
    logger.error("Zyprus property search failed", undefined, {
      category: LogCategory.ZYPRUS,
      operation: "searchProperties",
      status: response.status,
      query,
    });
    return [];
  }

  const data = await response.json();
  return data.data || [];
}

/**
 * Location & User Taxonomy Lookups
 * Extracted from taxonomy-cache.ts for better modularity
 */

import { getSupabaseAdmin } from "../../_shared/db.ts";
import {
  AGENT_NAME_MAP,
  DEFAULT_LOCATION_UUID,
  REGION_LOCATIONS,
  SOPHIA_AI_UUID,
  USER_FALLBACKS,
} from "../config/business-rules.ts";
import { LogCategory, logger } from "../utils/logger.ts";
import { loadTaxonomy, type TaxonomyCache } from "./taxonomy-cache.ts";

/**
 * Sanitize email input for use in filter queries
 * Prevents filter injection by only allowing valid email characters
 */
function sanitizeEmailForFilter(email: string): string {
  // Only allow alphanumeric, @, ., _, -, and +
  return email
    .replace(/[^a-zA-Z0-9@._+-]/g, "")
    .toLowerCase()
    .trim();
}

/**
 * Lookup agent's Zyprus UUID from Supabase agents table
 * Returns null if not found or no zyprus_user_id set
 */
async function lookupAgentFromSupabase(email: string): Promise<string | null> {
  // Sanitize email to prevent filter injection
  const sanitizedEmail = sanitizeEmailForFilter(email);
  if (!sanitizedEmail || !sanitizedEmail.includes("@")) {
    logger.debug("[Taxonomy] Invalid email format", {
      category: LogCategory.ZYPRUS,
    });
    return null;
  }

  try {
    const supabase = getSupabaseAdmin();

    // Use separate queries to avoid filter injection with .or() string interpolation
    // First try listing_owner_email
    const { data: ownerData, error: ownerError } = await supabase
      .from("agents")
      .select("zyprus_user_id, full_name")
      .eq("listing_owner_email", sanitizedEmail)
      .eq("is_active", true)
      .limit(1)
      .maybeSingle();

    if (!ownerError && ownerData && ownerData.zyprus_user_id) {
      logger.debug(
        `[Taxonomy] Found agent "${ownerData.full_name}" in Supabase with Zyprus UUID: ${ownerData.zyprus_user_id}`
      );
      return ownerData.zyprus_user_id;
    }

    // Then try communication_email
    const { data: commData, error: commError } = await supabase
      .from("agents")
      .select("zyprus_user_id, full_name")
      .eq("communication_email", sanitizedEmail)
      .eq("is_active", true)
      .limit(1)
      .maybeSingle();

    if (!commError && commData && commData.zyprus_user_id) {
      logger.debug(
        `[Taxonomy] Found agent "${commData.full_name}" in Supabase with Zyprus UUID: ${commData.zyprus_user_id}`
      );
      return commData.zyprus_user_id;
    }

    // Check if we found an agent without zyprus_user_id
    if (
      (ownerData && !ownerData.zyprus_user_id) ||
      (commData && !commData.zyprus_user_id)
    ) {
      const agentData = ownerData || commData;
      logger.debug(
        `[Taxonomy] Agent "${agentData!.full_name}" found but no zyprus_user_id set`
      );
    }

    return null;
  } catch (err) {
    logger.error(
      "[Taxonomy] Error looking up agent from Supabase",
      err instanceof Error ? err : new Error(String(err)),
      { category: LogCategory.ZYPRUS }
    );
    return null;
  }
}

/** Result from location UUID lookup — includes matched taxonomy name for title/description */
export interface LocationResult {
  uuid: string;
  /** The taxonomy name Zyprus uses for this location (e.g., "Strovolos, Nicosia") */
  matchedName: string;
  /** The detected district from the input (e.g., "nicosia") */
  district: string | null;
}

/**
 * Find location UUID by name
 * MANDATORY field - always returns a valid UUID
 *
 * CRITICAL FIX FOR DISTRICT DISAMBIGUATION:
 * When a district is explicitly specified (e.g., "Neapoli, Limassol"),
 * we MUST prioritize locations that are in that district over locations
 * with the same name in other districts.
 *
 * e.g., "Neapoli, Limassol" should match "Neapoli" in Limassol district,
 * NOT "Neapoli" in Nicosia district.
 *
 * Returns LocationResult with uuid, matchedName (taxonomy name), and district.
 */
export async function findLocationUuid(
  locationName: string
): Promise<LocationResult> {
  const normalized = locationName.toLowerCase().trim();
  let specifiedDistrict: string | null = null; // Declare outside try for error logging

  try {
    const taxonomy = await loadTaxonomy();

    // Helper to build LocationResult from a matched location
    const buildResult = (
      loc: TaxonomyCache["locations"][0],
      district: string | null
    ): LocationResult => ({
      uuid: loc.id,
      matchedName: loc.name,
      district,
    });

    // Try exact match first
    const exact = taxonomy.locations.find(
      (loc) => loc.name.toLowerCase() === normalized
    );
    if (exact) {
      logger.debug(
        `[Taxonomy] Exact match for "${locationName}": ${exact.name}`
      );
      return buildResult(exact, null);
    }

    // Extract words from input (filter short words)
    const words = normalized.split(/[\s,]+/).filter((w) => w.length > 2);

    if (words.length === 0) {
      // No meaningful words, use default
      logger.debug(
        `[Taxonomy] No meaningful words in "${locationName}", using default`
      );
      return {
        uuid: DEFAULT_LOCATION_UUID,
        matchedName: locationName,
        district: null,
      };
    }

    // CRITICAL: Detect the EXPLICITLY SPECIFIED district from input
    // This is the district name that appears AFTER the comma or as one of the words
    for (const [region, locationsList] of Object.entries(REGION_LOCATIONS)) {
      // Check if any region name or aliases appear in the input
      const regionAliases = [region, ...locationsList];
      if (
        words.some((w) =>
          regionAliases.some(
            (alias) => w === alias || w.includes(alias) || alias.includes(w)
          )
        )
      ) {
        specifiedDistrict = region;
        logger.debug(
          `[Taxonomy] Explicitly specified district "${region}" in input: ${locationName}`
        );
        break;
      }
    }

    // The FIRST word is usually the specific location (e.g., "Neapoli" in "Neapoli, Limassol")
    const firstWord = words[0];

    // Score all locations by multiple factors
    const scoredMatches: Array<{
      location: TaxonomyCache["locations"][0];
      score: number;
      matchedWords: string[];
      bonusReason: string;
    }> = [];

    for (const loc of taxonomy.locations) {
      const locNameLower = loc.name.toLowerCase();
      const locWords = locNameLower.split(/[\s,]+/).filter((w) => w.length > 1);
      const matchedWords: string[] = [];
      let score = 0;
      let bonusReason = "";

      // Check each input word for matches in the location name
      for (const word of words) {
        if (locNameLower.includes(word)) {
          matchedWords.push(word);
          // Exact word match gets more points than substring
          if (locWords.includes(word)) {
            score += 5; // Strong bonus for exact word match
            bonusReason += `exact:${word} `;
          } else {
            score += 1; // Weaker bonus for substring match
          }
        }
      }

      if (matchedWords.length === 0) {
        continue; // Skip locations with no matches
      }

      // CRITICAL: Strong bonus for matching the FIRST word (the specific location)
      // "Neapoli" should match "Neapoli" in the specified district
      if (firstWord && locNameLower.includes(firstWord)) {
        score += 20; // Very strong bonus for matching the specific location name
        bonusReason += `first-word:${firstWord} `;
      }

      // CRITICAL FIX: District-aware scoring
      // If user specified a district, heavily penalize locations NOT in that district
      if (specifiedDistrict) {
        const regionLocs = REGION_LOCATIONS[specifiedDistrict] || [];

        // Check if this location is in the specified district
        // CRITICAL: Use EXACT word match, not substring, to avoid "neapoli" matching "neapolis"
        // Also check multi-word entries (e.g., "mesa chorio", "kato paphos") against full name
        const locationIsInDistrict =
          locWords.some((locWord) =>
            regionLocs.some((regLoc) => locWord === regLoc)
          ) ||
          regionLocs.some(
            (regLoc) => regLoc.includes(" ") && locNameLower.includes(regLoc)
          );

        if (locationIsInDistrict) {
          score += 30; // HUGE bonus for being in the specified district
          bonusReason += `district-match:${specifiedDistrict} `;
        } else {
          // Check if location is in a DIFFERENT district
          let locationInOtherDistrict: string | null = null;
          for (const [otherRegion, otherLocs] of Object.entries(
            REGION_LOCATIONS
          )) {
            if (otherRegion === specifiedDistrict) continue;
            if (
              locWords.some((locWord) =>
                otherLocs.some((otherLoc) => locWord === otherLoc)
              ) ||
              otherLocs.some(
                (otherLoc) =>
                  otherLoc.includes(" ") && locNameLower.includes(otherLoc)
              )
            ) {
              locationInOtherDistrict = otherRegion;
              break;
            }
          }

          // HEAVY PENALTY for locations in the wrong district
          if (locationInOtherDistrict) {
            score -= 50; // Massive penalty for wrong district
            bonusReason += `WRONG-DISTRICT:${locationInOtherDistrict} `;
            logger.debug(
              `[Taxonomy] Penalizing "${loc.name}" - in ${locationInOtherDistrict}, user wants ${specifiedDistrict}`
            );
          }
        }
      }

      // Region bonus: Give moderate bonus if this location is in a detected region (when no explicit district)
      if (!specifiedDistrict) {
        for (const [region, locationsList] of Object.entries(
          REGION_LOCATIONS
        )) {
          const regionLocs = locationsList;
          const locationIsInRegion = locWords.some((locWord) =>
            regionLocs.some(
              (regLoc) => locWord.includes(regLoc) || regLoc.includes(locWord)
            )
          );

          if (locationIsInRegion) {
            score += 5; // Moderate bonus for being in any region
            bonusReason += `region:${region} `;
            break; // Only count one region bonus
          }
        }
      }

      scoredMatches.push({ location: loc, score, matchedWords, bonusReason });
    }

    // Sort by score descending, return best match
    if (scoredMatches.length > 0) {
      scoredMatches.sort((a, b) => b.score - a.score);
      const best = scoredMatches[0];

      // CRITICAL: When a district is specified, ONLY accept matches in that district
      // If the best match is in the wrong district, discard all matches and use fallback
      if (specifiedDistrict) {
        const regionLocs = REGION_LOCATIONS[specifiedDistrict] || [];
        const bestLocWords = best.location.name
          .toLowerCase()
          .split(/[\s,]+/)
          .filter((w) => w.length > 1);
        const bestLocNameLower = best.location.name.toLowerCase();
        // CRITICAL: Use EXACT word match for district detection + multi-word entries
        const bestIsInDistrict =
          bestLocWords.some((locWord) =>
            regionLocs.some((regLoc) => locWord === regLoc)
          ) ||
          regionLocs.some(
            (regLoc) =>
              regLoc.includes(" ") && bestLocNameLower.includes(regLoc)
          );

        if (bestIsInDistrict) {
          logger.debug(
            `[Taxonomy] Best match for "${locationName}": ${best.location.name} (score: ${best.score}, matched: ${best.matchedWords.join(", ")}, bonus: ${best.bonusReason})`
          );

          // Log top 3 alternatives for debugging
          for (let i = 1; i < Math.min(4, scoredMatches.length); i++) {
            const alt = scoredMatches[i];
            logger.debug(
              `[Taxonomy] Alternative ${i}: ${alt.location.name} (score: ${alt.score}, ${alt.bonusReason})`
            );
          }

          return buildResult(best.location, specifiedDistrict);
        }
        logger.warn(
          `[Taxonomy] Best match "${best.location.name}" is NOT in specified district "${specifiedDistrict}" - discarding and using fallback`,
          { category: LogCategory.ZYPRUS }
        );
      } else {
        logger.debug(
          `[Taxonomy] Best match for "${locationName}": ${best.location.name} (score: ${best.score}, matched: ${best.matchedWords.join(", ")}, bonus: ${best.bonusReason})`
        );

        // Log top 3 alternatives for debugging
        for (let i = 1; i < Math.min(4, scoredMatches.length); i++) {
          const alt = scoredMatches[i];
          logger.debug(
            `[Taxonomy] Alternative ${i}: ${alt.location.name} (score: ${alt.score}, ${alt.bonusReason})`
          );
        }

        return buildResult(best.location, specifiedDistrict);
      }
    }

    // Fallback: try to find a general location in the detected region
    if (specifiedDistrict && taxonomy.locations.length > 0) {
      // Get all location names that belong to this district from REGION_LOCATIONS
      const regionLocs = REGION_LOCATIONS[specifiedDistrict] || [];

      // First try: direct name match with district name (e.g., "Limassol")
      let regionFallback = taxonomy.locations.find((loc) =>
        loc.name.toLowerCase().includes(specifiedDistrict!)
      );

      // Second try: match ANY location name that appears in REGION_LOCATIONS for this district
      // CRITICAL: Use EXACT word match to avoid "neapoli" matching "neapolis" + multi-word entries
      if (!regionFallback && regionLocs.length > 0) {
        regionFallback = taxonomy.locations.find((loc) => {
          const locNameLower = loc.name.toLowerCase();
          const locWords = locNameLower
            .split(/[\s,]+/)
            .filter((w) => w.length > 1);
          return (
            locWords.some((locWord) => regionLocs.includes(locWord)) ||
            regionLocs.some(
              (regLoc) => regLoc.includes(" ") && locNameLower.includes(regLoc)
            )
          );
        });
      }

      // Third try: just find the first location that STARTS with the district name
      if (!regionFallback) {
        regionFallback = taxonomy.locations.find((loc) =>
          loc.name.toLowerCase().startsWith(specifiedDistrict!)
        );
      }

      if (regionFallback) {
        logger.debug(
          `[Taxonomy] Using region fallback for "${locationName}" (district: ${specifiedDistrict}): ${regionFallback.name}`
        );
        return buildResult(regionFallback, specifiedDistrict);
      }

      logger.warn(
        `[Taxonomy] No location found for district "${specifiedDistrict}" in "${locationName}", will use default`,
        { category: LogCategory.ZYPRUS }
      );
    }

    // Ultimate fallback: return first location if available (ONLY when no district specified)
    if (!specifiedDistrict && taxonomy.locations.length > 0) {
      logger.debug(
        `[Taxonomy] WARNING: Using first available location for "${locationName}": ${taxonomy.locations[0].name}`
      );
      return buildResult(taxonomy.locations[0], null);
    }
  } catch (error) {
    logger.error(
      "[Taxonomy] Error finding location",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.ZYPRUS }
    );
  }

  // Ultimate fallback: use default location UUID
  // NOTE: Zyprus API REQUIRES field_location to be non-null (422 error if missing)
  // Since Zyprus only has Nicosia locations in the database, we must use Nicosia as fallback
  // even for other districts. The location mismatch will be noted in AI message for manual correction.
  if (specifiedDistrict) {
    logger.warn(
      `[Taxonomy] No location found for district "${specifiedDistrict}" in "${locationName}" - using Nicosia default as API requires non-null location`,
      { category: LogCategory.ZYPRUS }
    );
  } else {
    logger.debug(
      `[Taxonomy] Using hardcoded default location UUID for: ${locationName}`
    );
  }
  return {
    uuid: DEFAULT_LOCATION_UUID,
    matchedName: locationName,
    district: specifiedDistrict,
  };
}

/**
 * Get all locations for a region
 */
export async function getLocationsByRegion(
  region: string
): Promise<TaxonomyCache["locations"]> {
  const taxonomy = await loadTaxonomy();

  // Region to parent location mapping
  const regionParents: Record<string, string[]> = {
    paphos: ["paphos", "pafos"],
    limassol: ["limassol", "lemesos"],
    larnaca: ["larnaca", "larnaka"],
    nicosia: ["nicosia", "lefkosia"],
    famagusta: ["famagusta", "ammochostos"],
  };

  const parentTerms = regionParents[region.toLowerCase()] || [];

  // Find parent location IDs
  const parentIds = taxonomy.locations
    .filter((loc) =>
      parentTerms.some((term) => loc.name.toLowerCase().includes(term))
    )
    .map((loc) => loc.id);

  // Return all locations that have these parents
  return taxonomy.locations.filter(
    (loc) => loc.parentId && parentIds.includes(loc.parentId)
  );
}

/**
 * Find user UUID by email address
 * Uses multiple lookup strategies:
 * 0. Supabase agents table (NEW - highest priority)
 * 1. Direct email match from Zyprus API
 * 2. Name/display_name match using AGENT_NAME_MAP
 * 3. Hardcoded UUID fallbacks
 * 4. SOPHIA_AI_UUID as ultimate fallback
 */
export async function findUserUuid(email: string): Promise<string> {
  if (!email) {
    logger.debug("[Taxonomy] No email provided, using SOPHIA_AI_UUID", {
      category: LogCategory.ZYPRUS,
    });
    return SOPHIA_AI_UUID;
  }

  const normalizedEmail = email.toLowerCase().trim();

  // Strategy 0: Check Supabase agents table FIRST (most reliable)
  const supabaseUuid = await lookupAgentFromSupabase(normalizedEmail);
  if (supabaseUuid) {
    return supabaseUuid;
  }

  try {
    const taxonomy = await loadTaxonomy();

    // Strategy 1: Direct email match from Zyprus API
    const userByEmail = taxonomy.users.find((u) => u.email === normalizedEmail);
    if (userByEmail) {
      logger.debug(
        `[Taxonomy] Found user by email ${normalizedEmail}: ${userByEmail.id}`
      );
      return userByEmail.id;
    }

    // Strategy 2: Match by name/display_name using AGENT_NAME_MAP
    const possibleNames = AGENT_NAME_MAP[normalizedEmail];
    if (possibleNames && possibleNames.length > 0) {
      for (const name of possibleNames) {
        const normalizedName = name.toLowerCase();
        const userByName = taxonomy.users.find(
          (u) =>
            u.name.toLowerCase() === normalizedName ||
            u.name.toLowerCase().includes(normalizedName) ||
            normalizedName.includes(u.name.toLowerCase())
        );
        if (userByName) {
          logger.debug(
            `[Taxonomy] Found user by name "${name}" for ${normalizedEmail}: ${userByName.id}`
          );
          return userByName.id;
        }
      }
    }

    // Strategy 3: Try matching just the username part of email (e.g., "evelina" from "evelina@zyprus.com")
    const emailUsername = normalizedEmail.split("@")[0];
    if (emailUsername && emailUsername.length > 2) {
      const userByUsername = taxonomy.users.find(
        (u) =>
          u.name.toLowerCase() === emailUsername ||
          u.name.toLowerCase().includes(emailUsername)
      );
      if (userByUsername) {
        logger.debug(
          `[Taxonomy] Found user by username "${emailUsername}" for ${normalizedEmail}: ${userByUsername.id}`
        );
        return userByUsername.id;
      }
    }

    logger.debug(
      `[Taxonomy] User not found in API for ${normalizedEmail}, checking fallbacks`
    );
  } catch (error) {
    logger.error(
      "[Taxonomy] Error finding user",
      error instanceof Error ? error : new Error(String(error)),
      { category: LogCategory.ZYPRUS }
    );
  }

  // Strategy 4: Check hardcoded fallbacks
  const fallback = USER_FALLBACKS[normalizedEmail];
  if (fallback) {
    logger.debug(
      `[Taxonomy] Using hardcoded fallback for ${normalizedEmail}: ${fallback}`
    );
    return fallback;
  }

  // Ultimate fallback: use SOPHIA_AI_UUID
  logger.debug(
    `[Taxonomy] Using SOPHIA_AI_UUID fallback for ${normalizedEmail}`
  );
  return SOPHIA_AI_UUID;
}

/**
 * Find multiple user UUIDs for reviewers
 * IMPORTANT: Excludes SOPHIA_AI_UUID from results to prevent "Sophia AI ()" showing as reviewer
 * Only returns UUIDs for emails that can be resolved to actual users
 */
export async function findUserUuids(emails: string[]): Promise<string[]> {
  const validEmails = emails.filter(Boolean);
  const results = await Promise.all(
    validEmails.map((email) => findUserUuid(email))
  );

  const uuids: string[] = [];
  for (let i = 0; i < results.length; i++) {
    const uuid = results[i];
    if (uuid !== SOPHIA_AI_UUID && !uuids.includes(uuid)) {
      uuids.push(uuid);
    } else if (uuid === SOPHIA_AI_UUID) {
      logger.debug(
        `[Taxonomy] Skipping SOPHIA_AI_UUID for reviewer email: ${validEmails[i]}`
      );
    }
  }
  return uuids;
}

/**
 * Zyprus OAuth2 Authentication
 * Handles token management and configuration for Zyprus API
 */

import { LogCategory, logger } from "../utils/logger.ts";
import { withRetry } from "../utils/retry.ts";
import {
  canRequest,
  recordSuccess,
  recordFailure,
} from "../utils/circuit-breaker.ts";

export interface TokenCache {
  token: string;
  expiresAt: number;
}

export interface ZyprusConfig {
  apiUrl: string;
  siteUrl: string;
  clientId: string;
  clientSecret: string;
}

// Token cache (in-memory for Edge Function)
let cachedToken: TokenCache | null = null;

// Circuit breaker configuration for Zyprus API
const ZYPRUS_BREAKER_CONFIG = {
  name: "zyprus-api",
  failureThreshold: 3,
  resetTimeoutMs: 60_000, // 1 minute
};

/**
 * Get Zyprus API configuration from environment
 */
export function getZyprusConfig(): ZyprusConfig {
  const apiUrl = Deno.env.get("ZYPRUS_API_URL");
  const siteUrl = Deno.env.get("ZYPRUS_SITE_URL") || "https://zyprus.com";
  const clientId = Deno.env.get("ZYPRUS_CLIENT_ID");
  const clientSecret = Deno.env.get("ZYPRUS_CLIENT_SECRET");

  if (!apiUrl || !clientId || !clientSecret) {
    throw new Error("Zyprus API credentials not configured");
  }

  return { apiUrl, siteUrl, clientId, clientSecret };
}

/**
 * Get OAuth2 access token
 */
export async function getAccessToken(config: ZyprusConfig): Promise<string> {
  // Check cache (with 5 minute buffer)
  if (cachedToken && cachedToken.expiresAt > Date.now() + 300_000) {
    return cachedToken.token;
  }

  // Circuit breaker check - fail fast if Zyprus is down
  if (!canRequest(ZYPRUS_BREAKER_CONFIG)) {
    throw new Error(
      "[Zyprus] Circuit breaker OPEN - failing fast to protect system stability"
    );
  }

  logger.info("Fetching new Zyprus access token", {
    category: LogCategory.ZYPRUS,
    operation: "getAccessToken",
  });

  try {
    const response = await withRetry(
    async () => {
      const res = await fetch(`${config.apiUrl}/oauth/token`, {
        method: "POST",
        headers: {
          "Content-Type": "application/x-www-form-urlencoded",
          "User-Agent": "SophiaAI",
        },
        body: new URLSearchParams({
          grant_type: "client_credentials",
          client_id: config.clientId,
          client_secret: config.clientSecret,
        }),
        signal: AbortSignal.timeout(30_000),
      });

      if (!res.ok && [500, 502, 503, 504].includes(res.status)) {
        throw new Error(`Token request failed: ${res.status}`);
      }
      return res;
    },
    { maxRetries: 3, baseDelayMs: 500 },
    "getAccessToken"
  );

  if (!response.ok) {
    const errorText = await response.text();
    logger.error("Failed to get Zyprus access token", undefined, {
      category: LogCategory.ZYPRUS,
      operation: "getAccessToken",
      status: response.status,
      errorPreview: errorText.substring(0, 200),
    });
    // Record failure in circuit breaker
    recordFailure(ZYPRUS_BREAKER_CONFIG);
    // Generic error message - don't expose OAuth token flow details to users
    throw new Error(
      "Unable to connect to property system. Please try again later."
    );
  }

  const data = await response.json();

  cachedToken = {
    token: data.access_token,
    expiresAt: Date.now() + data.expires_in * 1000,
  };

  // Record success in circuit breaker
  recordSuccess(ZYPRUS_BREAKER_CONFIG);

  logger.info("Zyprus access token obtained successfully", {
    category: LogCategory.ZYPRUS,
    operation: "getAccessToken",
    expiresIn: data.expires_in,
  });
  return data.access_token;
  } catch (error) {
    // Record failure and re-throw
    recordFailure(ZYPRUS_BREAKER_CONFIG);
    throw error;
  }
}

