/**
 * Detects if user is asking for the Zyprus logo
 */
function isLogoRequest(message: string): boolean {
  const lowerMessage = message.toLowerCase();
  const logoPatterns = [
    /\blogo\b/,
    /\bzyprus logo\b/,
    /\bcompany logo\b/,
    /\bbrand logo\b/,
    /\bsend.*logo\b/,
    /\bgive.*logo\b/,
    /\bget.*logo\b/,
    /\bneed.*logo\b/,
    /\bwant.*logo\b/,
    /\bshare.*logo\b/,
  ];

  return logoPatterns.some((pattern) => pattern.test(lowerMessage));
}

/**
 * Main request processor
 * @returns tokenCount from AI response (undefined if not available)
 */
async function processRequest(
  supabase: SupabaseClient,
  userId: string,
  userMessage: string,
  phoneNumber: string,
  imageUrls: string[] = []
): Promise<number | undefined> {
  try {
    // Check for logo request first
    if (isLogoRequest(userMessage)) {
      logger.info("[Logo] Logo request detected, sending logo image", {
        category: LogCategory.GENERAL,
      });
      await sendLogoImage(supabase, phoneNumber, SOPHIA_LOGO_BASE64);
      await addMessage(userId, "user", userMessage);
      await addMessage(
        userId,
        "assistant",
        "Here's the Zyprus Property Group logo!"
      );
      return undefined;
    }

    // Add user message to database
    await addMessage(userId, "user", userMessage);

    // Run independent queries in parallel
    const [
      userContextResult,
      history,
      identifiedAgentResult,
      lastDocumentResult,
    ] = await Promise.all([
      buildUserContext(phoneNumber, userMessage).catch((error) => {
        logger.warn("Failed to build user context (non-critical)", {
          category: LogCategory.GENERAL,
          operation: "buildUserContext",
          phoneNumber,
          error: error instanceof Error ? error.message : String(error),
        });
        return null;
      }),
      getHistory(userId).catch((error) => {
        logger.warn("Failed to get chat history (non-critical)", {
          category: LogCategory.GENERAL,
          operation: "getHistory",
          userId,
          error: error instanceof Error ? error.message : String(error),
        });
        return [];
      }),
      identifyAgentByPhone(phoneNumber).catch(
        (error) => {
          logger.warn("Failed to identify agent by phone (non-critical)", {
            category: LogCategory.GENERAL,
            operation: "identifyAgentByPhone",
            phoneNumber,
            error: error instanceof Error ? error.message : String(error),
          });
          return null;
        }
      ),
      getLastDocument(userId).catch((error) => {
        logger.warn("Failed to get last document (non-critical)", {
          category: LogCategory.GENERAL,
          operation: "getLastDocument",
          userId,
          error: error instanceof Error ? error.message : String(error),
        });
        return null;
      }),
    ]);

    const userContext = userContextResult;
    let personalizationContext = "";
    if (userContext) {
      personalizationContext = formatContextForPrompt(userContext);
      const topics = extractTopics(userMessage);
      const importance = calculateImportance(userMessage, topics);
      storeMemory(userContext.profile.id, "user", userMessage, {
        importance,
        topics,
      }).catch((error) => {
        logger.warn("Failed to store user message memory (non-critical)", {
          category: LogCategory.GENERAL,
          operation: "storeMemory-user",
          userId: userContext.profile.id,
          error: error instanceof Error ? error.message : String(error),
        });
      });
    }

    const identifiedAgent = identifiedAgentResult;

    // Build system prompt
    const systemPrompt = await buildSystemPrompt(
      supabase,
      {
        userId,
        phoneNumber,
        agentName: identifiedAgent?.fullName,
        agentEmail: identifiedAgent?.communicationEmail,
        agentRegion: identifiedAgent?.region,
        agentCanUpload: identifiedAgent?.canUpload,
        personalizationContext,
        imageUrls,
        userMessage, // P1 PERFORMANCE: Used for conditional image fetching
        lastDocument: lastDocumentResult,
      },
      identifiedAgent
    );

    // Add breadcrumb before AI call
    addBreadcrumb("Calling OpenRouter", "ai", {
      model: "google/gemini-3-flash-preview",
    });

    // Call AI
    const aiResult = await chat(
      history,
      systemPrompt,
      userMessage,
      imageUrls,
      identifiedAgent,
      phoneNumber
    );

    // Add breadcrumb for tool execution if tools were used
    if (aiResult.toolsUsed && aiResult.toolsUsed.length > 0) {
      addBreadcrumb("Tools executed", "tool", {
        toolNames: aiResult.toolsUsed.join(", "),
        toolCount: aiResult.toolsUsed.length,
      });
    }

    if (!aiResult.success || !aiResult.response) {
      await sendTextMessage(
        phoneNumber,
        aiResult.response ||
          "I couldn't process your request. Please try again."
      );
      return undefined;
    }

    // Sanitize AI output before sending to WhatsApp (strip untrusted URLs, injection markers)
    const aiResponse = sanitizeAiOutput(aiResult.response);
    const tokenCount = aiResult.tokenCount;

    // Add AI response to database
    await addMessage(userId, "model", aiResponse);

    // Store AI response in memory
    if (userContext) {
      const responseTopics = extractTopics(aiResponse);
      storeMemory(userContext.profile.id, "assistant", aiResponse, {
        importance: 0.5,
        topics: responseTopics,
      }).catch((error) => {
        logger.warn("Failed to store AI response memory (non-critical)", {
          category: LogCategory.GENERAL,
          operation: "storeMemory-assistant",
          userId: userContext.profile.id,
          error: error instanceof Error ? error.message : String(error),
        });
      });
    }

    // Build updated history once (reused for both email detection and DOCX routing)
    const updatedHistory = [
      ...history,
      { role: "user", parts: [{ text: userMessage }] },
      { role: "model", parts: [{ text: aiResponse }] },
    ];

    // Check for email sending intent
    // IMPORTANT: Skip email detection if sendEmail tool was already called (prevents double emails)
    const sendEmailAlreadyCalled = aiResult.toolsUsed?.includes("sendEmail");
    if (!sendEmailAlreadyCalled) {
      const emailIntent = await detectEmailSendingIntent(
        aiResponse,
        updatedHistory,
        identifiedAgent?.communicationEmail,
        userId
      );

      if (emailIntent) {
        const emailResult = await sendEmail(emailIntent);
        if (!emailResult.success) {
          const failureNote = `\n\n(Note: There was an issue sending the email: ${emailResult.error}. Please try again or send it manually.)`;
          await sendTextMessage(phoneNumber, aiResponse + failureNote);
          return tokenCount;
        }
      }
    }

    // Check if confirmation message - always send as text
    if (isConfirmationMessage(aiResponse)) {
      logger.info(
        "[Confirmation] Detected confirmation message -> sending as TEXT",
        { category: LogCategory.GENERAL }
      );
      await sendTextMessage(phoneNumber, aiResponse);
      return tokenCount;
    }

    // Determine DOCX vs text routing
    const isInformational = isInformationalResponse(aiResponse, userMessage);

    if (isInformational) {
      const messages = parseTemplateResponse(
        aiResponse,
        identifiedAgent?.landline
      );
      for (const msg of messages) {
        await sendTextMessage(phoneNumber, msg);
      }
      return tokenCount;
    }

    // Reuse the already-constructed history (avoids redundant DB call)
    let shouldSendAsDocx =
      !isInformational && isDocxTemplate(aiResponse, updatedHistory);
    const detectedTemplateType = detectTemplateType(userMessage);

    // DEBUG: Log initial DOCX detection result
    logger.info(
      `[DOCX DEBUG] Initial check - isDocxTemplate: ${shouldSendAsDocx}, isInformational: ${isInformational}, responseLength: ${aiResponse.length}`,
      { category: LogCategory.GENERAL }
    );

    // SAFETY: Registration templates (containing "Dear XXXXXXXX" or "Subject:") are ALWAYS TEXT
    // This prevents misrouting Advanced Seller Registration as Marketing Agreement DOCX
    if (
      shouldSendAsDocx &&
      (/Dear\s+X{6,}/i.test(aiResponse) || aiResponse.includes("Subject:"))
    ) {
      logger.info(
        "[Webhook] Registration template detected in DOCX response - forcing TEXT",
        { category: LogCategory.GENERAL }
      );
      shouldSendAsDocx = false;
    }

    // Field validation checks
    const isCollecting = isCollectingInformation(aiResponse);
    if (shouldSendAsDocx && isCollecting) {
      logger.info(
        "[DOCX DEBUG] Blocked - isCollectingInformation returned true",
        { category: LogCategory.GENERAL }
      );
      shouldSendAsDocx = false;
    }

    const hasAllFields = hasAllRequiredFields(
      aiResponse,
      detectedTemplateType || undefined
    );
    if (shouldSendAsDocx && !hasAllFields) {
      logger.info(
        `[DOCX DEBUG] Blocked - hasAllRequiredFields returned false, templateType: ${detectedTemplateType}`,
        { category: LogCategory.GENERAL }
      );
      shouldSendAsDocx = false;
    }

    // Final decision log
    logger.info(
      `[DOCX DEBUG] Final decision - shouldSendAsDocx: ${shouldSendAsDocx}`,
      { category: LogCategory.GENERAL }
    );

    if (shouldSendAsDocx) {
      // Send as DOCX file
      logger.info(
        "Detected DOCX template - generating and sending as file attachment",
        { category: LogCategory.GENERAL }
      );
      trackDocumentGenerated(
        phoneNumber,
        detectedTemplateType || "unknown",
        identifiedAgent?.id
      );

      let filename = `document_${Date.now()}.docx`;
      const templateType = detectDocxTemplateType(aiResponse);
      let docxContent: Uint8Array;

      if (
        templateType.startsWith("viewing-form-") ||
        templateType === "reservation-agreement" ||
        templateType === "marketing-non-exclusive"
      ) {
        try {
          // Convert base64 viewing form logo to Uint8Array for viewing forms
          let logoData: Uint8Array | undefined;
          const isViewingForm = templateType.startsWith("viewing-form-");
          const logoBase64 = isViewingForm
            ? VIEWING_FORM_LOGO_BASE64
            : SOPHIA_LOGO_BASE64;
          if (logoBase64) {
            try {
              const binaryString = atob(logoBase64);
              const array = new Uint8Array(binaryString.length);
              for (let i = 0; i < binaryString.length; i++) {
                array[i] = binaryString.charCodeAt(i);
              }
              logoData = array;
            } catch (_e) {
              logoData = undefined;
            }
          }

          let docxDoc: Document | null = null;

          switch (templateType) {
            case "viewing-form-single": {
              const singleData = parseViewingFormSingleData(aiResponse);
              if (singleData) {
                docxDoc = createViewingFormSingle(singleData, logoData, "jpg");
              }
              break;
            }
            case "viewing-form-multiple": {
              const multipleData = parseViewingFormMultipleData(aiResponse);
              if (multipleData) {
                docxDoc = createViewingFormMultiple(
                  multipleData,
                  logoData,
                  "jpg"
                );
              }
              break;
            }
            case "viewing-form-advanced": {
              const advancedData = parseViewingFormAdvancedData(aiResponse);
              if (advancedData) {
                docxDoc = createViewingFormAdvanced(
                  advancedData,
                  logoData,
                  "jpg"
                );
              } else {
                // Fallback: try multiple parser and still use advanced template
                const multipleAsAdvanced =
                  parseViewingFormMultipleData(aiResponse);
                if (multipleAsAdvanced) {
                  docxDoc = createViewingFormAdvanced(
                    {
                      date: multipleAsAdvanced.date,
                      persons: multipleAsAdvanced.persons,
                      property: multipleAsAdvanced.property,
                    },
                    logoData,
                    "jpg"
                  );
                }
              }
              break;
            }
            case "reservation-agreement": {
              const reservationData = parseReservationAgreementData(aiResponse);
              if (reservationData) {
                docxDoc = createReservationAgreement(reservationData);
                filename = "Property_Reservation_Agreement.docx";
              }
              break;
            }
            case "marketing-non-exclusive": {
              const agentName = identifiedAgent?.fullName || "Agent";
              const marketingData = parseMarketingAgreementData(
                aiResponse,
                agentName
              );
              if (marketingData) {
                docxDoc = createMarketingAgreement(marketingData);
                filename = "Non_Exclusive_Marketing_Agreement.docx";
              }
              break;
            }
          }

          if (docxDoc) {
            const buffer = await Packer.toBuffer(docxDoc);
            docxContent = new Uint8Array(buffer);
          } else {
            docxContent = await createDocxFile(aiResponse, filename);
          }
        } catch (_error) {
          docxContent = await createDocxFile(aiResponse, filename);
        }
      } else {
        docxContent = await createDocxFile(aiResponse, filename);
      }

      const sendResult = await sendDocxFile(
        supabase,
        phoneNumber,
        docxContent,
        filename,
        1,
        userId,
        saveLastDocument
      );

      if (!sendResult.ok) {
        await sendTextMessage(phoneNumber, aiResponse);
      }
    } else {
      // Send as text message(s)
      const messageParts = parseTemplateResponse(
        aiResponse,
        identifiedAgent?.landline
      );

      for (let i = 0; i < messageParts.length; i++) {
        const part = messageParts[i];
        await sendTextMessage(phoneNumber, part);

        if (i < messageParts.length - 1) {
          await new Promise((resolve) => setTimeout(resolve, 1000));
        }
      }
    }

    return tokenCount;
  } catch (error) {
    const { correlationId } = getContext();
    captureError(error as Error, {
      phoneNumber,
      correlationId,
      channel: "whatsapp",
    });
    logger.error("Error in processRequest: " + String(error), undefined, {
      category: LogCategory.GENERAL,
    });
    trackError(phoneNumber, "PROCESS_REQUEST_ERROR", String(error));
    return undefined;
  }
}

/**
 * Main webhook handler
 */
export async function handleWebhook(
  req: Request,
  supabase: SupabaseClient
): Promise<Response> {
  // Handle GET requests (webhook verification)
  if (req.method === "GET") {
    logger.info("Webhook verification request received", {
      category: LogCategory.WEBHOOK,
    });
    return new Response("Webhook functional", { status: 200 });
  }

  // Handle POST requests
  if (req.method !== "POST") {
    return new Response("Method not allowed", { status: 405 });
  }

  // Read raw body for signature verification
  const rawBody = await req.text();

  // Verify webhook signature - FAIL-CLOSED if secret not configured
  if (!WASEND_WEBHOOK_SECRET) {
    logger.error(
      "SECURITY: WASEND_WEBHOOK_SECRET not configured - rejecting webhook",
      undefined,
      {
        category: LogCategory.WEBHOOK,
        operation: "webhook_auth",
      }
    );
    return new Response(
      "Service Unavailable - webhook authentication not configured",
      { status: 503 }
    );
  }

  const signature = extractSignatureHeader(req.headers);

  const isValidSignature = await verifyWebhookSignature(
    signature,
    rawBody,
    WASEND_WEBHOOK_SECRET
  );
  if (!isValidSignature) {
    logger.error(
      "SECURITY: Invalid webhook signature - rejecting request",
      undefined,
      {
        category: LogCategory.WEBHOOK,
        operation: "webhook_auth",
        hasSignature: !!signature,
      }
    );
    return new Response("Unauthorized", { status: 401 });
  }

  // Parse payload
  let payload;
  try {
    payload = JSON.parse(rawBody);
  } catch {
    logger.error("Invalid JSON payload", undefined, {
      category: LogCategory.GENERAL,
    });
    return new Response("Bad Request", { status: 400 });
  }

  // Validate payload structure
  if (!validateWebhookPayload(payload)) {
    logger.warn("Invalid webhook payload structure", {
      operation: "validation",
    });
    return new Response("OK", { status: 200 });
  }

  // Extract message from payload
  const extracted = await extractMessage(payload);

  if (!extracted) {
    logger.info("Could not extract valid message from payload", {
      category: LogCategory.GENERAL,
    });
    return new Response("OK", { status: 200 });
  }

  const { message, remoteJid, userMessage, imageUrls } = extracted;

  if (!remoteJid) {
    logger.error("No remoteJid found in message", undefined, {
      category: LogCategory.GENERAL,
    });
    return new Response("OK", { status: 200 });
  }

  // Format phone number
  const phoneNumber = formatPhoneNumber(remoteJid);
  if (!phoneNumber) {
    logger.error("Could not format phone number", undefined, {
      category: LogCategory.GENERAL,
    });
    return new Response("OK", { status: 200 });
  }

  // Validate phone number format
  if (!validatePhoneNumber(phoneNumber)) {
    logger.warn("Invalid phone number format", { operation: "validation" });
    return new Response("OK", { status: 200 });
  }

  // Add Sentry breadcrumb for request tracking
  const { correlationId } = getContext();
  addBreadcrumb("WhatsApp webhook received", "http", { correlationId });

  // Check rate limit
  const withinRateLimit = await checkRateLimit(supabase, remoteJid);
  if (!withinRateLimit) {
    logger.warn("Rate limit exceeded", { operation: "rate_limit" });
    return new Response("OK", { status: 200 });
  }

  // Sanitize user input
  let sanitizedMessage: string;
  try {
    sanitizedMessage = sanitizeUserInput(userMessage);
  } catch (error) {
    logger.warn("User input failed validation", {
      operation: "validation",
      errorMessage: (error as Error).message,
    });
    return new Response("OK", { status: 200 });
  }

  // Deduplication (two layers: in-memory + database)
  const messageKey = generateMessageKey(message);
  if (messageKey) {
    // Layer 1: In-memory check (catches rapid duplicates before DB round-trip)
    if (isAlreadyProcessing(messageKey)) {
      logger.info("Duplicate webhook caught by in-memory dedup", {
        operation: "deduplication",
        messageKey,
      });
      return new Response("OK", { status: 200 });
    }
    // Layer 2: Database unique constraint (catches duplicates across Edge Function instances)
    const claimed = await claimMessageForProcessing(messageKey, remoteJid);
    if (!claimed) {
      logger.info("Duplicate webhook caught by database dedup", {
        operation: "deduplication",
        messageKey,
      });
      return new Response("OK", { status: 200 });
    }
  }

  // Image-only messages: images are already stored in pending_images by extractMessage().
  // Skip AI processing - the AI will see accumulated images when the next TEXT message arrives.
  // BUT still save to chat_history so the AI has conversation continuity.
  const isImageOnlyMessage =
    sanitizedMessage === "[User sent image(s)]" ||
    sanitizedMessage === "[User sent image(s) but decryption failed]";
  if (isImageOnlyMessage) {
    logger.info("Image-only message - stored to pending, skipping AI", {
      category: LogCategory.IMAGE,
      phoneNumber,
    });
    // Save to chat_history so AI context isn't lost (fixes zero-history issue for image-heavy users)
    await addMessage(remoteJid, "user", sanitizedMessage).catch((err) =>
      logger.warn("Failed to save image-only message to chat_history", {
        category: LogCategory.IMAGE,
        error: String(err),
      })
    );
    return new Response("OK", { status: 200 });
  }

  // Track inbound message (fire-and-forget)
  trackMessageReceived(phoneNumber, undefined, {
    hasImages: imageUrls.length > 0,
    imageCount: imageUrls.length,
    messageLength: sanitizedMessage.length,
  });

  // Start response timer
  const requestTimer = createTimer();

  // Process the request
  try {
    const tokenCount = await processRequest(
      supabase,
      remoteJid,
      sanitizedMessage,
      phoneNumber,
      imageUrls
    );
    // Track successful response with token usage
    trackMessageSent(phoneNumber, requestTimer.end(), tokenCount);
  } catch (err) {
    captureError(err as Error, {
      phoneNumber,
      correlationId,
      channel: "whatsapp",
    });
    logger.error("processRequest failed: " + String(err), undefined, {
      category: LogCategory.GENERAL,
    });
    trackError(phoneNumber, "PROCESS_REQUEST_FAILED", String(err));
  }

  return new Response("OK", { status: 200 });
}

/**
 * Admin API Handlers
 *
 * Authenticated endpoints for prompt management, cache control, and migrations.
 *
 * Endpoints:
 * - POST /admin/prompts/invalidate - Clear prompt cache
 * - POST /admin/prompts/rollback - Rollback a prompt to previous version
 * - GET /admin/prompts/history?key=X - Get version history
 * - GET /admin/cache/status - Cache diagnostic info
 * - POST /admin/migrate-templates - One-time template migration
 * - POST /admin/generate-description - Generate AI property description (for Zyprus)
 */

import type { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.0";
import {
  generateDescription,
  type PropertyDetails,
} from "../services/description-generator.ts";
import {
  getCacheStatus,
  getPromptVersionHistory,
  invalidateCache,
  rollbackPrompt,
} from "../services/prompt-loader.ts";
import { LogCategory, logger } from "../utils/logger.ts";
import { constantTimeCompare } from "../utils/webhook-auth.ts";

const ADMIN_SECRET = Deno.env.get("SOPHIA_ADMIN_SECRET");

/**
 * Handle admin API requests
 * Requires SOPHIA_ADMIN_SECRET header for authentication
 */
export async function handleAdminRequest(
  req: Request,
  url: URL,
  supabase: ReturnType<typeof createClient>
): Promise<Response> {
  // Authenticate admin request
  const providedSecret = req.headers.get("x-admin-secret");

  if (!ADMIN_SECRET) {
    logger.warn(
      "Admin endpoint accessed but SOPHIA_ADMIN_SECRET not configured",
      {
        category: LogCategory.GENERAL,
        endpoint: url.pathname,
      }
    );
    return new Response(
      JSON.stringify({
        error: "Admin endpoints not configured",
      }),
      {
        status: 503,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  // Use constant-time comparison to prevent timing attacks
  if (!constantTimeCompare(providedSecret || "", ADMIN_SECRET)) {
    logger.warn("Admin endpoint unauthorized access attempt", {
      category: LogCategory.GENERAL,
      endpoint: url.pathname,
    });
    return new Response(
      JSON.stringify({
        error: "Unauthorized",
      }),
      {
        status: 401,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  // Route to specific admin endpoint
  if (
    url.pathname === "/sophia-bot/admin/prompts/invalidate" &&
    req.method === "POST"
  ) {
    return handleCacheInvalidate();
  }

  if (
    url.pathname === "/sophia-bot/admin/prompts/rollback" &&
    req.method === "POST"
  ) {
    return handlePromptRollback(req, supabase);
  }

  if (
    url.pathname === "/sophia-bot/admin/prompts/history" &&
    req.method === "GET"
  ) {
    return handlePromptHistory(url, supabase);
  }

  if (
    url.pathname === "/sophia-bot/admin/cache/status" &&
    req.method === "GET"
  ) {
    return handleCacheStatus();
  }

  if (
    url.pathname === "/sophia-bot/admin/migrate-templates" &&
    req.method === "POST"
  ) {
    return handleTemplateMigration(supabase);
  }

  if (
    url.pathname === "/sophia-bot/admin/prompts/sync" &&
    req.method === "POST"
  ) {
    return handlePromptSync(req, supabase);
  }

  // Generate property description endpoint (for Zyprus CMS)
  if (
    url.pathname === "/sophia-bot/admin/generate-description" &&
    req.method === "POST"
  ) {
    return handleGenerateDescription(req);
  }

  // Unknown admin endpoint
  return new Response(
    JSON.stringify({
      error: "Not Found",
      availableEndpoints: [
        "POST /sophia-bot/admin/prompts/invalidate",
        "POST /sophia-bot/admin/prompts/rollback",
        "POST /sophia-bot/admin/prompts/sync",
        "GET /sophia-bot/admin/prompts/history?key=X",
        "GET /sophia-bot/admin/cache/status",
        "POST /sophia-bot/admin/migrate-templates",
        "POST /sophia-bot/admin/generate-description - Generate AI property description (for Zyprus)",
      ],
    }),
    {
      status: 404,
      headers: { "Content-Type": "application/json" },
    }
  );
}

/**
 * POST /admin/prompts/invalidate
 * Clears the prompt cache, forcing reload on next request
 */
function handleCacheInvalidate(): Response {
  invalidateCache();

  logger.info("Admin: Cache invalidated via API", {
    category: LogCategory.GENERAL,
  });

  return new Response(
    JSON.stringify({
      success: true,
      message:
        "Prompt cache invalidated. Next request will reload from database.",
      timestamp: new Date().toISOString(),
    }),
    {
      status: 200,
      headers: { "Content-Type": "application/json" },
    }
  );
}

/**
 * GET /admin/cache/status
 * Returns cache diagnostic information
 */
function handleCacheStatus(): Response {
  const status = getCacheStatus();

  logger.debug("Admin: Cache status requested", {
    category: LogCategory.GENERAL,
    ...status,
  });

  return new Response(
    JSON.stringify({
      cache: {
        isCached: status.isCached,
        ageMs: status.age,
        ageFormatted:
          status.age > 0 ? `${Math.round(status.age / 1000)}s` : "N/A",
        ttlMs: status.ttl,
        ttlFormatted:
          status.ttl > 0 ? `${Math.round(status.ttl / 60_000)}min` : "disabled",
        sectionCount: status.sectionCount,
        version: status.version,
        isExpired: status.ttl > 0 ? status.age > status.ttl : false,
      },
      timestamp: new Date().toISOString(),
    }),
    {
      status: 200,
      headers: { "Content-Type": "application/json" },
    }
  );
}

/**
 * POST /admin/prompts/rollback
 * Rollback a prompt to a previous version
 */
async function handlePromptRollback(
  req: Request,
  supabase: ReturnType<typeof createClient>
): Promise<Response> {
  try {
    const body = await req.json();
    const { key, version, reason } = body;

    if (!key || typeof key !== "string") {
      return new Response(
        JSON.stringify({ success: false, error: "Missing or invalid 'key'" }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    if (!version || typeof version !== "number" || version < 1) {
      return new Response(
        JSON.stringify({
          success: false,
          error: "Missing or invalid 'version' (must be positive integer)",
        }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    if (!reason || typeof reason !== "string") {
      return new Response(
        JSON.stringify({
          success: false,
          error: "Missing or invalid 'reason'",
        }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    logger.info("Admin: Rollback requested", {
      category: LogCategory.CACHE,
      promptKey: key,
      targetVersion: version,
      reason,
    });

    const result = await rollbackPrompt(supabase, key, version, reason);

    return new Response(JSON.stringify(result), {
      status: result.success ? 200 : 400,
      headers: { "Content-Type": "application/json" },
    });
  } catch (err) {
    logger.error("Admin: Rollback endpoint error", err as Error, {
      category: LogCategory.CACHE,
    });
    return new Response(
      JSON.stringify({ success: false, error: "Invalid request body" }),
      { status: 400, headers: { "Content-Type": "application/json" } }
    );
  }
}

/**
 * GET /admin/prompts/history?key=identity
 * Get version history for a prompt
 */
async function handlePromptHistory(
  url: URL,
  supabase: ReturnType<typeof createClient>
): Promise<Response> {
  const key = url.searchParams.get("key");

  if (!key) {
    return new Response(
      JSON.stringify({
        success: false,
        error: "Missing 'key' query parameter",
      }),
      { status: 400, headers: { "Content-Type": "application/json" } }
    );
  }

  const history = await getPromptVersionHistory(supabase, key);

  logger.debug("Admin: Version history requested", {
    category: LogCategory.CACHE,
    promptKey: key,
    versionCount: history.length,
  });

  return new Response(JSON.stringify({ key, history }), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
}

/**
 * POST /admin/prompts/sync
 * Sync file-based prompt content to DB as new versions
 * Body: { "keys": ["document_routing", "response_format"] } or { "keys": "all" }
 */
async function handlePromptSync(
  req: Request,
  supabase: ReturnType<typeof createClient>
): Promise<Response> {
  try {
    const body = await req.json();

    // Import all fallback prompts
    const { DOCUMENT_ROUTING } = await import("../prompts/behaviors/document-routing.ts");
    const { PROPERTY_UPLOAD } = await import("../prompts/behaviors/property-upload.ts");
    const { RESERVATION_LOAN_VAT_REQUIRED } = await import("../prompts/behaviors/reservation-loan-vat.ts");
    const { RESPONSE_FORMAT } = await import("../prompts/behaviors/response-format.ts");
    const { IDENTITY } = await import("../prompts/core/identity.ts");
    const { SAFETY_RULES } = await import("../prompts/core/safety-rules.ts");
    const { CALCULATOR_CAPABILITIES } = await import("../prompts/knowledge/calculators.ts");
    const { CYPRUS_KNOWLEDGE } = await import("../prompts/knowledge/cyprus-real-estate.ts");
    const { TEMPLATES } = await import("../prompts/templates/content.ts");

    const filePrompts: Record<string, string> = {
      identity: IDENTITY,
      safety_rules: SAFETY_RULES,
      reservation_loan_vat_required: RESERVATION_LOAN_VAT_REQUIRED,
      document_routing: DOCUMENT_ROUTING,
      property_upload: PROPERTY_UPLOAD,
      response_format: RESPONSE_FORMAT,
      calculators: CALCULATOR_CAPABILITIES,
      cyprus_knowledge: CYPRUS_KNOWLEDGE,
      templates: TEMPLATES,
    };

    // Determine which keys to sync
    let keysToSync: string[];
    if (body.keys === "all") {
      keysToSync = Object.keys(filePrompts);
    } else if (Array.isArray(body.keys)) {
      keysToSync = body.keys.filter((k: string) => k in filePrompts);
    } else {
      return new Response(
        JSON.stringify({ success: false, error: 'Body must have "keys": ["key1", "key2"] or "keys": "all"' }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    if (keysToSync.length === 0) {
      return new Response(
        JSON.stringify({ success: false, error: "No valid keys to sync", validKeys: Object.keys(filePrompts) }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    const results: Array<{ key: string; status: string; newVersion?: number }> = [];

    for (const key of keysToSync) {
      const content = filePrompts[key];

      // Get current version
      const { data: current } = await supabase
        .from("sophia_prompts")
        .select("version, priority, category, description, content")
        .eq("key", key)
        .eq("is_current", true)
        .maybeSingle();

      // Skip if content is identical
      if (current && current.content === content) {
        results.push({ key, status: "unchanged" });
        continue;
      }

      if (current) {
        // Mark old version as not current
        await supabase
          .from("sophia_prompts")
          .update({ is_current: false, replaced_at: new Date().toISOString() })
          .eq("key", key)
          .eq("version", current.version);

        // Insert new version
        const newVersion = current.version + 1;
        const { error: insertError } = await supabase
          .from("sophia_prompts")
          .insert({
            key,
            content,
            category: current.category,
            description: current.description,
            priority: current.priority,
            is_active: true,
            is_current: true,
            version: newVersion,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
            updated_by: "file-sync",
          });

        if (insertError) {
          // Restore old version
          await supabase
            .from("sophia_prompts")
            .update({ is_current: true, replaced_at: null })
            .eq("key", key)
            .eq("version", current.version);
          results.push({ key, status: `error: ${insertError.message}` });
        } else {
          results.push({ key, status: "synced", newVersion });
        }
      } else {
        results.push({ key, status: "not_in_db (skipped)" });
      }
    }

    // Invalidate cache
    invalidateCache("file-sync");

    logger.info("Admin: Prompt sync completed", {
      category: LogCategory.CACHE,
      results,
    });

    return new Response(
      JSON.stringify({ success: true, results, cacheInvalidated: true }),
      { status: 200, headers: { "Content-Type": "application/json" } }
    );
  } catch (err) {
    return new Response(
      JSON.stringify({ success: false, error: String(err) }),
      { status: 500, headers: { "Content-Type": "application/json" } }
    );
  }
}

/**
 * POST /admin/migrate-templates
 * One-time migration: Insert templates content into sophia_prompts table
 */
async function handleTemplateMigration(
  supabase: ReturnType<typeof createClient>
): Promise<Response> {
  try {
    // Check if templates key already exists
    const { data: existing, error: checkError } = await supabase
      .from("sophia_prompts")
      .select("key, priority, is_active")
      .eq("key", "templates")
      .maybeSingle();

    if (checkError) {
      logger.error("Admin: Template migration check failed", undefined, {
        category: LogCategory.GENERAL,
        errorMessage: checkError.message,
      });

      return new Response(
        JSON.stringify({
          success: false,
          error: "Database check failed",
          details: checkError.message,
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    if (existing) {
      logger.info("Admin: Templates already migrated", {
        category: LogCategory.GENERAL,
        existing,
      });

      return new Response(
        JSON.stringify({
          success: true,
          alreadyExists: true,
          message: "Templates key already exists in database",
          existing: {
            key: existing.key,
            priority: existing.priority,
            active: existing.is_active,
          },
        }),
        {
          status: 200,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    // Import templates content from prompts/templates/content.ts
    const { TEMPLATES } = await import("../prompts/templates/content.ts");

    logger.info("Admin: Inserting templates into database", {
      category: LogCategory.GENERAL,
      contentLength: TEMPLATES.length,
    });

    // Insert templates
    const { data, error: insertError } = await supabase
      .from("sophia_prompts")
      .insert({
        key: "templates",
        content: TEMPLATES,
        category: "templates",
        description:
          "All 43 document templates for Cyprus real estate communications",
        priority: 80,
        is_active: true,
        updated_by: "migration-08-02",
        version: 1,
        is_current: true,
      })
      .select("id, key, priority, is_active")
      .single();

    if (insertError) {
      logger.error("Admin: Template migration insert failed", undefined, {
        category: LogCategory.GENERAL,
        errorMessage: insertError.message,
      });

      return new Response(
        JSON.stringify({
          success: false,
          error: "Database insert failed",
          details: insertError.message,
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    logger.info("Admin: Templates migrated successfully", {
      category: LogCategory.GENERAL,
      id: data.id,
      key: data.key,
      priority: data.priority,
      contentLength: TEMPLATES.length,
    });

    // Invalidate cache to pick up new templates
    invalidateCache();

    return new Response(
      JSON.stringify({
        success: true,
        message: "Templates migrated successfully to database",
        data: {
          id: data.id,
          key: data.key,
          priority: data.priority,
          active: data.is_active,
          contentLength: TEMPLATES.length,
        },
        cacheInvalidated: true,
      }),
      {
        status: 200,
        headers: { "Content-Type": "application/json" },
      }
    );
  } catch (err) {
    logger.error(
      "Admin: Template migration unexpected error",
      err instanceof Error ? err : undefined,
      {
        category: LogCategory.GENERAL,
        errorDetails: err instanceof Error ? err.message : String(err),
      }
    );

    return new Response(
      JSON.stringify({
        success: false,
        error: "Unexpected error during migration",
        details: err instanceof Error ? err.message : String(err),
      }),
      {
        status: 500,
        headers: { "Content-Type": "application/json" },
      }
    );
  }
}

/**
 * POST /admin/generate-description
 * Generate AI property description for Zyprus CMS
 *
 * This endpoint is called by the Zyprus backend "Generate Description" button.
 * It uses Sophia AI's description generator to create professional property descriptions.
 *
 * Request body schema:
 * {
 *   "type": string,           // Property type (e.g., "apartment", "villa", "detached house")
 *   "listingType": "sale" | "rent",
 *   "bedrooms": number,
 *   "bathrooms": number,
 *   "location": string,       // Area name (e.g., "Tala", "Kato Paphos", "Limassol")
 *   "coveredArea": number,    // in square meters
 *   "plotSize"?: number,      // Optional: Plot size in sqm
 *   "coveredVeranda"?: number,
 *   "uncoveredVeranda"?: number,
 *   "features"?: string[],    // Optional: Array of feature strings
 *   "price": number,
 *   "yearBuilt"?: number,
 *   "condition"?: string,
 *   "orientation"?: string,
 *   "parking"?: string,
 *   "storage"?: boolean,
 *   "airConditioning"?: boolean,
 *   "centralHeating"?: boolean,
 *   "pool"?: boolean,
 *   "garden"?: boolean,
 *   "seaView"?: boolean,
 *   "mountainView"?: boolean,
 *   "titleDeedStatus"?: string,
 *   "areaDescription"?: string // Optional: User-provided custom area description
 * }
 *
 * Response:
 * {
 *   "success": true,
 *   "description": string,   // Generated description text
 *   "title"?: string         // Generated short title
 * }
 */
async function handleGenerateDescription(req: Request): Promise<Response> {
  try {
    const body = await req.json();

    // Validate required fields
    const requiredFields = [
      "type",
      "listingType",
      "bedrooms",
      "bathrooms",
      "location",
      "coveredArea",
      "price",
    ];
    const missingFields = requiredFields.filter(
      (field) => body[field] === undefined
    );

    if (missingFields.length > 0) {
      logger.warn("Admin: Generate description missing required fields", {
        category: LogCategory.GENERAL,
        missingFields,
      });

      return new Response(
        JSON.stringify({
          success: false,
          error: "Missing required fields",
          missingFields,
        }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    // Validate listingType
    if (body.listingType !== "sale" && body.listingType !== "rent") {
      return new Response(
        JSON.stringify({
          success: false,
          error: "Invalid listingType. Must be 'sale' or 'rent'",
        }),
        { status: 400, headers: { "Content-Type": "application/json" } }
      );
    }

    // Build property details object
    const propertyDetails: PropertyDetails = {
      type: body.type,
      listingType: body.listingType,
      bedrooms: Number(body.bedrooms),
      bathrooms: Number(body.bathrooms),
      location: body.location,
      coveredArea: Number(body.coveredArea),
      price: Number(body.price),
      plotSize: body.plotSize ? Number(body.plotSize) : undefined,
      coveredVeranda: body.coveredVeranda
        ? Number(body.coveredVeranda)
        : undefined,
      uncoveredVeranda: body.uncoveredVeranda
        ? Number(body.uncoveredVeranda)
        : undefined,
      features: Array.isArray(body.features) ? body.features : undefined,
      yearBuilt: body.yearBuilt ? Number(body.yearBuilt) : undefined,
      condition: body.condition,
      orientation: body.orientation,
      parking: body.parking,
      storage: body.storage,
      airConditioning: body.airConditioning,
      centralHeating: body.centralHeating,
      pool: body.pool,
      garden: body.garden,
      seaView: body.seaView,
      mountainView: body.mountainView,
      titleDeedStatus: body.titleDeedStatus,
      areaDescription: body.areaDescription,
    };

    logger.info("Admin: Generate description requested", {
      category: LogCategory.GENERAL,
      propertyType: propertyDetails.type,
      location: propertyDetails.location,
      bedrooms: propertyDetails.bedrooms,
    });

    // Generate the description using Sophia AI's description generator
    const description = generateDescription(propertyDetails);

    logger.info("Admin: Description generated successfully", {
      category: LogCategory.GENERAL,
      descriptionLength: description.length,
    });

    return new Response(
      JSON.stringify({
        success: true,
        description,
        title: `${propertyDetails.bedrooms === 0 ? "Studio" : propertyDetails.bedrooms === 1 ? "1 Bed" : `${propertyDetails.bedrooms} Bed`} ${propertyDetails.type.charAt(0).toUpperCase() + propertyDetails.type.slice(1)} in ${propertyDetails.location.charAt(0).toUpperCase() + propertyDetails.location.slice(1)}`,
      }),
      { status: 200, headers: { "Content-Type": "application/json" } }
    );
  } catch (err) {
    logger.error(
      "Admin: Generate description endpoint error",
      err instanceof Error ? err : undefined,
      {
        category: LogCategory.GENERAL,
        errorDetails: err instanceof Error ? err.message : String(err),
      }
    );

    return new Response(
      JSON.stringify({
        success: false,
        error: "Failed to generate description",
        details: err instanceof Error ? err.message : String(err),
      }),
      { status: 500, headers: { "Content-Type": "application/json" } }
    );
  }
}

/**
 * Health Check Handler
 *
 * Returns service status and dependency availability.
 * Endpoint: GET /health
 */

import type { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.0";
import { LogCategory, logger } from "../utils/logger.ts";

interface HealthCheck {
  status: "healthy" | "unhealthy" | "degraded";
  latencyMs?: number;
  error?: string;
}

/**
 * Health check endpoint - returns service status and dependency availability
 */
export async function handleHealthCheck(
  supabase: ReturnType<typeof createClient>
): Promise<Response> {
  const startTime = Date.now();

  logger.info("Health check requested", {
    category: LogCategory.WEBHOOK,
    operation: "healthCheck",
  });

  const checks: Record<string, HealthCheck> = {};

  // Check OpenRouter (AI provider)
  try {
    const orStart = Date.now();
    const orResponse = await fetch("https://openrouter.ai/api/v1/models", {
      method: "HEAD",
      signal: AbortSignal.timeout(5000),
    });
    checks.openrouter = {
      status: orResponse.ok ? "healthy" : "degraded",
      latencyMs: Date.now() - orStart,
    };
  } catch (err) {
    checks.openrouter = {
      status: "unhealthy",
      error: err instanceof Error ? err.message : "Connection failed",
    };
  }

  // Check Zyprus API
  // Note: /jsonapi returns 403 without auth, but that means the server is responding
  const zyprusUrl = Deno.env.get("ZYPRUS_API_URL");
  if (zyprusUrl) {
    try {
      const zStart = Date.now();
      const zResponse = await fetch(`${zyprusUrl}/jsonapi`, {
        method: "HEAD",
        headers: { "User-Agent": "SophiaAI-HealthCheck" },
        signal: AbortSignal.timeout(5000),
      });
      // 401/403 means the server is responding but we need auth - that's healthy
      // Only mark degraded if 5xx or connection issues
      const isHealthy =
        zResponse.ok || zResponse.status === 401 || zResponse.status === 403;
      checks.zyprus = {
        status: isHealthy
          ? "healthy"
          : zResponse.status >= 500
            ? "unhealthy"
            : "degraded",
        latencyMs: Date.now() - zStart,
      };
    } catch (err) {
      checks.zyprus = {
        status: "unhealthy",
        error: err instanceof Error ? err.message : "Connection failed",
      };
    }
  } else {
    checks.zyprus = {
      status: "unhealthy",
      error: "ZYPRUS_API_URL not configured",
    };
  }

  // Check Supabase (database)
  try {
    const dbStart = Date.now();
    const { error } = await supabase.from("chat_history").select("id").limit(1);
    checks.supabase = {
      status: error ? "degraded" : "healthy",
      latencyMs: Date.now() - dbStart,
      error: error?.message,
    };
  } catch (err) {
    checks.supabase = {
      status: "unhealthy",
      error: err instanceof Error ? err.message : "Connection failed",
    };
  }

  // Check WaSender API
  // WaSender doesn't have a /health endpoint, so we check the main app URL
  const wasendKey = Deno.env.get("WASEND_API_KEY");
  if (wasendKey) {
    try {
      const wStart = Date.now();
      // Check the main WaSender app URL instead of non-existent health endpoint
      const wResponse = await fetch("https://app.wasenderapi.com/", {
        method: "HEAD",
        signal: AbortSignal.timeout(5000),
      });
      // 200 means site is up, which is healthy enough for us
      checks.wasender = {
        status: wResponse.ok
          ? "healthy"
          : wResponse.status >= 500
            ? "unhealthy"
            : "degraded",
        latencyMs: Date.now() - wStart,
      };
    } catch (err) {
      checks.wasender = {
        status: "unhealthy",
        error: err instanceof Error ? err.message : "Connection failed",
      };
    }
  } else {
    checks.wasender = {
      status: "unhealthy",
      error: "WASEND_API_KEY not configured",
    };
  }

  // Determine overall status
  const statuses = Object.values(checks).map((c) => c.status);
  const overallStatus = statuses.every((s) => s === "healthy")
    ? "healthy"
    : statuses.some((s) => s === "unhealthy")
      ? "unhealthy"
      : "degraded";

  // Log warnings for unhealthy dependencies
  for (const [name, check] of Object.entries(checks)) {
    if (check.status === "unhealthy") {
      logger.warn(`Dependency unhealthy: ${name}`, {
        category: LogCategory.WEBHOOK,
        operation: "healthCheck",
        dependency: name,
        error: check.error,
      });
    }
  }

  logger.info("Health check completed", {
    category: LogCategory.WEBHOOK,
    operation: "healthCheck",
    status: overallStatus,
    totalLatencyMs: Date.now() - startTime,
    unhealthyDeps: Object.entries(checks)
      .filter(([_, v]) => v.status === "unhealthy")
      .map(([k, _]) => k),
  });

  const response = {
    service: "sophia-bot",
    version: "1.1.4",
    status: overallStatus,
    timestamp: new Date().toISOString(),
    totalLatencyMs: Date.now() - startTime,
    dependencies: checks,
    config: {
      openrouterConfigured: !!Deno.env.get("OPENROUTER_API_KEY"),
      wasenderConfigured: !!Deno.env.get("WASEND_API_KEY"),
      resendConfigured: !!Deno.env.get("RESEND_API_KEY"),
      adminSecretConfigured: !!Deno.env.get("SOPHIA_ADMIN_SECRET"),
    },
  };

  const httpStatus =
    overallStatus === "healthy"
      ? 200
      : overallStatus === "degraded"
        ? 200
        : 503;

  return new Response(JSON.stringify(response, null, 2), {
    status: httpStatus,
    headers: { "Content-Type": "application/json" },
  });
}

