    CALCULATOR_CAPABILITIES,

    // 7. Cyprus knowledge base
    CYPRUS_KNOWLEDGE,

    // 8. Templates (injected from legacy prompts.ts)
    templates,
  ];

  return sections.filter(Boolean).join("\n\n---\n\n");
