/**
 * Get 2 closing sentences about the property opportunity
 */
function getClosingSentences(details: PropertyDetails): string[] {
  const propertyType = details.type.toLowerCase();

  if (details.listingType === "rent") {
    return [
      `This ${propertyType} is an excellent rental opportunity!`,
      "Ideal for families, couples or professionals",
    ];
  }

  // For sale properties
  const sentences: string[] = [];

  if (details.plotSize && details.plotSize >= 500) {
    sentences.push(
      `This spacious ${propertyType} is a compelling investment opportunity!`
    );
  } else {
    sentences.push(
      `This ${propertyType} represents an excellent investment opportunity!`
    );
  }

  // Location-aware closing — Nicosia/Famagusta are NOT holiday destinations
  const locationLower = details.location.toLowerCase();
  const isInlandLocation =
    locationLower.includes("nicosia") ||
    locationLower.includes("strovolos") ||
    locationLower.includes("lakatamia") ||
    locationLower.includes("engomi") ||
    locationLower.includes("aglantzia") ||
    locationLower.includes("latsia") ||
    locationLower.includes("famagusta") ||
    locationLower.includes("paralimni");

  if (propertyType.includes("building")) {
    sentences.push("Ideal as an investment property or for rental income");
  } else if (
    propertyType.includes("villa") ||
    propertyType.includes("house") ||
    propertyType.includes("bungalow")
  ) {
    if (isInlandLocation) {
      sentences.push(
        "Suitable for a family for permanent living or as a rental property"
      );
    } else {
      sentences.push(
        "Suitable for a family for permanent living or as a holiday home"
      );
    }
  } else if (
    propertyType.includes("apartment") ||
    propertyType.includes("flat") ||
    propertyType.includes("penthouse")
  ) {
    if (isInlandLocation) {
      sentences.push(
        "Ideal for permanent residence, student accommodation or as a rental property"
      );
    } else {
      sentences.push(
        "Ideal for permanent residence, a holiday home or as a rental property"
      );
    }
  } else {
    sentences.push("Ideal for permanent living or as an investment property");
  }

  return sentences;
}

/**
 * Generate a short summary for the listing title
 * If covered veranda exists, includes both covered area and covered veranda separately
 */
export function generateTitle(details: PropertyDetails): string {
  const bedroomText =
    details.bedrooms === 0
      ? "Studio"
      : details.bedrooms === 1
        ? "1 Bed"
        : `${details.bedrooms} Bed`;
  const propertyType = capitalize(details.type);
  const location = capitalizeLocation(details.location);

  // If there's a COVERED veranda, show both covered area and covered veranda separately
  const hasCoveredVeranda =
    details.coveredVeranda && details.coveredVeranda > 0;

  const noVatSuffix =
    details.priceModifier === "no_vat" && details.listingType === "sale"
      ? " - No VAT"
      : "";

  if (hasCoveredVeranda) {
    return `${bedroomText} ${propertyType} (${formatArea(details.coveredArea)}m² + ${formatArea(details.coveredVeranda!)}m² covered veranda) in ${location}${noVatSuffix}`;
  }

  return `${bedroomText} ${propertyType} (${formatArea(details.coveredArea)}m²) in ${location}${noVatSuffix}`;
}

/**
 * Land Description Generator
 * Creates professional marketing descriptions for land/plot listings
 */
export interface LandDetails {
  landType: string;
  listingType: "sale" | "rent";
  landSize: number;
  location: string;
  titleDeedStatus?: string;
  buildingDensity?: number;
  siteCoverage?: number;
  maxFloors?: number;
  maxHeight?: number;
  infrastructure?: string[];
  views?: string[];
  price: number;
  areaDescription?: string;
  priceModifier?: string;
}

/**
 * Generate a professional land description
 */
export function generateLandDescription(details: LandDetails): string {
  const lines: string[] = [];

  // Opening paragraph: land type + size + location
  const landTypeCapitalized = capitalize(details.landType);
  const location = capitalizeLocation(details.location);
  const formattedSize = formatArea(details.landSize);

  if (details.listingType === "sale") {
    lines.push(
      `${landTypeCapitalized} for sale in ${location}, offering ${formattedSize}m² of land.`
    );
  } else {
    lines.push(
      `${landTypeCapitalized} for rent in ${location}, offering ${formattedSize}m² of land.`
    );
  }

  // Building regulations paragraph (if any provided)
  if (
    details.buildingDensity ||
    details.siteCoverage ||
    details.maxFloors ||
    details.maxHeight
  ) {
    const regs: string[] = [];
    if (details.buildingDensity !== undefined) {
      regs.push(`${details.buildingDensity}% building density`);
    }
    if (details.siteCoverage !== undefined) {
      regs.push(`${details.siteCoverage}% site coverage`);
    }
    if (details.maxFloors !== undefined) {
      regs.push(`up to ${details.maxFloors} floors`);
    }
    if (details.maxHeight !== undefined) {
      regs.push(`maximum height of ${details.maxHeight}m`);
    }

    if (regs.length > 0) {
      lines.push("");
      lines.push(`Building regulations allow ${regs.join(", ")}.`);
    }
  }

  // Infrastructure paragraph (if provided)
  if (details.infrastructure && details.infrastructure.length > 0) {
    const infraList = details.infrastructure.map((i) => {
      // Convert "road_access" → "road access", "electricity" → "electricity"
      return i.replace(/_/g, " ");
    });

    lines.push("");
    if (infraList.length === 1) {
      lines.push(`The plot has ${infraList[0]} available.`);
    } else if (infraList.length === 2) {
      lines.push(`The plot has ${infraList[0]} and ${infraList[1]} available.`);
    } else {
      const lastInfra = infraList.pop();
      lines.push(
        `The plot has ${infraList.join(", ")} and ${lastInfra} available.`
      );
    }
  }

  // Views/location paragraph (if views or area description provided)
  if (details.views && details.views.length > 0) {
    const viewsList = details.views
      .filter((v) => v.toLowerCase().includes("view"))
      .map((v) => v.toLowerCase());

    if (viewsList.length > 0) {
      lines.push("");
      if (viewsList.length === 1) {
        lines.push(`The land offers ${viewsList[0]}.`);
      } else if (viewsList.length === 2) {
        lines.push(`The land offers ${viewsList[0]} and ${viewsList[1]}.`);
      } else {
        const lastView = viewsList.pop();
        lines.push(`The land offers ${viewsList.join(", ")} and ${lastView}.`);
      }
    }
  }

  // Area description (if provided by agent)
  if (details.areaDescription) {
    lines.push("");
    lines.push(details.areaDescription);
  } else {
    // Generic area info from LOCATION_DESCRIPTIONS if available
    const locationLower = details.location.toLowerCase();
    const areaKey = Object.keys(LOCATION_DESCRIPTIONS).find((key) =>
      locationLower.includes(key)
    );
    if (areaKey) {
      lines.push("");
      lines.push(LOCATION_DESCRIPTIONS[areaKey]);
    }
  }

  // Title deed paragraph
  if (details.titleDeedStatus) {
    lines.push("");
    switch (details.titleDeedStatus) {
      case "separate":
        lines.push("The land comes with separate title deeds.");
        break;
      case "final_approval":
        lines.push("The title deeds are at final approval stage.");
        break;
      case "in_process":
        lines.push("Title deeds are currently in the process of being issued.");
        break;
      case "pending":
        lines.push(
          "Title deeds have been applied for and are pending issuance."
        );
        break;
      case "share_of_land":
        lines.push("The land has shared ownership with title deeds.");
        break;
      case "permits_only":
        lines.push(
          "Planning and building permits are available (title deeds not yet issued)."
        );
        break;
    }
  }

  // Price paragraph
  lines.push("");
  const formattedPrice = `€${details.price.toLocaleString()}`;

  if (details.priceModifier === "plus_vat") {
    lines.push(`The asking price is ${formattedPrice} plus VAT.`);
  } else if (details.priceModifier === "vat_included") {
    lines.push(`The asking price is ${formattedPrice} (VAT included).`);
  } else {
    lines.push(`The asking price is ${formattedPrice}.`);
  }

  // Closing call to action
  lines.push("");
  lines.push(
    "For more information or to arrange a viewing, please contact us today."
  );

  return lines.join("\n");
}

/**
 * Image Handler Service
 * Processes, validates, and orders property images for upload
 */

import { LogCategory, logger } from "../utils/logger.ts";
import { validateImageUrl } from "../utils/url-validator.ts";

export interface ProcessedImage {
  url: string;
  order: number;
  needsCropping: boolean;
  privacyIssues: string[];
  classification: ImageClassification;
}

export type ImageClassification =
  | "exterior_front"
  | "exterior_other"
  | "pool"
  | "garden"
  | "living_room"
  | "kitchen"
  | "bedroom"
  | "bathroom"
  | "other"
  | "unknown";

// Image order priority (lower = first)
const IMAGE_ORDER: Record<ImageClassification, number> = {
  exterior_front: 1,
  exterior_other: 2,
  pool: 3,
  garden: 4,
  living_room: 5,
  kitchen: 6,
  bedroom: 7,
  bathroom: 8,
  other: 9,
  unknown: 10,
};

// Domains that likely have watermarks we should warn about
const WATERMARK_DOMAINS = [
  "bazaraki.com",
  "bazaraki.cy",
  "facebook.com",
  "fb.com",
  "rightmove.co.uk",
  "zoopla.co.uk",
];

/**
 * Check if URL is from a domain known to have watermarks
 */
function hasKnownWatermark(url: string): boolean {
  try {
    const urlObj = new URL(url);
    return WATERMARK_DOMAINS.some(
      (domain) =>
        urlObj.hostname.includes(domain) ||
        url.toLowerCase().includes(domain.replace(".", ""))
    );
  } catch {
    return false;
  }
}

/**
 * Detect privacy issues in image URL or metadata
 * (This is a simple check - in production you might use AI vision)
 */
function detectPrivacyIssues(url: string): string[] {
  const issues: string[] = [];

  // Check for street view or location metadata
  if (url.toLowerCase().includes("streetview")) {
    issues.push("May contain Google Street View content");
  }

  // Check for personal information in URL
  if (
    url.toLowerCase().includes("personal") ||
    url.toLowerCase().includes("private")
  ) {
    issues.push("URL suggests private/personal content");
  }

  return issues;
}

/**
 * Simple image classification based on filename
 * In production, you'd use AI vision for this
 */
function classifyImage(url: string): ImageClassification {
  const filename = url.toLowerCase();

  // Exterior
  if (
    filename.includes("front") ||
    filename.includes("facade") ||
    filename.includes("entrance")
  ) {
    return "exterior_front";
  }
  if (
    filename.includes("exterior") ||
    filename.includes("outside") ||
    filename.includes("building")
  ) {
    return "exterior_other";
  }

  // Outdoor features
  if (filename.includes("pool") || filename.includes("swimming")) {
    return "pool";
  }
  if (
    filename.includes("garden") ||
    filename.includes("yard") ||
    filename.includes("terrace") ||
    filename.includes("patio")
  ) {
    return "garden";
  }

  // Interior rooms
  if (
    filename.includes("living") ||
    filename.includes("lounge") ||
    filename.includes("salon")
  ) {
    return "living_room";
  }
  if (filename.includes("kitchen") || filename.includes("cooking")) {
    return "kitchen";
  }
  if (
    filename.includes("bedroom") ||
    filename.includes("master") ||
    filename.includes("sleep")
  ) {
    return "bedroom";
  }
  if (
    filename.includes("bathroom") ||
    filename.includes("bath") ||
    filename.includes("shower") ||
    filename.includes("wc")
  ) {
    return "bathroom";
  }

  // Generic interior
  if (filename.includes("interior") || filename.includes("inside")) {
    return "other";
  }

  return "unknown";
}

// Image validation timeout in milliseconds
const IMAGE_VALIDATION_TIMEOUT_MS = 5000; // 5 seconds per image

/**
 * Validate image URL is accessible and safe
 * Checks both security (SSRF) and accessibility
 * Returns detailed error information for debugging
 */
async function checkImageAccessibleWithError(
  url: string
): Promise<{ valid: boolean; error: string }> {
  try {
    // P0 SECURITY: Validate URL before making any request (SSRF prevention)
    const securityCheck = validateImageUrl(url);
    if (!securityCheck.valid) {
      logger.warn(`[Image Handler] SSRF blocked: ${securityCheck.error}`, {
        category: LogCategory.IMAGE,
        url: url.substring(0, 100),
      });
      return { valid: false, error: `Security: ${securityCheck.error}` };
    }

    // Create abort controller for timeout
    const controller = new AbortController();
    const timeoutId = setTimeout(
      () => controller.abort(),
      IMAGE_VALIDATION_TIMEOUT_MS
    );

    try {
      // Try HEAD first, fall back to GET if HEAD fails (some servers like picsum don't support HEAD)
      let response = await fetch(url, {
        method: "HEAD",
        signal: controller.signal,
      });
      if (!response.ok && response.status === 405) {
        // HEAD not allowed, try GET with a range to minimize data transfer
        response = await fetch(url, {
          method: "GET",
          headers: { Range: "bytes=0-1024" },
          signal: controller.signal,
        });
      }

      clearTimeout(timeoutId);

      if (!response.ok) {
        return {
          valid: false,
          error: `HTTP ${response.status}: ${response.statusText}`,
        };
      }

      const contentType = response.headers.get("content-type");
      if (!contentType?.startsWith("image/")) {
        return {
          valid: false,
          error: `Not an image (${contentType || "no content-type"})`,
        };
      }

      return { valid: true, error: "" };
    } catch (fetchErr) {
      clearTimeout(timeoutId);
      if (fetchErr instanceof Error && fetchErr.name === "AbortError") {
        return {
          valid: false,
          error: `Timeout after ${IMAGE_VALIDATION_TIMEOUT_MS}ms`,
        };
      }
      throw fetchErr;
    }
  } catch (err) {
    const errorMsg = err instanceof Error ? err.message : String(err);
    return { valid: false, error: `Fetch failed: ${errorMsg}` };
  }
}

/**
 * Process a list of image URLs for upload
 */
export async function processImages(
  imageUrls: string[]
): Promise<ProcessedImage[]> {
  const processed: ProcessedImage[] = [];

  for (const url of imageUrls) {
    // Skip empty URLs
    if (!url || url.trim() === "") {
      continue;
    }

    const classification = classifyImage(url);
    const needsCropping = hasKnownWatermark(url);
    const privacyIssues = detectPrivacyIssues(url);

    processed.push({
      url: url.trim(),
      order: IMAGE_ORDER[classification],
      needsCropping,
      privacyIssues,
      classification,
    });
  }

  // Only sort when images have meaningful filenames (e.g., URL images from ibb.co).
  // WhatsApp images from Supabase Storage all get "unknown" classification (generic UUIDs),
  // so sorting is meaningless and can shuffle the agent's intended order.
  const allUnknown = processed.every((img) => img.classification === "unknown");
  if (allUnknown) {
    return processed; // Preserve original order (created_at ASC from getPendingImages)
  }

  // Sort by order priority when meaningful classifications exist
  return processed.sort((a, b) => a.order - b.order);
}

export interface InvalidImage {
  url: string;
  error: string;
}

/**
 * Validate that all images are accessible
 * IMPORTANT: Preserves original array order (parallel checks complete in random order)
 */
export async function validateImages(
  images: ProcessedImage[]
): Promise<{ valid: ProcessedImage[]; invalid: InvalidImage[] }> {
  // Check all images in parallel but use index to preserve order
  const results = await Promise.all(
    images.map(async (img) => {
      const result = await checkImageAccessibleWithError(img.url);
      return { img, result };
    })
  );

  const valid: ProcessedImage[] = [];
  const invalid: InvalidImage[] = [];

  // Iterate in original order (Promise.all preserves index mapping)
  for (const { img, result } of results) {
    if (result.valid) {
      valid.push(img);
    } else {
      invalid.push({ url: img.url, error: result.error });
    }
  }

  return { valid, invalid };
}

/**
 * Generate warning message for images with issues
 */
export function generateImageWarnings(images: ProcessedImage[]): string {
  const warnings: string[] = [];

  const watermarkImages = images.filter((img) => img.needsCropping);
  if (watermarkImages.length > 0) {
    warnings.push(
      `⚠️ ${watermarkImages.length} image(s) may contain watermarks from other websites. ` +
        "Please crop or replace these before publishing."
    );
  }

  const privacyImages = images.filter((img) => img.privacyIssues.length > 0);
  if (privacyImages.length > 0) {
    warnings.push(
      `⚠️ ${privacyImages.length} image(s) may have privacy concerns. ` +
        "Please review before publishing."
    );
  }

  return warnings.join("\n\n");
}

/**
 * Get image URLs in optimized order
 */
export function getOrderedImageUrls(images: ProcessedImage[]): string[] {
  return images.map((img) => img.url);
}

/**
 * Minimum images required for different property types
 * Reduced to 1 for all types to allow easier WhatsApp uploads
 * Zyprus API only requires 1 image minimum
 */
export function getMinimumImageCount(propertyType: string): number {
  // All property types now only require 1 image minimum
  // The API can accept more, but 1 is sufficient for draft creation
  return 1;
}

/**
 * Check if we have enough images
 */
export function hasEnoughImages(
  images: ProcessedImage[],
  propertyType: string
): { enough: boolean; required: number; provided: number } {
  const required = getMinimumImageCount(propertyType);
  const provided = images.length;

  return {
    enough: provided >= required,
    required,
    provided,
  };
}

/**
 * Pending Images Service
 *
 * Accumulates property listing images across multiple WhatsApp webhook calls.
 * WhatsApp sends each photo as a separate message, so we need to track them
 * together until the user confirms all photos are sent.
 *
 * Images auto-expire after 1 hour and are cleared after successful upload.
 */

import { getContext } from "../utils/context.ts";
import { LogCategory, logger } from "../utils/logger.ts";
import { getSupabaseAdmin } from "../../_shared/db.ts";

const supabase = getSupabaseAdmin();

// Auto-expire images older than 1 hour
const EXPIRY_MS = 60 * 60 * 1000; // 1 hour

export interface PendingImageRecord {
  url: string;
  contentHash: string;
}

/**
 * Add images to pending queue for a user.
 * Uses content_hash for deduplication — same image content with different URLs
 * will be rejected by the UNIQUE(phone_number, content_hash) index.
 */
export async function addPendingImages(
  phoneNumber: string,
  images: PendingImageRecord[],
  correlationId?: string
): Promise<void> {
  if (!images || images.length === 0) return;

  // Get correlation ID from context if not provided
  const ctx = getContext();
  const corrId = correlationId || ctx.correlationId;

  logger.info("Adding images to pending queue", {
    category: LogCategory.IMAGE,
    operation: "addPendingImages",
    correlationId: corrId,
    imageCount: images.length,
  });

  // Build records with content_hash for content-based deduplication
  const records = images.map((img) => ({
    phone_number: phoneNumber,
    image_url: img.url,
    content_hash: img.contentHash,
  }));

  // Use upsert with ignoreDuplicates on content_hash
  // This prevents the SAME image content from being stored twice,
  // even when WhatsApp re-decrypts it into a different temporary URL
  const { error } = await supabase.from("pending_images").upsert(records, {
    onConflict: "phone_number,image_url",
    ignoreDuplicates: true,
  });

  if (error) {
    // If the content_hash unique constraint fires, that's expected (dedup working!)
    if (error.code === "23505" && error.message?.includes("content_hash")) {
      logger.info("Content-hash dedup: duplicate image(s) skipped", {
        category: LogCategory.IMAGE,
        operation: "addPendingImages",
        correlationId: corrId,
      });
    } else {
      logger.error("Failed to add pending images", error, {
        category: LogCategory.IMAGE,
        operation: "addPendingImages",
        correlationId: corrId,
        imageCount: images.length,
      });
    }
  } else {
    logger.info("Successfully added pending images", {
      category: LogCategory.IMAGE,
      operation: "addPendingImages",
      correlationId: corrId,
      imageCount: images.length,
    });
  }
}

// Track last cleanup time to avoid per-request cleanup overhead
let lastCleanupTime = 0;
const CLEANUP_INTERVAL_MS = 5 * 60 * 1000; // 5 minutes

/**
 * Clean up expired images - called periodically, not on every request
 */
async function cleanupExpiredImages(): Promise<void> {
  const now = Date.now();
  // Only cleanup every 5 minutes to reduce database load
  if (now - lastCleanupTime < CLEANUP_INTERVAL_MS) {
    return;
  }
  lastCleanupTime = now;

  const expiryTime = new Date(now - EXPIRY_MS).toISOString();
  await supabase.from("pending_images").delete().lt("created_at", expiryTime);
}

/**
 * Get all pending images for a user (accumulated across multiple webhook calls)
 * Cleanup runs periodically (every 5 min) to reduce per-request overhead
 */
export async function getPendingImages(phoneNumber: string): Promise<string[]> {
  const ctx = getContext();

  // Periodic cleanup (non-blocking, fire and forget)
  cleanupExpiredImages().catch((error) => {
    logger.warn("Periodic image cleanup failed (non-critical)", {
      category: LogCategory.IMAGE,
      operation: "cleanupExpiredImages",
      error: error instanceof Error ? error.message : String(error),
    });
  });

  // Get all pending images for this user
  // Order by id (auto-increment) for reliable insertion-order preservation
  // created_at can have identical timestamps for batch inserts
  const { data, error } = await supabase
    .from("pending_images")
    .select("image_url")
    .eq("phone_number", phoneNumber)
    .order("id", { ascending: true });

  if (error) {
    logger.error("Failed to get pending images", error, {
      category: LogCategory.IMAGE,
      operation: "getPendingImages",
      correlationId: ctx.correlationId,
    });
    return [];
  }

  const urls = data?.map((row) => row.image_url) || [];
  logger.info("Retrieved pending images", {
    category: LogCategory.IMAGE,
    operation: "getPendingImages",
    correlationId: ctx.correlationId,
    imageCount: urls.length,
  });

  return urls;
}

/**
 * Get count of pending images for a user
 */
export async function getPendingImageCount(
  phoneNumber: string
): Promise<number> {
  const { count, error } = await supabase
    .from("pending_images")
    .select("id", { count: "exact", head: true })
    .eq("phone_number", phoneNumber);

  if (error) {
    logger.error("Failed to count pending images", error, {
      category: LogCategory.IMAGE,
      operation: "getPendingImageCount",
    });
    return 0;
  }

  return count || 0;
}

/**
 * Clear all pending images for a user (call after successful upload)
 */
export async function clearPendingImages(phoneNumber: string): Promise<void> {
  logger.info("Clearing pending images", {
    category: LogCategory.IMAGE,
    operation: "clearPendingImages",
  });

  const { error } = await supabase
    .from("pending_images")
    .delete()
    .eq("phone_number", phoneNumber);

  if (error) {
    logger.error("Failed to clear pending images", error, {
      category: LogCategory.IMAGE,
      operation: "clearPendingImages",
    });
  } else {
    logger.info("Successfully cleared pending images", {
      category: LogCategory.IMAGE,
      operation: "clearPendingImages",
    });
  }
}

