/**
 * Builds the system prompt with all contextual information
 */
export async function buildSystemPrompt(
  supabase: ReturnType<typeof createClient>,
  context: ChatContext,
  identifiedAgent: Agent | null
): Promise<string> {
  // Get current date/time in Cyprus timezone (Europe/Nicosia)
  const cyprusDate = new Date().toLocaleString("en-GB", {
    timeZone: "Europe/Nicosia",
    weekday: "long",
    year: "numeric",
    month: "long",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
  const cyprusDateShort = new Date().toLocaleDateString("en-GB", {
    timeZone: "Europe/Nicosia",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });

  // Calculate tomorrow's date
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowDateShort = tomorrow.toLocaleDateString("en-GB", {
    timeZone: "Europe/Nicosia",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });

  // Inject current date context into system prompt
  const dateContext = `

---
## CURRENT DATE/TIME AWARENESS

**IMPORTANT: You must be aware of the current date and time.**

**Current Date/Time in Cyprus (Nicosia):** ${cyprusDate}
**Today's Date (DD/MM/YYYY format):** ${cyprusDateShort}

**When users say relative dates like:**
- "today" -> Use ${cyprusDateShort}
- "tomorrow" -> Add 1 day to today
- "next week" -> Add 7 days to today
- "yesterday" -> Subtract 1 day from today

**ALWAYS calculate dates correctly based on today being ${cyprusDateShort}.**

---
`;

  // Inject sender info with agent details if known
  let senderContext: string;
  if (identifiedAgent) {
    // Use the new agent identification for property uploads
    senderContext = `

---
## CURRENT SENDER - KNOWN AGENT

**IMPORTANT: You are talking to a KNOWN AGENT who can upload property listings.**

**Agent Name:** ${identifiedAgent.fullName}
**Phone Number:** ${context.phoneNumber}
**Email:** ${identifiedAgent.communicationEmail}
**Region:** ${identifiedAgent.region}
**Role:** ${identifiedAgent.role}
**Can Upload Listings:** ${identifiedAgent.canUpload ? "Yes" : "No"}

**When this agent wants to upload a property listing, use the createPropertyListing or createLandListing tools. DO NOT ask for their name - use their info directly.**

---
`;
  } else if (context.agentName) {
    senderContext = `

---
## CURRENT SENDER - KNOWN AGENT

**IMPORTANT: You are talking to a KNOWN AGENT. Use their info directly - DO NOT ask for their name or phone number.**

**Agent Name:** ${context.agentName}
**Phone Number:** ${context.phoneNumber}
${
  context.agentEmail
    ? `**Email:** ${context.agentEmail}
`
    : ""
}
**When generating documents for this agent, automatically use their name and phone number. DO NOT ask them to provide this information.**

---
`;
  } else {
    senderContext = `

---
## CURRENT SENDER IDENTIFICATION

**Message sent from phone number:** ${context.phoneNumber}

**This is an unknown sender. You may need to ask for their name if generating documents. If they want to upload a property, ask them to confirm who they are first.**

---
`;
  }

  // P1 PERFORMANCE: Only fetch accumulated images when relevant to message
  // This saves a DB call on ~95% of requests (most messages aren't about property uploads)
  let accumulatedImages: string[] = [];
  const lowerMessage = context.userMessage?.toLowerCase() || "";
  const isImageRelated = context.imageUrls && context.imageUrls.length > 0;
  const isPropertyRelated =
    lowerMessage.includes("property") ||
    lowerMessage.includes("upload") ||
    lowerMessage.includes("listing") ||
    lowerMessage.includes("photo") ||
    lowerMessage.includes("image") ||
    lowerMessage.includes("finished") ||
    lowerMessage.includes("done") ||
    lowerMessage.includes("that's all") ||
    lowerMessage.includes("assign") ||
    lowerMessage.includes("@zyprus.com");
  // Also check if agent can upload — short replies during upload flow need image context
  const isUploadCapableAgent = context.agentCanUpload === true;
  // Short messages (< 30 chars) from upload-capable agents are likely replies in upload flow
  const isShortReplyFromAgent =
    isUploadCapableAgent && lowerMessage.length < 30 && lowerMessage.length > 0;

  if (isImageRelated || isPropertyRelated || isShortReplyFromAgent) {
    accumulatedImages = await getPendingImages(
      context.phoneNumber.replace(/\D/g, "")
    );
  }
  const totalImageCount = accumulatedImages.length;

  let imageContext = "";
  if (totalImageCount > 0) {
    // Use accumulated images (includes current + previous photos)
    imageContext = `

---
## ACCUMULATED PROPERTY PHOTOS

**IMPORTANT: You have received a total of ${totalImageCount} photo(s) for the property listing.**

**All Image URLs (use ALL of these for property listings):**
${accumulatedImages.map((url, i) => `${i + 1}. ${url}`).join("\n")}

**When the user is ready to create a property listing, use ALL of these image URLs in the \`imageUrls\` parameter of the createPropertyListing or createLandListing tool. INCLUDE EVERY IMAGE - do not leave any out.**

**REMEMBER: Ask the user to confirm all photos have been sent before uploading! Also ask if any photos are title deed images (not property photos) — if yes, pass their numbers in titleDeedImageIndices.**

---
`;
    logger.info(
      `[Images] Added ${totalImageCount} ACCUMULATED image URL(s) to AI context`,
      { category: LogCategory.GENERAL }
    );
  }

  // Check for recently generated documents that can be attached to emails
  let documentContext = "";
  if (context.lastDocument) {
    const docTypeDisplay =
      context.lastDocument.document_type?.replace(/_/g, " ") || "document";
    documentContext = `

---
## AVAILABLE DOCUMENT FOR EMAIL ATTACHMENT

**You have a recently generated document available:**
- **Document:** ${context.lastDocument.document_name}
- **Type:** ${docTypeDisplay}
- **URL:** ${context.lastDocument.document_url}

**If the user asks to email this document (e.g., "send it to my email", "email me the document"):**
-> Use the sendEmail tool with the \`attachmentUrl\` parameter set to the URL above.
-> Keep the email subject and body simple (e.g., "Find attached the ${docTypeDisplay}")

---
`;
    logger.info(
      `[DocContext] Found available document for attachment: ${context.lastDocument.document_name}`,
      { category: LogCategory.GENERAL }
    );
  }

  // Build agent context for dynamic prompt loading
  const agentContext = {
    agentName: identifiedAgent?.fullName || context.agentName || "Agent",
    agentPhone: context.phoneNumber,
    currentDate: cyprusDateShort,
    tomorrowDate: tomorrowDateShort,
  };

  // Load system prompt from database (cached for 5 minutes, falls back to hardcoded)
  const baseSystemPrompt = await loadSystemPrompt(supabase, agentContext);
  logger.info(
    `[PromptLoader] Loaded system prompt (${baseSystemPrompt.length} chars)`,
    { category: LogCategory.GENERAL }
  );

  return (
    baseSystemPrompt +
    dateContext +
    senderContext +
    imageContext +
    documentContext +
    (context.personalizationContext || "")
  );
}

/**
 * Calls OpenRouter API with retry logic for rate limiting
 * @returns message, error, and usage (token counts from OpenRouter)
 */
async function callOpenRouter(
  messages: OpenRouterMessage[],
  tools: OpenRouterTool[],
  toolChoice: "auto" | "required" = "auto",
  model: string = PRIMARY_MODEL
): Promise<{
  message: OpenRouterMessage | null;
  usage: {
    promptTokens: number;
    completionTokens: number;
    totalTokens: number;
  } | null;
  error?: string;
}> {
  // Circuit breaker: fail fast if OpenRouter has been consistently failing
  if (!canRequest(OPENROUTER_CIRCUIT)) {
    logger.warn("OpenRouter circuit breaker OPEN — failing fast", {
      category: LogCategory.GENERAL,
    });
    return {
      message: null,
      usage: null,
      error: "AI service temporarily unavailable (circuit open)",
    };
  }

  let retries = 0;
  const maxRetries = 3;
  const baseDelay = 2000;

  try {
    while (retries <= maxRetries) {
      // Create fresh AbortController for each retry
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30_000); // 30 seconds

      try {
        const aiRes = await fetch(OPENROUTER_URL, {
          method: "POST",
          headers: {
            Authorization: `Bearer ${OPENROUTER_API_KEY}`,
            "Content-Type": "application/json",
            "HTTP-Referer": "https://sophia-ai.vercel.app",
            "X-Title": "SOPHIA WhatsApp Bot",
          },
          body: JSON.stringify({
            model,
            messages,
            temperature: 0.1,
            max_tokens: 8192,
            tools,
            tool_choice: toolChoice,
          }),
          signal: controller.signal,
        });

        clearTimeout(timeoutId);

        if (aiRes.ok) {
          recordSuccess(OPENROUTER_CIRCUIT);
          const aiData = await aiRes.json();

          // Extract usage data from OpenRouter response
          const usage = aiData.usage
            ? {
                promptTokens: aiData.usage.prompt_tokens || 0,
                completionTokens: aiData.usage.completion_tokens || 0,
                totalTokens: aiData.usage.total_tokens || 0,
              }
            : null;

          if (!usage) {
            logger.warn(
              "[OpenRouter] No usage data in response - token tracking unavailable for this request",
              { category: LogCategory.GENERAL }
            );
          }

          return { message: aiData.choices?.[0]?.message, usage };
        }

        const errorData = await aiRes.json().catch(() => ({
          error: { status: aiRes?.status ?? 0 },
        }));

        if (aiRes.status === 429 && retries < maxRetries) {
          const delay = baseDelay * 2 ** retries;
          logger.info(
            `OpenRouter rate limited (429). Retrying in ${delay}ms... (attempt ${retries + 1}/${maxRetries})`,
            { category: LogCategory.GENERAL }
          );
          await new Promise((resolve) => setTimeout(resolve, delay));
          retries++;
          continue;
        }

        logger.error(
          "OpenRouter Error: " + JSON.stringify(errorData, null, 2),
          undefined,
          { category: LogCategory.GENERAL }
        );
        logger.error("Status: " + String(aiRes.status), undefined, {
          category: LogCategory.GENERAL,
        });

        recordFailure(OPENROUTER_CIRCUIT);
        return { message: null, usage: null, error: "OpenRouter API error" };
      } catch (error) {
        clearTimeout(timeoutId);
        // Re-throw to outer catch if it's an abort error
        if (error instanceof Error && error.name === "AbortError") {
          throw error;
        }
        throw error;
      }
    }

    recordFailure(OPENROUTER_CIRCUIT);
    return { message: null, usage: null, error: "Max retries exceeded" };
  } catch (error) {
    if (error instanceof Error && error.name === "AbortError") {
      logger.error("OpenRouter request timeout (30s)", error, {
        category: LogCategory.GENERAL,
      });
      recordFailure(OPENROUTER_CIRCUIT);
      return {
        message: null,
        usage: null,
        error: "OpenRouter request timeout (30s)",
      };
    }
    recordFailure(OPENROUTER_CIRCUIT);
    throw error;
  }
}

/**
 * Main AI chat function with tool calling loop
 */
export async function chat(
  history: Array<{ role: string; parts: Array<{ text: string }> }>,
  systemPrompt: string,
  userMessage: string,
  imageUrls: string[],
  identifiedAgent: Agent | null,
  phoneNumber: string
): Promise<AIResponse> {
  if (!OPENROUTER_API_KEY) {
    logger.error("CRITICAL: OPENROUTER_API_KEY is not set", undefined, {
      category: LogCategory.GENERAL,
    });
    return {
      response: "Service configuration error. Please contact support.",
      success: false,
    };
  }

  // Convert Gemini history format to OpenRouter format
  const openrouterMessages: OpenRouterMessage[] = [
    { role: "system", content: systemPrompt },
  ];

  // Convert history: {role, parts: [{text}]} -> {role, content}
  for (const msg of history) {
    const role = msg.role === "model" ? "assistant" : msg.role;
    const content = msg.parts
      .map((p: { text?: string }) => p.text || "")
      .join("");
    openrouterMessages.push({
      role: role as "system" | "user" | "assistant" | "tool",
      content,
    });
  }

  logger.info(
    `[OpenRouter] Calling with ${openrouterMessages.length} messages`,
    { category: LogCategory.GENERAL }
  );

  // Get tool definitions for property listing uploads
  const tools = getToolDefinitions();
  logger.info(
    `[OpenRouter] Including ${tools.length} tools for function calling`,
    { category: LogCategory.GENERAL }
  );

  // Detect if user wants to upload a property - force tool usage in this case
  const lowerMessage = userMessage.toLowerCase();
  const isPropertyUploadIntent =
    (lowerMessage.includes("upload") && lowerMessage.includes("property")) ||
    (lowerMessage.includes("create") && lowerMessage.includes("listing")) ||
    (lowerMessage.includes("add") && lowerMessage.includes("property")) ||
    (lowerMessage.includes("want to") && lowerMessage.includes("upload")) ||
    (lowerMessage.includes("i want to") && lowerMessage.includes("property")) ||
    (imageUrls.length > 0 &&
      (lowerMessage.includes("property") ||
        lowerMessage.includes("listing") ||
        lowerMessage.includes("bedroom") ||
        lowerMessage.includes("apartment") ||
        lowerMessage.includes("villa") ||
        lowerMessage.includes("house")));

  if (isPropertyUploadIntent) {
    logger.info(
      "[OpenRouter] Property upload intent detected - will force tool usage",
      { category: LogCategory.ZYPRUS }
    );
  }

  // Tool calling loop - handle multiple tool calls if needed
  let aiResponse = "";
  const maxToolCalls = 5; // Prevent infinite loops
  let toolCallCount = 0;
  let retryableCount = 0; // Cap retryable validation loops to avoid burning tokens
  const MAX_RETRYABLE = 2;
  const currentMessages = [...openrouterMessages];
  const toolsUsed: string[] = [];
  let totalTokens = 0; // Accumulate tokens from all OpenRouter calls

  // Edge Function timeout is 120s - use 90s budget with 30s buffer for response generation
  const TIME_BUDGET_MS = 90_000;
  const startTime = Date.now();

  while (toolCallCount < maxToolCalls) {
    // Check time budget before each iteration
    const elapsedMs = Date.now() - startTime;
    if (elapsedMs > TIME_BUDGET_MS) {
      logger.warn(
        `Tool execution loop exceeded time budget (${elapsedMs}ms > ${TIME_BUDGET_MS}ms) after ${toolCallCount} tool calls`,
        { category: LogCategory.GENERAL }
      );
      return {
        response:
          "I'm taking longer than expected to complete this task. Please try again, and I'll work more efficiently.",
        success: true, // Graceful degradation, not a failure
        toolsUsed,
        tokenCount: totalTokens > 0 ? totalTokens : undefined,
      };
    }

    const toolChoiceForCall =
      isPropertyUploadIntent && toolCallCount === 0 ? "required" : "auto";

    const openRouterResult = await callOpenRouter(
      currentMessages,
      tools,
      toolChoiceForCall
    );
    let { message, error } = openRouterResult;
    const { usage } = openRouterResult;

    // Accumulate token usage
    if (usage?.totalTokens) {
      totalTokens += usage.totalTokens;
    }

    // Fallback: if primary model fails, try the stable fallback model
    if (error || !message) {
      logger.warn(
        `[Fallback] Primary model failed (${error}), trying ${FALLBACK_MODEL}`,
        { category: LogCategory.GENERAL }
      );
      const fallback = await callOpenRouter(
        currentMessages,
        tools,
        toolChoiceForCall,
        FALLBACK_MODEL
      );
      message = fallback.message;
      error = fallback.error;

      // Accumulate fallback token usage
      if (fallback.usage?.totalTokens) {
        totalTokens += fallback.usage.totalTokens;
      }

      if (error || !message) {
        return {
          response:
            "I'm experiencing technical difficulties right now. Please try again in a few moments.",
          success: false,
        };
      }
      logger.info("[Fallback] Fallback model succeeded", {
        category: LogCategory.GENERAL,
      });
    }

    // SAFETY NET: Detect tool calls output as text (Gemini preview models sometimes do this)
    // Pattern: {"action": "default_api:sendEmail", "action_input": "{ ... }"}
    if (
      (!message?.tool_calls || message.tool_calls.length === 0) &&
      message?.content
    ) {
      const content =
        typeof message.content === "string" ? message.content : "";
      const textToolMatch = content.match(
        /\{\s*"action"\s*:\s*"(?:default_api:)?(\w+)"\s*,\s*"action_input"\s*:\s*"(.+?)"\s*\}/s
      );
      if (textToolMatch) {
        const toolName = textToolMatch[1];
        const toolArgsStr = textToolMatch[2]
          .replace(/\\"/g, '"') // unescape quotes
          .replace(/\\n/g, "\n");
        try {
          const toolArgs = JSON.parse(toolArgsStr);
          logger.info(
            `[OpenRouter] Detected text-based tool call for ${toolName}, converting to proper tool call`,
            { category: LogCategory.GENERAL }
          );
          message.tool_calls = [
            {
              id: `text_tool_${Date.now()}`,
              type: "function",
              function: { name: toolName, arguments: JSON.stringify(toolArgs) },
            },
          ];
          // Clear the text content so it doesn't get sent to the user as raw JSON
          message.content = "";
        } catch (parseErr) {
          logger.error(
            `[OpenRouter] Failed to parse text-based tool call: ${String(parseErr)}`,
            undefined,
            { category: LogCategory.GENERAL }
          );
        }
      }
    }

    // Check for tool calls
    if (message?.tool_calls && message.tool_calls.length > 0) {
      toolCallCount++;
      logger.info(
        `[OpenRouter] Tool call ${toolCallCount}: ${message.tool_calls.length} tools requested`,
        { category: LogCategory.GENERAL }
      );

      // CRITICAL: Deduplicate identical tool calls within the same response
      // OpenRouter sometimes returns duplicate tool calls, causing duplicate executions
      const seenToolSignatures = new Set<string>();
      const uniqueToolCalls = message.tool_calls.filter((toolCall) => {
        const toolName = toolCall.function.name;
        const toolArgs = toolCall.function.arguments || "{}";
        // Create a signature from tool name + args hash
        const signature = `${toolName}:${toolArgs}`;
        if (seenToolSignatures.has(signature)) {
          logger.warn(
            `[OpenRouter] Filtering out duplicate tool call: ${toolName}`,
            { category: LogCategory.GENERAL }
          );
          return false;
        }
        seenToolSignatures.add(signature);
        return true;
      });

      if (uniqueToolCalls.length < message.tool_calls.length) {
        logger.info(
          `[OpenRouter] Deduplicated tool calls: ${message.tool_calls.length} -> ${uniqueToolCalls.length}`,
          { category: LogCategory.GENERAL }
        );
      }

      // Add assistant message with original tool calls to history (for proper conversation flow)
      currentMessages.push({
        role: "assistant",
        content: message.content || "",
        tool_calls: message.tool_calls,
      });

      // Execute only unique tool calls
      for (const toolCall of uniqueToolCalls) {
        const toolName = toolCall.function.name;
        let toolArgs: Record<string, unknown>;

        try {
          toolArgs = JSON.parse(toolCall.function.arguments || "{}");
        } catch (_e) {
          logger.error(
            `Tool error: Failed to parse arguments for ${toolName}`,
            undefined,
            { category: LogCategory.TOOL }
          );
          toolArgs = {};
        }

        logger.info(`Tool: Executing: ${toolName}`, {
          category: LogCategory.TOOL,
        });
        logger.info(
          `Tool: Arguments: ${JSON.stringify(toolArgs).substring(0, 200)}`,
          { category: LogCategory.TOOL }
        );

        toolsUsed.push(toolName);

        // Execute the tool with error handling
        let toolResult;
        try {
          toolResult = await executeTool(
            { name: toolName, arguments: toolArgs },
            identifiedAgent,
            phoneNumber
          );
        } catch (error) {
          logger.error(`Tool execution failed: ${toolName}`, {
            error,
            category: LogCategory.ERROR,
          });
          toolResult = {
            success: false,
            message: `Error executing ${toolName}: ${error instanceof Error ? error.message : String(error)}`,
          };
        }

        logger.info(
          `Tool: Result: ${JSON.stringify(toolResult).substring(0, 200)}`,
          { category: LogCategory.TOOL }
        );

        // Add tool result to history
        currentMessages.push({
          role: "tool",
          tool_call_id: toolCall.id,
          content: JSON.stringify(toolResult),
        });

        // If tool needs user input, send the question and stop
        // EXCEPT: if the result is retryable (validation failure where AI didn't extract fields),
        // feed it back as a tool result so the AI can retry with correct args
        if (toolResult.needsInput && toolResult.question) {
          if (
            toolResult.retryable &&
            toolCallCount < maxToolCalls &&
            retryableCount < MAX_RETRYABLE
          ) {
            retryableCount++;
            logger.info(
              `[Retry] Tool ${toolName} returned retryable needsInput (attempt ${retryableCount}/${MAX_RETRYABLE}) — feeding back to AI loop`,
              { category: LogCategory.TOOL }
            );
            // The tool result is already in currentMessages (added above)
            // Break out of the for loop so the while loop makes a new AI call
            break;
          }
          return {
            response: toolResult.question,
            success: true,
            toolsUsed,
            tokenCount: totalTokens > 0 ? totalTokens : undefined,
          };
        }

        // If tool succeeded with a message, use it directly (don't ask AI to respond again)
        // This prevents the AI from generating DOCX when we just want a text confirmation
        if (toolResult.success && toolResult.message) {
          logger.info(
            "Tool: Success with message, using tool response directly",
            { category: LogCategory.TOOL }
          );

          // Clear pending images after successful upload
          if (
            toolName === "createPropertyListing" ||
            toolName === "createLandListing"
          ) {
            const cleanPhone = phoneNumber.replace(/\D/g, "");
            await clearPendingImages(cleanPhone);
            logger.info(
              `[Images] Cleared pending images for ${cleanPhone} after successful upload`,
              { category: LogCategory.IMAGE }
            );
          }

          return {
            response: toolResult.message,
            success: true,
            toolsUsed,
            tokenCount: totalTokens > 0 ? totalTokens : undefined,
          };
        }

        // If tool returned an error, return it directly (for debugging)
        if (toolResult.error) {
          logger.info(`Tool: Error result: ${toolResult.error}`, {
            category: LogCategory.TOOL,
          });
          // For createPropertyListing errors, show the actual error instead of generic message
          if (
            toolName === "createPropertyListing" ||
            toolName === "createLandListing"
          ) {
            return {
              response: `I encountered an error while creating the listing: ${toolResult.error}`,
              success: false,
              toolsUsed,
              tokenCount: totalTokens > 0 ? totalTokens : undefined,
            };
          }
        }
      }

      // Continue loop to get AI's next response
      continue;
    }

    // No tool calls - get the text response
    aiResponse = message?.content || "";

    // ANTI-HALLUCINATION FIX: If upload intent detected but no tool called, force retry with tool_choice: "required"
    if (isPropertyUploadIntent && toolCallCount === 0 && imageUrls.length > 0) {
      // Check budget before force retry
      const elapsedMs = Date.now() - startTime;
      if (elapsedMs > TIME_BUDGET_MS) {
        logger.warn(
          `Skipping force retry - time budget exceeded (${elapsedMs}ms > ${TIME_BUDGET_MS}ms)`,
          { category: LogCategory.GENERAL }
        );
        // Return current response without retry
        return {
          response: aiResponse,
          success: true,
          toolsUsed,
          tokenCount: totalTokens > 0 ? totalTokens : undefined,
        };
      }

      logger.info(
        "[FORCE TOOL] Upload intent with images but no tool call - forcing retry with required tool_choice",
        { category: LogCategory.GENERAL }
      );

      const {
        message: retryMessage,
        usage: retryUsage,
      } = await callOpenRouter(currentMessages, tools, "required");

      // Accumulate retry token usage
      if (retryUsage?.totalTokens) {
        totalTokens += retryUsage.totalTokens;
      }

      if (retryMessage?.tool_calls && retryMessage.tool_calls.length > 0) {
        logger.info("[FORCE TOOL] Retry successful - got tool calls", {
          category: LogCategory.GENERAL,
        });

        // CRITICAL: Deduplicate identical tool calls within the retry response
        const seenToolSignatures = new Set<string>();
        const uniqueRetryCalls = retryMessage.tool_calls.filter((toolCall) => {
          const toolName = toolCall.function.name;
          const toolArgs = toolCall.function.arguments || "{}";
          const signature = `${toolName}:${toolArgs}`;
          if (seenToolSignatures.has(signature)) {
            logger.warn(
              `[FORCE TOOL] Filtering out duplicate tool call: ${toolName}`,
              { category: LogCategory.GENERAL }
            );
            return false;
          }
          seenToolSignatures.add(signature);
          return true;
        });

        // Process only unique tool calls
        for (const toolCall of uniqueRetryCalls) {
          const toolName = toolCall.function.name;
          let toolArgs: Record<string, unknown>;
          try {
            toolArgs = JSON.parse(toolCall.function.arguments || "{}");
          } catch (_e) {
            toolArgs = {};
          }
          logger.info(`[FORCE TOOL] Executing: ${toolName}`, {
            category: LogCategory.GENERAL,
          });
          toolsUsed.push(toolName);

          let toolResult;
          try {
            toolResult = await executeTool(
              { name: toolName, arguments: toolArgs },
              identifiedAgent,
              supabaseUrl,
              supabaseKey,
              phoneNumber
            );
          } catch (error) {
            logger.error(`[FORCE TOOL] Tool execution failed: ${toolName}`, {
              error,
              category: LogCategory.ERROR,
            });
            toolResult = {
              success: false,
              message: `Error executing ${toolName}: ${error instanceof Error ? error.message : String(error)}`,
            };
          }

          if (toolResult.success && toolResult.message) {
            // Clear pending images after successful upload
            if (
              toolName === "createPropertyListing" ||
              toolName === "createLandListing"
            ) {
              const cleanPhone = phoneNumber.replace(/\D/g, "");
              await clearPendingImages(cleanPhone);
            }
            return {
              response: toolResult.message,
              success: true,
              toolsUsed,
              tokenCount: totalTokens > 0 ? totalTokens : undefined,
            };
          }
          if (toolResult.needsInput && toolResult.question) {
            return {
              response: toolResult.question,
              success: true,
              toolsUsed,
              tokenCount: totalTokens > 0 ? totalTokens : undefined,
            };
          }
          if (toolResult.error) {
            return {
              response: `I encountered an issue: ${toolResult.error}`,
              success: false,
              toolsUsed,
              tokenCount: totalTokens > 0 ? totalTokens : undefined,
            };
          }
        }
      }
    }

    break;
  }

  if (!aiResponse) {
    logger.error("Empty response from OpenRouter", undefined, {
      category: LogCategory.GENERAL,
    });
    return {
      response:
        "I couldn't generate a response. Please rephrase your request and try again.",
      success: false,
    };
  }

  logger.info(
    "AI Response received (first 500 chars): " + aiResponse.substring(0, 500),
    { category: LogCategory.GENERAL }
  );
  logger.info("AI Response length:" + String(aiResponse.length), {
    category: LogCategory.GENERAL,
  });

  return {
    response: aiResponse,
    success: true,
    toolsUsed: toolsUsed.length > 0 ? toolsUsed : undefined,
    tokenCount: totalTokens > 0 ? totalTokens : undefined,
  };
}

/**
 * SOPHIA Dynamic Prompt Loader
 * Loads prompts from sophia_prompts table with 5-minute caching
 *
 * Benefits:
 * - Edit prompts via Supabase Dashboard without redeploying
 * - 5-minute cache TTL for performance
 * - Fallback to hardcoded prompts if DB fails
 */

import type { SupabaseClient } from "jsr:@supabase/supabase-js@2";
import { LogCategory, logger } from "../utils/logger.ts";

/**
 * Cache TTL: 5 minutes
 *
 * Cache invalidation strategy:
 * 1. Time-based: Cache expires after 5 minutes
 * 2. Version-based: Cache invalidated if DB updated_at > cached version
 * 3. Manual: Admin can POST to /admin/prompts/invalidate
 *
 * This dual-strategy ensures:
 * - Performance: Most requests served from cache
 * - Freshness: DB changes detected within seconds (version check)
 * - Control: Admin can force refresh when needed
 */
const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes

// Cache miss reason tracking
type CacheMissReason =
  | "first_load"
  | "expired"
  | "version_mismatch"
  | "manual_invalidation";

// In-memory cache
let cachedPromptSections: Map<string, string> | null = null;
let cacheTimestamp = 0;
let cacheVersion: string | null = null; // Stores MAX(updated_at) from last load
let lastInvalidationReason: string | null = null;
let lastVersionCheckTime = 0;

// Version check interval: Only check DB version every 30 seconds (not every request)
// This reduces DB queries from ~50-100ms per request to once per 30s
const VERSION_CHECK_INTERVAL_MS = 30_000;

// Single-inflight-request pattern: Prevents concurrent cache loads during cache miss
// When multiple requests arrive simultaneously, they share the same loading promise
let loadingPromise: Promise<Map<string, string>> | null = null;

import { DOCUMENT_ROUTING } from "../prompts/behaviors/document-routing.ts";
import { PROPERTY_UPLOAD } from "../prompts/behaviors/property-upload.ts";
import { RESERVATION_LOAN_VAT_REQUIRED } from "../prompts/behaviors/reservation-loan-vat.ts";
import { RESPONSE_FORMAT } from "../prompts/behaviors/response-format.ts";
// Fallback prompts imported from modular files (used if DB fails)
import { IDENTITY } from "../prompts/core/identity.ts";
import { SAFETY_RULES } from "../prompts/core/safety-rules.ts";
import { CALCULATOR_CAPABILITIES } from "../prompts/knowledge/calculators.ts";
import { CYPRUS_KNOWLEDGE } from "../prompts/knowledge/cyprus-real-estate.ts";
import { TEMPLATES } from "../prompts/templates/content.ts";

// Fallback map for when DB is unavailable
const FALLBACK_PROMPTS: Record<string, string> = {
  identity: IDENTITY,
  safety_rules: SAFETY_RULES,
  reservation_loan_vat_required: RESERVATION_LOAN_VAT_REQUIRED,
  document_routing: DOCUMENT_ROUTING,
  property_upload: PROPERTY_UPLOAD,
  response_format: RESPONSE_FORMAT,
  calculators: CALCULATOR_CAPABILITIES,
  cyprus_knowledge: CYPRUS_KNOWLEDGE,
  templates: TEMPLATES,
};

// Keys where file content MUST override DB (updated in code, DB not yet synced)
// TODO: Remove entries after running /admin/prompts/sync to push to DB
const FILE_OVERRIDE_KEYS = [
  "document_routing",
  "response_format",
  "safety_rules",
  "property_upload",
  "templates",
];

interface PromptRow {
  key: string;
  content: string;
  priority: number;
}

interface AgentContext {
  agentName: string;
  agentPhone: string;
  currentDate: string;
  tomorrowDate: string;
}

/**
 * Get current database version using MAX(updated_at)
 * Used for version-based cache invalidation
 */
async function getDatabaseVersion(
  supabase: SupabaseClient
): Promise<string | null> {
  try {
    const { data, error } = await supabase
      .from("sophia_prompts")
      .select("updated_at")
      .eq("is_active", true)
      .eq("is_current", true)
      .order("updated_at", { ascending: false })
      .limit(1)
      .single();

    if (error || !data) {
      return null;
    }
    return data.updated_at;
  } catch {
    return null;
  }
}

/**
 * Load prompt sections from database with caching
 */
async function loadPromptSectionsFromDB(
  supabase: SupabaseClient
): Promise<Map<string, string> | null> {
  try {
    const { data, error } = await supabase
      .from("sophia_prompts")
      .select("key, content, priority")
      .eq("is_active", true)
      .eq("is_current", true)
      .order("priority", { ascending: true });

    if (error) {
      logger.error("DB error loading prompts", new Error(error.message), {
        category: LogCategory.CACHE,
        errorMessage: error.message,
      });
      return null;
    }

    if (!data || data.length === 0) {
      logger.warn("No active prompts found in DB", {
        category: LogCategory.CACHE,
      });
      return null;
    }

    // Convert to map for easy lookup
    const promptMap = new Map<string, string>();
    for (const row of data as PromptRow[]) {
      promptMap.set(row.key, row.content);
    }

    logger.info("Loaded prompts from DB", {
      category: LogCategory.CACHE,
      promptCount: promptMap.size,
    });
    return promptMap;
  } catch (err) {
    logger.error("Exception loading prompts", err as Error, {
      category: LogCategory.CACHE,
    });
    return null;
  }
}

/**
 * Get prompt sections with caching
 * Merges DB prompts with fallback for any missing keys
 */
async function getPromptSections(
  supabase: SupabaseClient
): Promise<Map<string, string>> {
  const now = Date.now();
  let cacheMissReason: CacheMissReason | null = null;
  let detectedDbVersion: string | null = null; // Track version from first check to avoid duplicate DB call

  // Check if cache exists
  if (!cachedPromptSections) {
    cacheMissReason = "first_load";
  } else if (now - cacheTimestamp >= CACHE_TTL_MS) {
    cacheMissReason = "expired";
  } else {
    // Cache exists and within TTL
    // Only check version periodically (every 30s) to avoid DB query on every request
    const shouldCheckVersion =
      now - lastVersionCheckTime >= VERSION_CHECK_INTERVAL_MS;

    if (shouldCheckVersion) {
      lastVersionCheckTime = now;
      detectedDbVersion = await getDatabaseVersion(supabase);
      if (detectedDbVersion && detectedDbVersion !== cacheVersion) {
        cacheMissReason = "version_mismatch";
        logger.info("Cache version mismatch detected", {
          category: LogCategory.CACHE,
          cachedVersion: cacheVersion?.substring(0, 19) ?? "none",
          dbVersion: detectedDbVersion.substring(0, 19),
        });
      }
    }

    // If no version mismatch (or didn't check), return cached data
    if (!cacheMissReason) {
      const cacheAge = now - cacheTimestamp;
      logger.debug("Cache HIT", {
        category: LogCategory.CACHE,
        cacheAgeMs: cacheAge,
        cacheAgeFormatted: `${Math.round(cacheAge / 1000)}s`,
        ttlRemainingMs: CACHE_TTL_MS - cacheAge,
        sectionCount: cachedPromptSections.size,
        version: cacheVersion?.substring(0, 19) ?? "unknown",
      });
      return cachedPromptSections;
    }
  }

  // Cache miss - check if already loading (race condition protection)
  if (loadingPromise) {
    logger.debug("Concurrent request detected - waiting for inflight load", {
      category: LogCategory.CACHE,
    });
    return loadingPromise;
  }

  // Cache miss - log reason and start loading
  logger.info("Cache MISS", {
    category: LogCategory.CACHE,
    reason: cacheMissReason,
    previousCacheAge: cachedPromptSections ? now - cacheTimestamp : null,
  });

  // Create loading promise BEFORE async work starts
  loadingPromise = (async () => {
    try {
      // Start with fallback prompts (full modular content)
      const mergedPrompts = new Map(Object.entries(FALLBACK_PROMPTS));

      // Try loading from DB and merge (DB takes precedence)
      const dbPrompts = await loadPromptSectionsFromDB(supabase);

      if (dbPrompts && dbPrompts.size > 0) {
        // Override fallback with DB values where available (DB is single source of truth)
        for (const [key, value] of dbPrompts) {
          mergedPrompts.set(key, value);
        }

        // File overrides: these keys were updated in code and MUST use file versions
        // until DB is synced via /admin/prompts/sync. Remove entries here after DB sync.
        for (const key of FILE_OVERRIDE_KEYS) {
          if (FALLBACK_PROMPTS[key]) {
            mergedPrompts.set(key, FALLBACK_PROMPTS[key]);
          }
        }

        const fallbackCount =
          Object.keys(FALLBACK_PROMPTS).length - dbPrompts.size;
        logger.debug("Merged DB prompts with fallbacks", {
          category: LogCategory.CACHE,
          dbCount: dbPrompts.size,
          fallbackCount,
          fileOverrides: FILE_OVERRIDE_KEYS.length,
        });
      } else {
        logger.warn("Using fallback hardcoded prompts (DB unavailable)", {
          category: LogCategory.CACHE,
        });
      }

      // Store the version - reuse from version check if available, otherwise fetch
      // This avoids a duplicate DB call when we already fetched the version during mismatch detection
      cacheVersion = detectedDbVersion ?? (await getDatabaseVersion(supabase));

      // Update cache
      cachedPromptSections = mergedPrompts;
      cacheTimestamp = now;

      // Log cache population
      logger.info("Cache populated", {
        category: LogCategory.CACHE,
        sectionCount: mergedPrompts.size,
        dbPromptCount: dbPrompts?.size ?? 0,
        fallbackPromptCount: Object.keys(FALLBACK_PROMPTS).length,
        version: cacheVersion?.substring(0, 19) ?? "unknown",
        ttlMs: CACHE_TTL_MS,
      });

      return mergedPrompts;
    } finally {
      // Clear loading promise whether success or failure
      loadingPromise = null;
    }
  })();

  return loadingPromise;
}

/**
 * Inject agent context into prompts
 */
function injectAgentContext(prompt: string, ctx: AgentContext): string {
  return prompt
    .replace(/\{AGENT_NAME\}/g, ctx.agentName)
    .replace(/\{AGENT_PHONE\}/g, ctx.agentPhone)
    .replace(/\{CURRENT_DATE\}/g, ctx.currentDate)
    .replace(/\{TOMORROW_DATE\}/g, ctx.tomorrowDate);
}

/**
 * Build the complete system prompt
 */
export async function loadSystemPrompt(
  supabase: SupabaseClient,
  agentContext: AgentContext
): Promise<string> {
  const sections = await getPromptSections(supabase);

  // Build agent context section
  const agentContextSection = `## Agent Context (Auto-Detected)
- Agent Name: ${agentContext.agentName}
- Agent Phone: ${agentContext.agentPhone}
- Today's Date: ${agentContext.currentDate}
- Tomorrow's Date: ${agentContext.tomorrowDate}`;

  // Assemble sections in priority order
  // The DB returns them sorted by priority, but we also define explicit order
  // NOTE: reservation_loan_vat_required (priority 25) must come BEFORE document_routing (30)
  const orderedKeys = [
    "identity",
    "safety_rules",
    "reservation_loan_vat_required", // MUST load before document_routing
    "document_routing",
    "property_upload",
    "response_format",
    "calculators",
    "cyprus_knowledge",
    "templates",
  ];

  const promptParts: string[] = [];

  // Add each section in order
  for (const key of orderedKeys) {
    const content = sections.get(key);
    if (content) {
      // Inject agent context into content
      const processedContent = injectAgentContext(content, agentContext);
      promptParts.push(processedContent);
    }
  }

  // Insert agent context after identity section
  promptParts.splice(1, 0, agentContextSection);

  // Join all sections with separator
  const fullPrompt = promptParts.join("\n\n---\n\n");

  logger.debug("Assembled system prompt", {
    category: LogCategory.CACHE,
    promptLength: fullPrompt.length,
  });

  return fullPrompt;
}

/**
 * Get a specific prompt section by key
 */
export async function getPromptSection(
  supabase: SupabaseClient,
  key: string
): Promise<string | null> {
  const sections = await getPromptSections(supabase);
  return sections.get(key) ?? null;
}

/**
 * Force refresh the cache (useful after Dashboard edits)
 */
export function invalidateCache(reason = "manual"): void {
  cachedPromptSections = null;
  cacheTimestamp = 0;
  cacheVersion = null;
  lastInvalidationReason = reason;
  logger.info("Cache invalidated", {
    category: LogCategory.CACHE,
    reason,
  });
}

/**
 * Check if cache is currently valid
 */
export function isCacheValid(): boolean {
  if (!cachedPromptSections) return false;
  return Date.now() - cacheTimestamp < CACHE_TTL_MS;
}

/**
 * Get cache status info (for debugging)
 */
export function getCacheStatus(): {
  isCached: boolean;
  age: number;
  ttl: number;
  sectionCount: number;
  version: string | null;
  lastInvalidationReason: string | null;
  isExpired: boolean;
} {
  const age = cachedPromptSections ? Date.now() - cacheTimestamp : 0;
  return {
    isCached: !!cachedPromptSections,
    age,
    ttl: CACHE_TTL_MS,
    sectionCount: cachedPromptSections?.size ?? 0,
    version: cacheVersion,
    lastInvalidationReason,
    isExpired: age > CACHE_TTL_MS,
  };
}

/**
 * Get version history for a prompt key (for admin UI)
 */
export async function getPromptVersionHistory(
  supabase: SupabaseClient,
  key: string
): Promise<
  Array<{
    version: number;
    created_at: string;
    replaced_at: string | null;
    is_current: boolean;
  }>
> {
  const { data, error } = await supabase
    .from("sophia_prompts")
    .select("version, created_at, replaced_at, is_current")
    .eq("key", key)
    .order("version", { ascending: false });

  if (error || !data) {
    logger.error(
      "Failed to get version history",
      new Error(error?.message || "Unknown"),
      {
        category: LogCategory.CACHE,
        promptKey: key,
      }
    );
    return [];
  }
  return data;
}

interface RollbackResult {
  success: boolean;
  message: string;
  newVersion?: number;
  error?: string;
}

/**
 * Rollback a prompt to a previous version
 *
 * Strategy:
 * 1. Find the target version's content
 * 2. Mark current version as not current (replaced_at = NOW())
 * 3. Create new version with target's content (version = current + 1)
 * 4. Invalidate cache
 *
 * This is append-only - we never delete or mutate historical versions.
 */
export async function rollbackPrompt(
  supabase: SupabaseClient,
  key: string,
  targetVersion: number,
  reason: string
): Promise<RollbackResult> {
  try {
    // 1. Get the target version's content
    const { data: targetData, error: targetError } = await supabase
      .from("sophia_prompts")
      .select("content, priority, category, description")
      .eq("key", key)
      .eq("version", targetVersion)
      .single();

    if (targetError || !targetData) {
      return {
        success: false,
        message: `Target version ${targetVersion} not found for key '${key}'`,
        error: targetError?.message,
      };
    }

    // 2. Get current version number
    const { data: currentData, error: currentError } = await supabase
      .from("sophia_prompts")
      .select("version")
      .eq("key", key)
      .eq("is_current", true)
      .single();

    if (currentError || !currentData) {
      return {
        success: false,
        message: `No current version found for key '${key}'`,
        error: currentError?.message,
      };
    }

    const currentVersion = currentData.version;
    const newVersion = currentVersion + 1;

    // 3. Mark current version as not current
    const { error: updateError } = await supabase
      .from("sophia_prompts")
      .update({
        is_current: false,
        replaced_at: new Date().toISOString(),
      })
      .eq("key", key)
      .eq("version", currentVersion);

    if (updateError) {
      return {
        success: false,
        message: "Failed to mark current version as replaced",
        error: updateError.message,
      };
    }

    // 4. Insert new version with target's content
    const { error: insertError } = await supabase
      .from("sophia_prompts")
      .insert({
        key,
        content: targetData.content,
        category: targetData.category,
        description: targetData.description,
        priority: targetData.priority,
        is_active: true,
        is_current: true,
        version: newVersion,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        updated_by: `rollback:${reason}`,
      });

    if (insertError) {
      // Try to restore current version flag
      await supabase
        .from("sophia_prompts")
        .update({ is_current: true, replaced_at: null })
        .eq("key", key)
        .eq("version", currentVersion);

      return {
        success: false,
        message: "Failed to create rollback version",
        error: insertError.message,
      };
    }

    // 5. Invalidate cache
    invalidateCache(`rollback:${key}:v${targetVersion}`);

    logger.info("Prompt rolled back", {
      category: LogCategory.CACHE,
      promptKey: key,
      fromVersion: currentVersion,
      toVersion: newVersion,
      targetVersion,
      reason,
    });

    return {
      success: true,
      message: `Rolled back '${key}' from v${currentVersion} to content of v${targetVersion} (now v${newVersion})`,
      newVersion,
    };
  } catch (err) {
    logger.error("Rollback failed", err as Error, {
      category: LogCategory.CACHE,
      promptKey: key,
      targetVersion,
    });
    return {
      success: false,
      message: "Rollback failed with exception",
      error: String(err),
    };
  }
}

/**
 * Message Processor Service
 *
 * Handles message extraction, parsing, validation, and response formatting.
 */

import { getContext } from "../utils/context.ts";
import { LogCategory, logger } from "../utils/logger.ts";
import { formatPropertyDescription } from "../utils/property-formatter.ts";
import { sendTextMessage } from "../utils/wasend.ts";
import { persistDocument, persistImages } from "./image-persistence.ts";
import { validateImagesAtIngress } from "./image-validator.ts";
import {
  decryptWhatsAppImage,
  isPublicUrl,
  needsDecryption,
} from "./media-decryptor.ts";
import { addPendingDocument } from "./pending-documents.ts";
import { addPendingImages } from "./pending-images.ts";
import type {
  WaSendDocumentMessage,
  WaSendImageMessage,
  WaSendMessage,
  WaSendWebhookPayload,
} from "../types/wasend.ts";

/**
 * Extracts message content from WaSend webhook payload
 * WaSend Format: { event: "messages.received", data: { messages: { key: {...}, messageBody: "...", message: {...} } } }
 * IMPORTANT: data.messages is a SINGLE OBJECT, not an array
 * IMPORTANT: Use key.cleanedSenderPn for phone number (remoteJid can be LID format)
 * IMPORTANT: WhatsApp images are encrypted - we decrypt them via WaSend API
 */
export async function extractMessage(payload: WaSendWebhookPayload): Promise<{
  message: WaSendMessage;
  remoteJid: string | null;
  userMessage: string;
  imageUrls: string[];
} | null> {
  logger.info("Extracting message from payload...", {
    category: LogCategory.GENERAL,
  });
  // DEBUG: Log full payload structure to diagnose image handling
  logger.debug("Full payload keys: " + String(Object.keys(payload)), {
    category: LogCategory.GENERAL,
  });
  logger.debug(
    "Payload preview: " + JSON.stringify(payload).substring(0, 500),
    { category: LogCategory.GENERAL }
  );

  let message: WaSendMessage | null = null;
  let remoteJid: string | null = null;
  let userMessage = "";
  const imageUrls: string[] = [];
  let imageDetectedButFailed = false; // Track if images were found but decryption failed

  // WaSend Format: { event: "messages.received", data: { messages: {...} } }
  if (payload.event && payload.data) {
    const event = payload.event;
    const data = payload.data;

    logger.info("Event type:" + String(event), {
      category: LogCategory.GENERAL,
    });

    if (
      event === "messages.upsert" ||
      event === "messages.received" ||
      event === "message" ||
      event === "messages"
    ) {
      // WaSend sends data.messages as a SINGLE OBJECT (not array)
      if (data.messages) {
        message = Array.isArray(data.messages)
          ? data.messages[0]
          : data.messages;
      } else if (data.message) {
        message = data.message;
      } else {
        message = data;
      }
    } else {
      logger.info("Unhandled event type:" + String(event), {
        category: LogCategory.GENERAL,
      });
      return null;
    }
  }
  // Fallback formats for other webhook providers
  else if (payload.from || payload.to) {
    message = payload;
  } else if (payload.data) {
    message = payload.data;
  } else {
    message = payload;
  }

  if (!message) {
    logger.info("No message object found", { category: LogCategory.GENERAL });
    return null;
  }

  // DEBUG: Comprehensive logging to diagnose image handling
  logger.debug(" === MESSAGE STRUCTURE ANALYSIS ===", {
    category: LogCategory.GENERAL,
  });
  logger.debug("Message keys: " + String(Object.keys(message)), {
    category: LogCategory.GENERAL,
  });
  logger.debug("Full message: " + JSON.stringify(message).substring(0, 2000), {
    category: LogCategory.GENERAL,
  });

  if (message.message) {
    logger.debug(
      "message.message keys: " + String(Object.keys(message.message)),
      { category: LogCategory.GENERAL }
    );
    logger.debug(
      "message.message: " + JSON.stringify(message.message).substring(0, 1000),
      { category: LogCategory.GENERAL }
    );
  }

  // Check specific fields that indicate image presence
  const hasImageIndicators = {
    "message.imageMessage": !!message.imageMessage,
    "message.message?.imageMessage": !!message.message?.imageMessage,
    "message.mediaUrl": !!message.mediaUrl,
    "message.media": !!message.media,
    "message.hasMedia": message.hasMedia,
    "message.messageType": message.messageType,
    "message.type": message.type,
  };
  logger.debug("Image indicators: " + JSON.stringify(hasImageIndicators), {
    category: LogCategory.GENERAL,
  });

  // Deep search for "imageMessage" keyword in the entire payload
  const payloadStr = JSON.stringify(message);
  if (payloadStr.includes("imageMessage")) {
    logger.debug(" *** Found 'imageMessage' somewhere in payload! ***", {
      category: LogCategory.GENERAL,
    });
    const imgIdx = payloadStr.indexOf("imageMessage");
    logger.debug(
      "Context around imageMessage: " +
        payloadStr.substring(Math.max(0, imgIdx - 50), imgIdx + 200),
      { category: LogCategory.GENERAL }
    );
  }
  if (payloadStr.includes("mediaKey")) {
    logger.debug(
      " *** Found 'mediaKey' - this is likely an image message ***",
      { category: LogCategory.GENERAL }
    );
  }
  if (payloadStr.includes("mmg.whatsapp.net")) {
    logger.debug(" *** Found encrypted WhatsApp media URL ***", {
      category: LogCategory.GENERAL,
    });
  }

  // Check if message is from me (outgoing) - ignore it
  if (message.key?.fromMe || message.fromMe) {
    logger.info("Ignoring outgoing message (fromMe=true)", {
      category: LogCategory.GENERAL,
    });
    return null;
  }

  // Extract phone number - PRIORITY ORDER per WaSend docs:
  // 1. key.cleanedSenderPn (recommended by WaSend for private chats)
  // 2. key.cleanedParticipantPn (for group chats)
  // 3. key.remoteJid (fallback, but check for LID format)
  // 4. Other fallbacks

  // First try the cleaned phone numbers (these are usually reliable)
  remoteJid = message.key?.cleanedSenderPn || message.key?.cleanedParticipantPn;

  // If not found, try remoteJid but validate it's not a LID
  if (!remoteJid && message.key?.remoteJid) {
    const jid = message.key.remoteJid;
    // LID format is like "520:123456@lid" - we can't use these
    if (!jid.includes(":") && !jid.includes("@lid")) {
      remoteJid = jid;
    } else {
      logger.info("Skipping LID format remoteJid:" + String(jid), {
        category: LogCategory.GENERAL,
      });
    }
  }

  // Fall back to other fields if still not found
  if (!remoteJid) {
    remoteJid =
      message.remoteJid || message.from || message.to || message.phone;
  }

  logger.info("Extracted remoteJid:" + String(remoteJid), {
    category: LogCategory.GENERAL,
  });

  // Extract text content - PRIORITY ORDER per WaSend docs:
  // 1. messageBody (WaSend unified field for all message types including captions)
  // 2. message.conversation (raw text messages)
  // 3. Other fallbacks
  userMessage =
    message.messageBody ||
    message.message?.conversation ||
    message.message?.extendedTextMessage?.text ||
    message.message?.imageMessage?.caption ||
    message.message?.text ||
    message.text ||
    message.body ||
    message.content ||
    "";

  logger.info("Extracted userMessage: " + userMessage.substring(0, 100), {
    category: LogCategory.GENERAL,
  });

  // Get message ID for decryption
  const messageId = message.key?.id || message.id || `msg_${Date.now()}`;

  // Extract image URLs from WhatsApp media messages
  // WaSend provides encrypted URLs that need decryption via their API
  // Check MULTIPLE locations for imageMessage (WaSend payload variations)

  // Helper to process an imageMessage object
  const processImageMessage = async (
    imgMsg: WaSendImageMessage,
    source: string
  ) => {
    const rawUrl = imgMsg.url;
    logger.info(
      `Image: Found in ${source}, URL: ${rawUrl?.substring(0, 80) || "none"}`,
      { category: LogCategory.IMAGE }
    );
    logger.info(
      `Image: Has mediaKey: ${!!imgMsg.mediaKey}, mimetype: ${imgMsg.mimetype || "unknown"}`,
      { category: LogCategory.IMAGE }
    );

    if (rawUrl) {
      // Check if this is an encrypted WhatsApp URL that needs decryption
      if (needsDecryption(rawUrl) && imgMsg.mediaKey) {
        logger.info("Image: Decrypting via WaSend API...", {
          category: LogCategory.IMAGE,
        });
        const decryptedUrl = await decryptWhatsAppImage(messageId, {
          url: rawUrl,
          mimetype: imgMsg.mimetype || "image/jpeg",
          mediaKey: imgMsg.mediaKey,
          fileSha256: imgMsg.fileSha256,
          fileLength: imgMsg.fileLength?.toString(),
        });
        if (decryptedUrl) {
          logger.info(
            `Image: Decryption successful! Public URL: ${decryptedUrl.substring(0, 80)}`,
            { category: LogCategory.IMAGE }
          );
          imageUrls.push(decryptedUrl);
        } else {
          logger.info(
            "Image: Decryption failed - marking imageDetectedButFailed",
            { category: LogCategory.IMAGE }
          );
          imageDetectedButFailed = true;
        }
      } else if (isPublicUrl(rawUrl)) {
        logger.info("Image: Already public URL", {
          category: LogCategory.IMAGE,
        });
        imageUrls.push(rawUrl);
      } else {
        logger.info(
          "Image: Encrypted but missing mediaKey - marking imageDetectedButFailed",
          { category: LogCategory.IMAGE }
        );
        imageDetectedButFailed = true;
      }
    }
  };

  // Location 1: message.message.imageMessage (standard WaSend format)
  if (message.message?.imageMessage) {
    await processImageMessage(
      message.message.imageMessage,
      "message.message.imageMessage"
    );
  }

  // Location 2: message.imageMessage directly (some WaSend variations)
  if (message.imageMessage && !message.message?.imageMessage) {
    await processImageMessage(message.imageMessage, "message.imageMessage");
  }

  // Location 3: data.imageMessage (if message IS the data object)
  if (message.data?.imageMessage && !message.message?.imageMessage) {
    await processImageMessage(
      message.data.imageMessage,
      "message.data.imageMessage"
    );
  }

  // Location 4-5: Fallback checks — ONLY if no images found from primary locations above
  // WaSender often provides the same image in multiple payload fields (imageMessage + mediaUrl),
  // but with different URLs (encrypted vs pre-decrypted). Skip fallbacks to avoid double-counting.
  if (imageUrls.length === 0) {
    // Location 4: Check if WaSend provides decryptedMediaUrl directly
    if (message.decryptedMediaUrl || message.message?.decryptedMediaUrl) {
      const url =
        message.decryptedMediaUrl || message.message?.decryptedMediaUrl;
      logger.info(`Image: Found decryptedMediaUrl: ${url?.substring(0, 80)}`, {
        category: LogCategory.IMAGE,
      });
      if (url && isPublicUrl(url)) {
        imageUrls.push(url);
      }
    }

    // Location 5: Check mediaUrl field (some webhook formats)
    if (message.mediaUrl && !imageUrls.includes(message.mediaUrl)) {
      logger.info(
        `Image: Found mediaUrl: ${message.mediaUrl.substring(0, 80)}`,
        { category: LogCategory.IMAGE }
      );
      if (isPublicUrl(message.mediaUrl)) {
        imageUrls.push(message.mediaUrl);
      }
    }
  }

  // Also check for document messages with images
  if (
    message.message?.documentMessage?.url &&
    message.message?.documentMessage?.mimetype?.startsWith("image/")
  ) {
    const docMsg = message.message.documentMessage;
    const rawUrl = docMsg.url;
    logger.info(
      "Found image in documentMessage, URL: " +
        (rawUrl?.substring(0, 80) || "none"),
      { category: LogCategory.GENERAL }
    );

    if (rawUrl) {
      if (needsDecryption(rawUrl) && docMsg.mediaKey) {
        logger.info("Decrypting document image via WaSend API...", {
          category: LogCategory.GENERAL,
        });
        const decryptedUrl = await decryptWhatsAppImage(messageId + "_doc", {
          url: rawUrl,
          mimetype: docMsg.mimetype,
          mediaKey: docMsg.mediaKey,
          fileSha256: docMsg.fileSha256,
          fileLength: docMsg.fileLength?.toString(),
          fileName: docMsg.fileName,
        });
        if (decryptedUrl) {
          logger.info("Document image decryption successful!", {
            category: LogCategory.GENERAL,
          });
          imageUrls.push(decryptedUrl);
        }
      } else if (isPublicUrl(rawUrl)) {
        imageUrls.push(rawUrl);
      }
    }
  }

  // Capture non-image document attachments (PDF, DOCX — e.g., title deeds)
  // These get persisted to Supabase Storage and tracked in pending_documents
  if (
    message.message?.documentMessage?.url &&
    !message.message?.documentMessage?.mimetype?.startsWith("image/")
  ) {
    const docMsg = message.message.documentMessage;
    const rawUrl = docMsg.url;
    const docMimetype = docMsg.mimetype || "application/octet-stream";
    const docFilename = docMsg.fileName || undefined;

    logger.info("Found non-image document attachment", {
      category: LogCategory.GENERAL,
      operation: "extractMessage",
      mimetype: docMimetype,
      filename: docFilename,
    });

    if (rawUrl) {
      let documentUrl: string | null = null;

      if (needsDecryption(rawUrl) && docMsg.mediaKey) {
        logger.info("Decrypting document via WaSend API...", {
          category: LogCategory.GENERAL,
        });
        documentUrl = await decryptWhatsAppImage(messageId + "_doc", {
          url: rawUrl,
          mimetype: docMimetype,
          mediaKey: docMsg.mediaKey,
          fileSha256: docMsg.fileSha256,
          fileLength: docMsg.fileLength?.toString(),
          fileName: docFilename,
        });
      } else if (isPublicUrl(rawUrl)) {
        documentUrl = rawUrl;
      }

      if (documentUrl) {
        // Persist to Supabase Storage for stable URL
        const persistedUrl = await persistDocument(
          documentUrl,
          docFilename,
          docMimetype
        );
        if (persistedUrl) {
          const phoneNumber =
            remoteJid?.split("@")[0]?.replace(/\D/g, "") || "";
          if (phoneNumber) {
            await addPendingDocument(
              phoneNumber,
              persistedUrl,
              docFilename,
              docMimetype
            );
          }

          // Use placeholder so AI knows a document was sent
          if (!userMessage || userMessage.trim() === "") {
            userMessage = `[User sent document: ${docFilename || "file"}]`;
          }
        }
      }
    }
  }

  // Support for test/simple webhook format with "media" array
  // Format: { from: "+123", body: "...", media: ["url1", "url2"] }
  // These are typically already public URLs from testing
  if (message.media && Array.isArray(message.media)) {
    for (const mediaUrl of message.media) {
      if (typeof mediaUrl === "string" && mediaUrl.startsWith("http")) {
        logger.info(
          "Found image URL in media array: " + mediaUrl.substring(0, 100),
          { category: LogCategory.GENERAL }
        );
        imageUrls.push(mediaUrl);
      }
    }
  }

  // Early image validation (before storage)
  let persistedImageUrls: string[] = [];
  if (imageUrls.length > 0) {
    logger.info("Validating images at ingress", {
      category: LogCategory.IMAGE,
      operation: "webhookImageValidation",
      imageCount: imageUrls.length,
    });

    const validation = await validateImagesAtIngress(imageUrls);

    // Log validation results
    if (validation.invalid.length > 0) {
      logger.warn("Some images failed validation at ingress", {
        category: LogCategory.IMAGE,
        operation: "webhookImageValidation",
        validCount: validation.valid.length,
        invalidCount: validation.invalid.length,
        invalidReasons: validation.invalid.map((i) => i.error),
      });
    }

    // Only persist valid images
    if (validation.valid.length > 0) {
      const validUrls = validation.valid.map((i) => i.url);
      logger.info(
        `Image: Persisting ${validUrls.length} valid image(s) to storage...`,
        { category: LogCategory.IMAGE }
      );
      const persistResults = await persistImages(validUrls);
      persistedImageUrls = persistResults.map((r) => r.url);

      if (persistResults.length > 0) {
        logger.info(
          `Image: Persisted ${persistResults.length} images to Supabase Storage`,
          { category: LogCategory.IMAGE }
        );

        // CRITICAL: Store images in pending_images table with content hash for dedup
        // Content hash prevents the same image from being stored twice even if
        // WhatsApp re-decrypts it into a different temporary URL
        const phoneNumber = remoteJid?.split("@")[0]?.replace(/\D/g, "") || "";
        if (phoneNumber) {
          logger.info("Storing images to pending queue with content hash", {
            category: LogCategory.IMAGE,
            count: persistResults.length,
          });
          await addPendingImages(
            phoneNumber,
            persistResults.map((r) => ({
              url: r.url,
              contentHash: r.contentHash,
            })),
            getContext().correlationId
          );
          logger.info("Images queued for property upload", {
            category: LogCategory.IMAGE,
            count: persistResults.length,
          });
        }
      } else if (validUrls.length > 0) {
        logger.warn("Image warning: Failed to persist any valid images", {
          category: LogCategory.IMAGE,
        });
      }
    }

    // If ALL images were invalid, send feedback to user
    if (validation.valid.length === 0 && validation.invalid.length > 0) {
      // Get the most helpful user message
      const userFeedback =
        validation.invalid[0].userMessage ||
        "These images could not be used. Please send photos directly from your phone gallery.";

      // Send feedback (this happens before AI processing)
      const phoneNumber = remoteJid?.split("@")[0]?.replace(/\D/g, "") || "";
      if (phoneNumber) {
        logger.info("Sending image validation feedback to user", {
          category: LogCategory.IMAGE,
          operation: "webhookImageValidation",
        });
        await sendTextMessage(phoneNumber, userFeedback);
      }
    }
  }

  if (!userMessage || userMessage.trim() === "") {
    // Allow messages with only images if they have a URL
    if (imageUrls.length > 0) {
      logger.info(
        "No text content but found images, using placeholder message",
        { category: LogCategory.GENERAL }
      );
      userMessage = "[User sent image(s)]";
    } else if (imageDetectedButFailed) {
      // Images were detected but decryption failed - don't drop the message!
      logger.info(
        "No text content, images detected but decryption failed - using failure placeholder",
        { category: LogCategory.GENERAL }
      );
      userMessage = "[User sent image(s) but decryption failed]";
    } else {
      logger.info("No text content found in message", {
        category: LogCategory.GENERAL,
      });
      return null;
    }
  }

  return { message, remoteJid, userMessage, imageUrls: persistedImageUrls };
}

/**
 * Generates a unique message key for deduplication
 */
export function generateMessageKey(message: WaSendMessage): string | null {
  // Try to extract a unique identifier from the message
  // Priority: message ID > key ID > timestamp + content hash

  if (message.key?.id) {
    return `key:${message.key.id}`;
  }

  if (message.id) {
    return `id:${message.id}`;
  }

  if (message.messageId) {
    return `msgid:${message.messageId}`;
  }

  // Fallback: create a hash from timestamp + first 50 chars of content
  const content =
    message.message?.conversation ||
    message.message?.extendedTextMessage?.text ||
    message.text ||
    message.body ||
    "";
  const timestamp = message.messageTimestamp || Date.now();

  if (content) {
    const contentHash = content.substring(0, 50).replace(/\s+/g, "_");
    return `hash:${timestamp}_${contentHash}`;
  }

  return null;
}

/**
 * Formats text for WhatsApp - converts markdown bold to WhatsApp bold, preserves phone masking
 * Phone masking format: XX**YYYY (e.g., 99**1111)
 * Converts **text** to *text* for WhatsApp bold formatting
 */
export function formatForWhatsApp(text: string): string {
  let formatted = text;

  // Step 0a: Strip code blocks (```...```) - show content as plain text
  // Handle multiline code blocks with optional language specifier
  formatted = formatted.replace(/```[\w]*\n?([\s\S]*?)```/g, "$1");
  // Handle inline code blocks (moved here for logical grouping)
  formatted = formatted.replace(/`([^`]+)`/g, "$1");

  // Step 0b: FIX single-asterisk phone masking (AI mistake) - convert 99*1111 to 99**1111
  // Pattern: 2 digits + single asterisk + 4 digits (but NOT already double asterisk)
  formatted = formatted.replace(/(\d{2})\*(\d{4})(?!\*)/g, "$1**$2");

  // Step 1: Protect phone masking patterns (XX**YYYY) with placeholder
  formatted = formatted.replace(/(\d{2})\*\*(\d{4})/g, "$1{{PHONE_MASK}}$2");

  // Step 2: Convert **text** markdown bold to *text* WhatsApp bold
  // This ensures field names requested by AI are properly bolded
  formatted = formatted.replace(/\*\*([^*]+)\*\*/g, "*$1*");

  // Step 3: Restore phone masking pattern
  formatted = formatted.replace(/\{\{PHONE_MASK\}\}/g, "**");

  // Step 4: Add WhatsApp bold (*text*) to specific document labels
  // Match label at start of line or after newline, with or without leading spaces
  formatted = formatted.replace(/^(\s*)(My Mobile:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Registration Details:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Property:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Client Information:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Property Introduced:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Property Link:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Viewing Arranged for:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Fees:)/gm, "$1*$2*");
  formatted = formatted.replace(/^(\s*)(Marketing Price:)/gm, "$1*$2*");

  // Step 5: Apply property description formatting to "Property Introduced" and "Property:" lines
  // This normalizes reg numbers to "Reg No.", title-cases locations, and handles Dimos
  formatted = formatted.replace(
    /^(\s*\*?Property Introduced:\*?\s*)(.+)$/gm,
    (_match, label, content) => `${label}${formatPropertyDescription(content)}`
  );
  formatted = formatted.replace(
    /^(\s*\*?Property:\*?\s*)(.+)$/gm,
    (_match, label, content) => `${label}${formatPropertyDescription(content)}`
  );

  // Remove header markers # Header -> Header
  formatted = formatted.replace(/^#{1,6}\s+/gm, "");
  // Clean up excessive whitespace but preserve single newlines
  formatted = formatted.replace(/[ \t]+/g, " ");
  formatted = formatted.replace(/\n{3,}/g, "\n\n");
  return formatted.trim();
}

/**
 * Parses CREA wording response into 3 separate messages
 * Message 1: Intro text
 * Message 2: The actual CREA wording (copy-pasteable) - with agent's landline auto-populated
 * Message 3: Important note about landline
 */
export function parseCREAResponse(
  text: string,
  agentLandline?: string
): string[] {
  const messages: string[] = [];

  // The CREA wording block that should be standalone
  // Auto-populate agent's landline if available
  const phoneLine = agentLandline
    ? `+357 ${agentLandline}`
    : "+357 (your land line) [optional]";

  const creaBlock = `Licensed Real Estate Agency
CREA Reg. No. 742 & CREA Lic. No. 378/E
CSC Zyprus Property Group LTD
${phoneLine}`;

  // Check if response contains the CREA block pattern
  const hasCreaCert =
    text.includes("Licensed Real Estate Agency") &&
    text.includes("CREA Reg") &&
    text.includes("CSC Zyprus");

  if (!hasCreaCert) {
    return [formatForWhatsApp(text)];
  }

  // Message 1: Intro
  const introText =
    "Of course. Here is the required CREA wording that should be added below each property post you make on social media or other online platforms:";
  messages.push(introText);

  // Message 2: The CREA wording block (standalone for copy-paste)
  messages.push(creaBlock);

  // Message 3: Important note
  const noteText =
    "Important Note: For professional compliance, it is recommended to use your Zyprus landline in online posts, which is already connected to your mobile phone, rather than your personal mobile number.";
  messages.push(noteText);

  logger.info("[CREA] Split into 3 messages for social media wording", {
    category: LogCategory.GENERAL,
  });
  return messages;
}

/**
 * Parses a template response into separate parts: Subject, Body, and Notes (if any)
 * Returns an array of message parts to be sent separately
 * @param text - The AI response text
 * @param agentLandline - Optional agent landline for CREA wording auto-population
 */
export function parseTemplateResponse(
  text: string,
  agentLandline?: string
): string[] {
  const messages: string[] = [];

  // Check for CREA wording response - split into 3 messages
  // Trigger if response contains the CREA block (Licensed Real Estate Agency + CREA Reg + CSC Zyprus)
  const lowerText = text.toLowerCase();
  const hasCreaBlock =
    lowerText.includes("licensed real estate agency") &&
    lowerText.includes("crea reg") &&
    lowerText.includes("csc zyprus");
  if (hasCreaBlock) {
    // This is a CREA wording response - split into 3 messages with agent's landline
    const creaSplit = parseCREAResponse(text, agentLandline);
    if (creaSplit.length > 1) {
      return creaSplit;
    }
  }

  // Check if this is a template response with Subject line
  if (!text.includes("Subject:")) {
    // Not a template - return as single message
    return [formatForWhatsApp(text)];
  }

  // Split by lines for easier processing
  const lines = text.split("\n");

  let subjectLine = "";
  const bodyLines: string[] = [];
  const noteLines: string[] = [];
  let inNote = false;

  for (const line of lines) {
    const trimmedLine = line.trim();

    // Extract Subject line (first line starting with "Subject:")
    if (trimmedLine.startsWith("Subject:") && !subjectLine) {
      subjectLine = trimmedLine;
      continue;
    }

    // ONLY these are separate notes - NOT "Looking forward", "For the confirmation", "Please confirm"
    // Only actual explicit notes/reminders get separated
    const lowerLine = trimmedLine.toLowerCase();
    if (
      lowerLine.startsWith("note:") ||
      lowerLine.startsWith("reminder:") ||
      lowerLine.startsWith("important:") ||
      lowerLine.startsWith("n.b.") ||
      lowerLine.startsWith("nb:") ||
      (lowerLine.includes("warning") && lowerLine.includes("reminder"))
    ) {
      inNote = true;
    }

    if (inNote) {
      noteLines.push(line);
    } else {
      bodyLines.push(line);
    }
  }

  // Add Subject as first message
  if (subjectLine) {
    messages.push(formatForWhatsApp(subjectLine));
  }

  // Add Body as second message (includes confirmation text, looking forward, etc.)
  const bodyText = bodyLines.join("\n").trim();
  if (bodyText) {
    messages.push(formatForWhatsApp(bodyText));
  }

  // Add Notes as third message ONLY if there's an actual Note/Reminder section
  const noteText = noteLines.join("\n").trim();
  if (noteText) {
    messages.push(formatForWhatsApp(noteText));
  }

  // If we somehow ended up with no messages, return original as single message
  if (messages.length === 0) {
    return [formatForWhatsApp(text)];
  }

  logger.info(
    `Parsed template into ${messages.length} parts: Subject="${subjectLine.substring(0, 50)}...", Body=${bodyText.length} chars, Notes=${noteText.length} chars`,
    { category: LogCategory.GENERAL }
  );

  return messages;
}

/**
 * My Notes Generator
 * Creates back-office notes for property listings
 *
 * My Notes contains only essential info for reviewers:
 * 1. Google Maps link (priority)
