/**
 * Get tool definitions for OpenRouter
 */
export function getToolDefinitions(): ToolDefinition[] {
  return TOOLS;
}

/**
 * Get tool by name
 */
export function getToolByName(name: string): ToolDefinition | undefined {
  return TOOLS.find((t) => t.function.name === name);
}

/**
 * Tool Argument Validation
 * Validates tool inputs against Zod schemas to prevent injection attacks (SEC-04)
 */

import { z } from "https://esm.sh/zod@3.22.4";
import { TOOL_SCHEMAS } from "./schemas.ts";

/**
 * Result of tool argument validation
 */
export type ValidationResult =
  | { valid: true; data: Record<string, unknown> }
  | { valid: false; error: string; issues?: string[] };

/**
 * Validates tool arguments against their Zod schema
 *
 * Prevents malicious payloads (negative numbers, oversized strings, SQL injection)
 * from reaching tool handlers by validating all inputs before execution.
 *
 * @param toolName - Name of the tool being called
 * @param args - Tool arguments from OpenRouter
 * @returns Validation result with typed data or error details
 *
 * @example
 * ```typescript
 * const result = validateToolArguments("createPropertyListing", {
 *   price: -1000,  // Invalid: negative price
 *   location: "Paphos"
 * });
 * if (!result.valid) {
 *   console.error(result.error, result.issues);
 *   // "Invalid arguments" ["price: Number must be greater than 0"]
 * }
 * ```
 */
export function validateToolArguments(
  toolName: string,
  args: Record<string, unknown>
): ValidationResult {
  // Look up schema for this tool
  const schema = TOOL_SCHEMAS[toolName];

  if (!schema) {
    return {
      valid: false,
      error: `Unknown tool: ${toolName}`,
    };
  }

  // Validate arguments against schema
  const result = schema.safeParse(args);

  if (result.success) {
    return {
      valid: true,
      data: result.data as Record<string, unknown>,
    };
  }

  // Extract validation issues for logging
  const issues = result.error.issues.map(
    (issue) => `${issue.path.join(".")}: ${issue.message}`
  );

  return {
    valid: false,
    error: "Invalid arguments",
    issues,
  };
}

/**
 * Tool Executor
 * Routes tool calls from OpenRouter to handler modules and returns results
 */

import type { Agent } from "../agents/identifier.ts";
import { RejectionError } from "../rules/reviewer-assignment.ts";
import {
  createTimer,
  trackDocumentGenerated,
  trackPropertyUploaded,
  trackToolUsed,
} from "../services/analytics.ts";
import {
  classifyError,
  getUserFriendlyMessage,
} from "../utils/error-mapper.ts";
import { LogCategory, logger } from "../utils/logger.ts";
import {
  handleCalculateCapitalGains,
  handleCalculateTransferFees,
  handleCalculateVAT,
} from "./handlers/calculators.ts";
import {
  handleExtractFromBazaraki,
  handleGetRegionalAgents,
  handleGetZyprusData,
} from "./handlers/data-retrieval.ts";
import { handleSendEmail } from "./handlers/email.ts";
import { handleCreateLandListing } from "./handlers/land-listing.ts";
import { handleCreatePropertyListing } from "./handlers/property-listing.ts";
import { validateToolArguments } from "./validation.ts";

export interface ToolResult {
  success?: boolean;
  error?: string;
  needsInput?: boolean;
  question?: string;
  message?: string;
  data?: unknown;
  retryable?: boolean;
}

export interface ToolCall {
  name: string;
  arguments: Record<string, unknown>;
}

/**
 * Execute a tool call with analytics tracking
 */
export async function executeTool(
  tool: ToolCall,
  agent: Agent | null,
  phoneNumber?: string
): Promise<ToolResult> {
  const timer = createTimer();

  logger.info("Tool execution started", {
    category: LogCategory.TOOL,
    toolName: tool.name,
    agentName: agent?.fullName,
  });

  // Validate tool arguments against schema (SEC-04)
  const validation = validateToolArguments(tool.name, tool.arguments);
  if (!validation.valid) {
    logger.warn("Tool validation failed", {
      category: LogCategory.TOOL,
      toolName: tool.name,
      error: validation.error,
      issues: validation.issues,
    });
    const detail = validation.issues?.length
      ? ` [${validation.issues.slice(0, 3).join("; ")}]`
      : "";
    return {
      error: `Invalid arguments for ${tool.name}: ${validation.error}${detail}`,
      retryable: true,
    };
  }

  // Use validated data (type-safe)
  const validArgs = validation.data;

  try {
    let result: ToolResult;

    switch (tool.name) {
      case "createPropertyListing":
        result = await handleCreatePropertyListing(
          validArgs,
          agent
        );
        // Track successful property upload
        if (result.success && phoneNumber) {
          trackPropertyUploaded(phoneNumber, agent?.id, {
            propertyType: validArgs.propertyType,
            location: validArgs.location,
          });
        }
        break;

      case "createLandListing":
        result = await handleCreateLandListing(
          validArgs,
          agent
        );
        // Track successful land upload
        if (result.success && phoneNumber) {
          trackPropertyUploaded(phoneNumber, agent?.id, {
            propertyType: "land",
            location: validArgs.location,
          });
        }
        break;

      case "getZyprusData":
        result = await handleGetZyprusData(validArgs);
        break;

      case "calculateVAT":
        result = handleCalculateVAT(validArgs);
        break;

      case "calculateTransferFees":
        result = handleCalculateTransferFees(validArgs);
        break;

      case "calculateCapitalGains":
        result = handleCalculateCapitalGains(validArgs);
        break;

      case "getRegionalAgents":
        result = await handleGetRegionalAgents(validArgs);
        break;

      case "extractFromBazaraki":
        result = await handleExtractFromBazaraki(validArgs);
        break;

      case "sendEmail":
        result = await handleSendEmail(validArgs, agent, phoneNumber);
        // Track document sent via email
        if (
          result.success &&
          phoneNumber &&
          (validArgs.attachmentUrl ||
            (result.data as Record<string, unknown>)?.attachedDocument)
        ) {
          trackDocumentGenerated(phoneNumber, "email_with_document", agent?.id);
        }
        break;

      default:
        logger.warn("Unknown tool requested", {
          category: LogCategory.TOOL,
          toolName: tool.name,
        });
        return { error: `Unknown tool: ${tool.name}` };
    }

    // Track tool usage (fire-and-forget)
    if (phoneNumber) {
      trackToolUsed(phoneNumber, tool.name, timer.end(), agent?.id, {
        success: result.success ?? !result.error,
      });
    }

    return result;
  } catch (error) {
    // Track tool error
    if (phoneNumber) {
      trackToolUsed(phoneNumber, tool.name, timer.end(), agent?.id, {
        success: false,
        error: error instanceof Error ? error.message : String(error),
      });
    }

    if (error instanceof RejectionError) {
      // RejectionError messages are already user-friendly
      return { error: error.message };
    }

    // Classify and log the error
    const errorObj = error instanceof Error ? error : new Error(String(error));
    const errorType = classifyError(errorObj);

    logger.error("Tool execution failed", errorObj, {
      category: LogCategory.TOOL,
      toolName: tool.name,
      errorType,
    });

    // Return user-friendly message
    const userMessage = getUserFriendlyMessage(errorType, `while ${tool.name}`);
    return { error: userMessage };
  }
}

/**
 * Reviewer Assignment Engine
 * Determines who reviews and owns listings based on business rules
 */

import type { Agent } from "../agents/identifier.ts";
import { REGIONAL_EMAILS } from "../config/business-rules.ts";

export interface ReviewerAssignment {
  reviewer1: string;
  reviewer2: string | null;
  listingOwner: string;
  listingInstructor: string;
}

export class RejectionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "RejectionError";
  }
}

/**
 * Assign reviewers based on property type, region, and agent
 *
 * Rules from documentation:
 * - FOR SALE (Paphos/Limassol/Larnaca/Nicosia):
 *   - Reviewer 1: listings@zyprus.com (Lauren)
 *   - Reviewer 2: request{region}@zyprus.com
 *
 * - FOR SALE (Famagusta only):
 *   - Reviewer 1: requestfamagusta@zyprus.com
 *   - Reviewer 2: NONE
 *
 * - FOR RENT (all regions):
 *   - Reviewer 1: Same as agent who sent it
 *   - Reviewer 2: NONE
 */
export function assignReviewers(
  agent: Agent,
  propertyType: "sale" | "rent",
  propertyRegion: string,
  assignTo?: string
): ReviewerAssignment {
  // SPECIAL CASE: Charalambos/Lauren (management) cannot do rentals via AI
  if (agent.role === "management" && propertyType === "rent") {
    throw new RejectionError(
      "Unfortunately you cannot use my services for adding rental properties. " +
        "Please send it to a normal regional agent."
    );
  }

  // SPECIAL CASE: Michelle rentals → Demetra
  // Michelle's communication email is limassol@zyprus.com
  // Spec 03_AGENT_ACCOUNTS.md line 154: Reviewer 2 = requestlimassol@zyprus.com
  if (
    agent.communicationEmail === "limassol@zyprus.com" &&
    propertyType === "rent"
  ) {
    return {
      reviewer1: "demetra@zyprus.com",
      reviewer2: "requestlimassol@zyprus.com",
      listingOwner: "demetra@zyprus.com",
      listingInstructor: "demetra@zyprus.com", // CRITICAL: Must be same as listingOwner
    };
  }

  // FOR RENT: Agent reviews their own listings
  if (propertyType === "rent") {
    return {
      reviewer1: agent.listingOwnerEmail,
      reviewer2: null,
      listingOwner: agent.listingOwnerEmail,
      listingInstructor: agent.listingOwnerEmail, // CRITICAL: Must be same as listingOwner
    };
  }

  // FOR SALE: Famagusta has special rules (only one reviewer)
  if (propertyRegion === "famagusta") {
    const listingOwner =
      assignTo ||
      (agent.listingOwnerEmail === "ASK"
        ? agent.communicationEmail
        : agent.listingOwnerEmail);

    return {
      reviewer1: "requestfamagusta@zyprus.com",
      reviewer2: null,
      listingOwner,
      listingInstructor: listingOwner, // Always same as listingOwner
    };
  }

  // FOR SALE: Standard regions (Paphos, Limassol, Larnaca, Nicosia)
  // When assignTo is provided, it always takes precedence (management assigns to specific agent)
  const listingOwner =
    assignTo ||
    (agent.listingOwnerEmail === "ASK"
      ? agent.communicationEmail
      : agent.listingOwnerEmail);

  return {
    reviewer1: "listings@zyprus.com",
    reviewer2: REGIONAL_EMAILS[propertyRegion] || null,
    listingOwner,
    listingInstructor: listingOwner, // Always same as listingOwner
  };
}

