/**
 * Region Validator
 * Enforces regional boundaries for property uploads
 */

import type { Agent } from "../agents/identifier.ts";
import { REGION_LOCATIONS } from "../config/business-rules.ts";
import { LogCategory, logger } from "../utils/logger.ts";

export interface ValidationResult {
  allowed: boolean;
  message?: string;
  propertyRegion?: string;
}

/**
 * Determine which region a location belongs to
 */
export function determineRegion(location: string): string | null {
  const normalizedLocation = location.toLowerCase().trim();

  // Return null early for empty strings to avoid false matches
  if (!normalizedLocation) {
    return null;
  }

  for (const [region, locations] of Object.entries(REGION_LOCATIONS)) {
    for (const loc of locations) {
      if (
        normalizedLocation.includes(loc) ||
        loc.includes(normalizedLocation)
      ) {
        return region;
      }
    }
  }

  // If no match, try to infer from partial matches
  if (
    normalizedLocation.includes("paphos") ||
    normalizedLocation.includes("pafos")
  ) {
    return "paphos";
  }
  if (
    normalizedLocation.includes("limassol") ||
    normalizedLocation.includes("lemesos")
  ) {
    return "limassol";
  }
  if (
    normalizedLocation.includes("larnaca") ||
    normalizedLocation.includes("larnaka")
  ) {
    return "larnaca";
  }
  if (
    normalizedLocation.includes("nicosia") ||
    normalizedLocation.includes("lefkosia")
  ) {
    return "nicosia";
  }
  if (
    normalizedLocation.includes("famagusta") ||
    normalizedLocation.includes("ammochostos")
  ) {
    return "famagusta";
  }

  return null;
}

/**
 * Validate if an agent is authorized to upload a property in a given location
 */
export function validateRegionalAccess(
  agent: Agent,
  propertyLocation: string
): ValidationResult {
  // Management can upload anywhere
  if (agent.region === "all") {
    const propertyRegion = determineRegion(propertyLocation);
    return {
      allowed: true,
      propertyRegion: propertyRegion || "unknown",
    };
  }

  // Determine property region
  const propertyRegion = determineRegion(propertyLocation);

  // If we can't determine the region, trust the agent (they know their region)
  if (!propertyRegion) {
    logger.debug(
      `[RegionValidator] Could not determine region for: ${propertyLocation}, trusting agent`,
      { category: LogCategory.GENERAL }
    );
    return {
      allowed: true,
      propertyRegion: agent.region,
    };
  }

  // Check if agent's region matches property region
  if (agent.region !== propertyRegion) {
    return {
      allowed: false,
      propertyRegion,
      message:
        "Unfortunately, you are not allowed to market a property outside your region. Please contact the relevant regional manager for assistance.",
    };
  }

  return {
    allowed: true,
    propertyRegion,
  };
}

/**
 * Validate if a management user can assign a property to a specific agent/region
 */
export function validateAssignment(
  propertyRegion: string,
  assigneeRegion: string
): ValidationResult {
  // If assignee can work anywhere (management), allow
  if (assigneeRegion === "all") {
    return { allowed: true };
  }

  // Check if assignee's region matches property region
  if (assigneeRegion !== propertyRegion) {
    return {
      allowed: false,
      message: `I'm not able to assign this ${propertyRegion} property to an agent in ${assigneeRegion}. Would you like me to assign it to a ${propertyRegion}-based agent instead?`,
    };
  }

  return { allowed: true };
}

/**
 * Get the regional office email for a region
 */
export function getRegionalOfficeEmail(region: string): string {
  const officeEmails: Record<string, string> = {
    paphos: "requestpaphos@zyprus.com",
    limassol: "requestlimassol@zyprus.com",
    larnaca: "requestlarnaca@zyprus.com",
    nicosia: "requestnicosia@zyprus.com",
    famagusta: "requestfamagusta@zyprus.com",
  };

  return officeEmails[region] || "listings@zyprus.com";
}

/**
 * Special Cases Handler
 * Handles edge cases and exceptions in the business rules
 */

import { type Agent, getAgentByEmail } from "../agents/identifier.ts";
import { REGIONAL_EMAILS } from "../config/business-rules.ts";

export interface UploadRequest {
  listingType: "sale" | "rent";
  location: string;
  assignTo?: string;
}

export interface SpecialCaseResult {
  proceed?: boolean;
  rejected?: boolean;
  needsInput?: boolean;
  question?: string;
  message?: string;
  modifiedRequest?: Partial<UploadRequest>;
}

/**
 * Get the region for an agent by their email (from database)
 */
export async function getAgentRegion(
  email: string
): Promise<string | null> {
  const agent = await getAgentByEmail(email);
  return agent?.region || null;
}

/**
 * Handle special cases before processing an upload request
 */
export async function handleSpecialCases(
  agent: Agent,
  request: UploadRequest,
  propertyRegion: string
): Promise<SpecialCaseResult> {
  // 1. Check if agent can upload (canUpload flag from database)
  if (!agent.canUpload) {
    return {
      rejected: true,
      message:
        "I'm not able to upload properties for you as you're not configured as a listing agent. " +
        "However, I can help you generate documents such as viewing forms or marketing agreements.",
    };
  }

  // 2. Management trying to do rentals
  if (agent.role === "management" && request.listingType === "rent") {
    return {
      rejected: true,
      message:
        "Unfortunately you cannot use my services for adding rental properties. " +
        "Please send it to a normal regional agent.",
    };
  }

  // 3. Management must specify assignment for sales
  if (
    agent.role === "management" &&
    agent.listingOwnerEmail === "ASK" &&
    request.listingType === "sale" &&
    !request.assignTo
  ) {
    return {
      needsInput: true,
      question:
        "To whom would you like me to assign this property as the listing owner? " +
        "Please provide the agent's name or email.",
    };
  }

  // 4. Management trying to assign to wrong region
  if (agent.role === "management" && request.assignTo) {
    const assignToLower = request.assignTo.toLowerCase().trim();

    // Check if this is a regional office email (requestpaphos@zyprus.com, etc.)
    const regionalOfficeRegion = Object.entries(REGIONAL_EMAILS).find(
      ([_, email]) => email === assignToLower
    )?.[0];

    if (regionalOfficeRegion) {
      // Regional office email — validate region matches property
      if (regionalOfficeRegion !== propertyRegion) {
        return {
          rejected: true,
          message:
            `I'm not able to assign this ${propertyRegion} property to the ${regionalOfficeRegion} office. ` +
            `Would you like me to assign it to the ${propertyRegion} office (${REGIONAL_EMAILS[propertyRegion]}) instead?`,
        };
      }
    } else {
      // Regular agent — validate from database
      const assigneeRegion = await getAgentRegion(
        request.assignTo
      );

      if (
        assigneeRegion &&
        assigneeRegion !== "all" &&
        assigneeRegion !== propertyRegion
      ) {
        return {
          rejected: true,
          message:
            `I'm not able to assign this ${propertyRegion} property to ${request.assignTo} ` +
            `as they are based in ${assigneeRegion}. ` +
            `Would you like me to assign it to a ${propertyRegion}-based agent instead?`,
        };
      }
    }
  }

  // 5. Michelle rentals special case - auto-reassign to Demetra
  if (
    agent.communicationEmail.toLowerCase() === "limassol@zyprus.com" &&
    request.listingType === "rent"
  ) {
    return {
      proceed: true,
      modifiedRequest: {
        assignTo: "demetra@zyprus.com",
      },
      message: "I'll assign this rental to Demetra as per company policy.",
    };
  }

  // No special case applies - proceed normally
  return { proceed: true };
}

/**
 * Check if an unknown sender needs identification
 */
export function handleUnknownSender(): SpecialCaseResult {
  return {
    needsInput: true,
    question:
      "I don't recognize your phone number in our system. " +
      "Could you please confirm who you are and your Zyprus email address?",
  };
}

/**
 * Validate that required fields are present
 */
export function validateRequiredFields(data: Record<string, unknown>): {
  valid: boolean;
  missing: string[];
} {
  const required = [
    "price",
    "propertyType",
    "location",
    "bedrooms",
    "coveredArea",
    "ownerName",
    "ownerPhone",
    "titleDeedStatus",
  ];

  // Bathrooms are required for all types EXCEPT residential buildings
  const propertyType = ((data.propertyType as string) || "").toLowerCase();
  if (!propertyType.includes("building")) {
    required.push("bathrooms");
  }

  const missing = required.filter(
    (field) =>
      data[field] === undefined || data[field] === null || data[field] === ""
  );

  return {
    valid: missing.length === 0,
    missing,
  };
}

/**
 * Get a friendly message for missing fields
 */
export function getMissingFieldsMessage(missing: string[]): string {
  const fieldNames: Record<string, string> = {
    price: "the price",
    propertyType: "the property type (apartment, house, villa, etc.)",
    location: "the location/area",
    bedrooms: "the number of bedrooms",
    bathrooms: "the number of bathrooms",
    coveredArea: "the covered area in square meters",
    ownerName: "the owner's name",
    ownerPhone: "the owner's phone number",
    titleDeedStatus: "the title deed status",
  };

  const friendlyNames = missing.map((f) => fieldNames[f] || f);

  if (friendlyNames.length === 1) {
    return `I still need ${friendlyNames[0]} to create the listing.`;
  }

  const last = friendlyNames.pop();
  return `I still need ${friendlyNames.join(", ")} and ${last} to create the listing.`;
}

/**
 * Email Format Rules - Single Source of Truth
 *
 * 3-message format for email templates.
 * This consolidates the email format rules that were duplicated
 * in 4+ locations across the codebase.
 *
 * ALL email format logic should import from here.
 */

/**
 * Email message parts structure
 */
export interface EmailParts {
  subject: string | null;
  body: string;
  reminder: string | null;
}

/**
 * Parse an email template response into its 3 parts
 *
 * @param response - AI response containing email template
 * @returns EmailParts with subject, body, and optional reminder
 */
export function parseEmailParts(response: string): EmailParts {
  const parts: EmailParts = {
    subject: null,
    body: response,
    reminder: null,
  };

  // Extract subject line
  const subjectMatch = response.match(/^Subject:\s*(.+?)(?:\n|$)/im);
  if (subjectMatch) {
    parts.subject = subjectMatch[1].trim();
  }

  // Extract body (everything between subject and reminder)
  let bodyStart = 0;
  let bodyEnd = response.length;

  if (subjectMatch) {
    bodyStart = subjectMatch.index! + subjectMatch[0].length;
  }

  // Check for reminder patterns at the end
  const reminderPatterns = [
    /\n\*?REMINDER:?\*?\s*.+$/i,
    /\n\*?Important Note:?\*?\s*.+$/i,
    /\n\*?Note:?\*?\s*Don't forget.+$/i,
    /\nDon't forget to attach.+$/i,
  ];

  for (const pattern of reminderPatterns) {
    const reminderMatch = response.match(pattern);
    if (reminderMatch) {
      parts.reminder = reminderMatch[0].trim();
      bodyEnd = reminderMatch.index!;
      break;
    }
  }

  // Extract body
  parts.body = response.substring(bodyStart, bodyEnd).trim();

  return parts;
}

/**
 * Split an email response into separate messages for WhatsApp
 *
 * @param response - AI response containing email template
 * @returns Array of message strings (1-3 messages)
 */
export function splitEmailIntoMessages(response: string): string[] {
  const parts = parseEmailParts(response);
  const messages: string[] = [];

  // Message 1: Subject line only (if present)
  if (parts.subject) {
    messages.push(`Subject: ${parts.subject}`);
  }

  // Message 2: Body only
  if (parts.body) {
    messages.push(parts.body);
  }

  // Message 3: Reminder only (if present)
  if (parts.reminder) {
    messages.push(parts.reminder);
  }

  // If no parts were extracted, return original as single message
  if (messages.length === 0) {
    return [response];
  }

  return messages;
}

/**
 * Check if a response contains an email template (has Subject: line)
 */
export function isEmailTemplate(response: string): boolean {
  return /^Subject:/im.test(response);
}

