            width: { size: 50, type: WidthType.PERCENTAGE },
            children: [
              new Paragraph({
                children: rightPerson
                  ? [
                      new TextRun({
                        text: "Name: ",
                        bold: true,
                        size: FONTS.SIZES.BODY,
                        font: FONTS.PRIMARY,
                      }),
                      new TextRun({
                        text: createSignatureLine(20),
                        size: FONTS.SIZES.BODY,
                        font: FONTS.PRIMARY,
                      }),
                    ]
                  : [],
                spacing: { before: 600, after: 300 },
              }),
            ],
          }),
        ],
      })
    );

    // Signature row
    signatureRows.push(
      new TableRow({
        children: [
          new TableCell({
            borders: noBorders,
            width: { size: 50, type: WidthType.PERCENTAGE },
            children: [
              new Paragraph({
                children: [
                  new TextRun({
                    text: "Signature: ",
                    bold: true,
                    size: FONTS.SIZES.BODY,
                    font: FONTS.PRIMARY,
