/**
 * Creates an advanced viewing form document with legal paragraph
 */
export function createViewingFormAdvanced(
  data: ViewingFormAdvancedData,
  logoData?: Uint8Array,
  logoType: "jpg" | "png" = "png"
): Document {
  const dateStr = data.date || formatDate();
  const isSingle = data.persons.length === 1;

  const children: Paragraph[] = [];

  // Logo - Zyprus viewing form logo
  if (logoData && logoData.length > 0) {
    children.push(
      new Paragraph({
        children: [
          new ImageRun({
            data: logoData,
            transformation: {
              width: 120,
              height: 62,
            },
            type: logoType,
          }),
        ],
        alignment: AlignmentType.LEFT,
        spacing: { after: SPACING.TITLE_AFTER },
      })
    );
  }

  // Title: "Viewing Form" - centered, bold
  children.push(
    new Paragraph({
      children: [
        new TextRun({
          text: "Viewing Form",
          bold: true,
          size: FONTS.SIZES.TITLE,
          font: FONTS.PRIMARY,
          underline: { type: UnderlineType.SINGLE },
        }),
      ],
      alignment: AlignmentType.CENTER,
      spacing: { after: SPACING.TITLE_AFTER },
    })
  );

  // Empty line
  children.push(new Paragraph({ text: "" }));

  // Date line - plain text, no bold
  children.push(
    new Paragraph({
      children: [
        new TextRun({
          text: `Date: ${dateStr}`,
          size: FONTS.SIZES.BODY,
          font: FONTS.PRIMARY,
        }),
      ],
    })
  );

  // Empty line
  children.push(new Paragraph({ text: "" }));

  // Build declaration with bold placeholder fields
  const verb = isSingle ? "me" : "us";
  const declarationRuns: TextRun[] = [];
  data.persons.forEach((p, idx) => {
    const prefix = idx === 0 ? "Herein, I " : " and I ";
    declarationRuns.push(new TextRun({ text: prefix, size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));
    declarationRuns.push(new TextRun({ text: p.fullName, bold: isPlaceholder(p.fullName), size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));
    declarationRuns.push(new TextRun({ text: " with ID ", size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));
    declarationRuns.push(new TextRun({ text: p.idNumber, bold: isPlaceholder(p.idNumber), size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));
    declarationRuns.push(new TextRun({ text: ", Issued By: ", size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));
    declarationRuns.push(new TextRun({ text: p.issuedBy, bold: isPlaceholder(p.issuedBy), size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));
  });
  declarationRuns.push(new TextRun({ text: ` confirm that ${COMPANY.FULL_REFERENCE}, has introduced to ${verb} with a viewing and/or digitally the property with the following Registry details:`, size: FONTS.SIZES.BODY, font: FONTS.PRIMARY }));

  children.push(
    new Paragraph({
      children: declarationRuns,
    })
  );

  // Empty line
  children.push(new Paragraph({ text: "" }));

  // Property line
  const rawProp = data.property.rawDescription || [
    data.property.registrationNo ? `registration no ${data.property.registrationNo}` : '',
    data.property.municipality, data.property.district, data.property.locality,
  ].filter(Boolean).join(" ");
  const propertyDescription = formatPropertyDescription(rawProp);
  children.push(
    new Paragraph({
      children: [
        new TextRun({
          text: "Property:",
          bold: true,
          size: FONTS.SIZES.BODY,
          font: FONTS.PRIMARY,
        }),
        ...(propertyDescription
          ? [
              new TextRun({
                text: ` ${propertyDescription}`,
                bold: isPlaceholder(propertyDescription),
                size: FONTS.SIZES.BODY,
                font: FONTS.PRIMARY,
              }),
            ]
          : []),
      ],
    })
  );

  // Empty line
  children.push(new Paragraph({ text: "" }));

  // Legal paragraph - plain text, no box/border (matches reference)
  children.push(
    new Paragraph({
      children: [
        new TextRun({
          text: LEGAL_TEXT.ADVANCED_VIEWING,
          size: FONTS.SIZES.BODY,
          font: FONTS.PRIMARY,
        }),
      ],
    })
  );

  // Signatures as simple paragraphs (not table), no bold labels (matches reference)
  for (const _person of data.persons) {
    // Space before each signature block
    children.push(new Paragraph({ text: "", spacing: { after: 400 } }));

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: `Name: ${createSignatureLine(25)}`,
            size: FONTS.SIZES.BODY,
            font: FONTS.PRIMARY,
          }),
        ],
        spacing: { after: 400 },
      })
    );

    children.push(
      new Paragraph({
        children: [
          new TextRun({
            text: `Signature: ${createSignatureLine(25)}`,
            size: FONTS.SIZES.BODY,
            font: FONTS.PRIMARY,
          }),
        ],
        spacing: { after: 200 },
      })
    );
  }

  return new Document({
    sections: [{
      children,
    }],
  });
}

