/**
 * Create a new caller alert.
 * Uses INSERT with unique constraint to prevent duplicate alerts per caller/run.
 *
 * @returns CallerAlert if created, null if duplicate
 */
export const createCallerAlert = async (
  params: CreateCallerAlertParams
): Promise<CallerAlert | null> => {
  const supabase = getSupabaseAdmin();

  try {
    const { data, error } = await supabase
      .from("caller_alerts")
      .insert([
        {
          caller_phone: params.caller_phone,
          audit_run_id: params.audit_run_id,
          call_record_id: params.call_record_id || null,
          status: params.status || "pending",
          call_time: params.call_time || null,
          chat_id: params.chat_id || null,
        },
      ])
      .select()
      .single();

    if (error) {
      // Unique constraint violation - alert already exists for this caller + run
      if (error.code === "23505") {
        logger.info("Caller alert already exists", {
          category: LogCategory.DATABASE,
          operation: "createCallerAlert",
          callerPhone: params.caller_phone,
        });
        return null;
      }

      logger.error("Error creating caller alert", error, {
        category: LogCategory.DATABASE,
        operation: "createCallerAlert",
        callerPhone: params.caller_phone,
      });
      throw error;
    }

    logger.info("Caller alert created", {
      category: LogCategory.DATABASE,
      operation: "createCallerAlert",
      alertId: data.id,
      callerPhone: params.caller_phone,
    });

    return data as CallerAlert;
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error("Exception creating caller alert", err, {
      category: LogCategory.DATABASE,
      operation: "createCallerAlert",
    });
    throw err;
  }
};

/**
 * Update alert status with appropriate timestamp logic
 */
export const updateAlertStatus = async (
  alertId: string,
  params: UpdateAlertStatusParams
): Promise<void> => {
  const supabase = getSupabaseAdmin();

  const now = new Date().toISOString();
  const updates: Record<string, unknown> = {
    status: params.status,
    updated_at: now,
  };

  // Set appropriate timestamps based on status
  if (params.status === "alerted" && !params.alert_message_id) {
    updates.alerted_at = now;
  }
  if (params.status === "follow_up_sent") {
    updates.follow_up_at = now;
  }
  if (params.status === "resolved" || params.status === "ignored") {
    updates.resolved_at = now;
  }

  // Add optional fields
  if (params.alert_message_id)
    updates.alert_message_id = params.alert_message_id;
  if (params.follow_up_message_id)
    updates.follow_up_message_id = params.follow_up_message_id;
  if (params.chat_id) updates.chat_id = params.chat_id;
  if (params.resolution_type) updates.resolution_type = params.resolution_type;
  if (params.resolution_note) updates.resolution_note = params.resolution_note;
  if (params.alternative_phone)
    updates.alternative_phone = params.alternative_phone;

  const { error } = await withRetry(
    async () => {
      const result = await supabase
        .from("caller_alerts")
        .update(updates)
        .eq("id", alertId);

      if (result.error) throw result.error;
      return result;
    },
    { maxRetries: 2, baseDelayMs: 200 },
    "updateAlertStatus"
  );

  if (error) {
    logger.error("Error updating alert status", error, {
      category: LogCategory.DATABASE,
      operation: "updateAlertStatus",
      alertId,
      status: params.status,
    });
    throw error;
  }

  logger.info("Alert status updated", {
    category: LogCategory.DATABASE,
    operation: "updateAlertStatus",
    alertId,
    status: params.status,
  });
};

/**
 * Get all unresolved alerts (pending, alerted, follow_up_sent)
 */
export const getUnresolvedAlerts = async (): Promise<CallerAlert[]> => {
  const supabase = getSupabaseAdmin();

  const { data, error } = await supabase
    .from("caller_alerts")
    .select("*")
    .in("status", ["pending", "alerted", "follow_up_sent"])
    .order("created_at", { ascending: true });

  if (error) {
    logger.error("Error fetching unresolved alerts", error, {
      category: LogCategory.DATABASE,
      operation: "getUnresolvedAlerts",
    });
    throw error;
  }

  return (data || []) as CallerAlert[];
};

/**
 * Get alerts pending follow-up (alerted > N hours ago, no follow-up sent yet)
 */
export const getPendingFollowUps = async (
  hoursThreshold = 24
): Promise<CallerAlert[]> => {
  const supabase = getSupabaseAdmin();

  const thresholdTime = new Date(
    Date.now() - hoursThreshold * 60 * 60 * 1000
  ).toISOString();

  const { data, error } = await supabase
    .from("caller_alerts")
    .select("*")
    .eq("status", "alerted")
    .lt("alerted_at", thresholdTime)
    .order("alerted_at", { ascending: true });

  if (error) {
    logger.error("Error fetching pending follow-ups", error, {
      category: LogCategory.DATABASE,
      operation: "getPendingFollowUps",
      hoursThreshold,
    });
    throw error;
  }

  return (data || []) as CallerAlert[];
};

/**
 * Get a specific alert by caller phone and audit run
 */
export const getAlertByPhone = async (
  callerPhone: string,
  auditRunId: string
): Promise<CallerAlert | null> => {
  const supabase = getSupabaseAdmin();

  const { data, error } = await supabase
    .from("caller_alerts")
    .select("*")
    .eq("caller_phone", callerPhone)
    .eq("audit_run_id", auditRunId)
    .single();

  if (error || !data) {
    if (error && error.code !== "PGRST116") {
      logger.error("Error fetching alert by phone", error, {
        category: LogCategory.DATABASE,
        operation: "getAlertByPhone",
        callerPhone,
      });
    }
    return null;
  }

  return data as CallerAlert;
};

/**
 * Sentry Error Tracking for Deno Edge Functions
 *
 * Provides centralized error tracking and monitoring for SOPHIA Edge Functions.
 * Captures production errors with stack traces, user context, and breadcrumbs.
 *
 * Features:
 * - Deno-compatible Sentry SDK via esm.sh CDN
 * - Environment-based configuration (production vs development)
 * - User context (phone number, agent ID) for debugging
 * - Breadcrumb trail showing request flow before errors
 * - No hardcoded DSN (uses environment variable)
 *
 * Related: AI-PRODUCTION-AUDIT.md findings #20, #53
 */

import * as Sentry from "https://esm.sh/@sentry/deno@8.40.0";

// Track initialization state
let sentryInitialized = false;

/**
 * Initialize Sentry for Edge Function error tracking
 *
 * Should be called once at module load time (top-level in index.ts).
 * Safe to call multiple times - will only initialize once.
 *
 * Configuration:
 * - DSN from SENTRY_DSN environment variable
 * - Environment auto-detected from DENO_DEPLOYMENT_ID
 * - 10% traces sampling in production
 * - Release tag from deployment ID when available
 *
 * @example
 * ```typescript
 * // In index.ts (top-level, before Deno.serve)
 * import { initSentry } from "../_shared/sentry.ts";
 * initSentry(); // Initialize Sentry for error tracking (OBS-01)
 * ```
 */
export function initSentry(): void {
  // Prevent double initialization
  if (sentryInitialized) {
    return;
  }

  const sentryDsn = Deno.env.get("SENTRY_DSN");
  const deploymentId = Deno.env.get("DENO_DEPLOYMENT_ID");
  const isProduction = !!deploymentId;

  // Only initialize if DSN is configured
  if (!sentryDsn) {
    console.warn(
      "[Sentry] SENTRY_DSN not configured - error tracking disabled"
    );
    return;
  }

  try {
    Sentry.init({
      dsn: sentryDsn,
      environment: isProduction ? "production" : "development",
      enabled: isProduction, // Only enabled in production
      tracesSampleRate: 0.1, // 10% sampling to match edge config
      release: deploymentId || undefined, // Tag releases with deployment ID
      debug: false, // No debug logs in production
      // Attach stack traces for error events
      attachStacktrace: true,
      // Capture unhandled rejections
      integrations: [
        Sentry.denoIntegration(),
      ],
    });

    sentryInitialized = true;
    console.log(
      `[Sentry] Initialized for ${isProduction ? "production" : "development"} environment`
    );
  } catch (error) {
    console.error("[Sentry] Failed to initialize:", error);
  }
}

/**
 * Capture an error and send to Sentry with contextual information
 *
 * Enriches error with user context (phone number, agent ID) and tags
 * (channel, correlation ID) for easier debugging in production.
 *
 * @param error - Error instance to capture
 * @param context - Optional context with user/request metadata
 *
 * Context fields:
 * - phoneNumber: User's WhatsApp phone number (sets Sentry user ID)
 * - agentId: Zyprus agent UUID (helps filter by agent)
 * - correlationId: Request correlation ID for tracing
 * - channel: Communication channel (whatsapp, telegram, etc.)
 * - Any other custom fields
 *
 * @example
 * ```typescript
 * try {
 *   await riskyOperation();
 * } catch (error) {
 *   captureError(error as Error, {
 *     phoneNumber,
 *     agentId: agent?.id,
 *     correlationId,
 *     channel: "whatsapp"
 *   });
 *   logger.error("Operation failed", error); // Still log normally
 * }
 * ```
 */
export function captureError(
  error: Error,
  context?: Record<string, unknown>
): void {
  if (!sentryInitialized) {
    // Sentry not initialized - skip silently
    return;
  }

  try {
    // Set user context if phone number provided
    if (context?.phoneNumber) {
      Sentry.setUser({
        id: String(context.phoneNumber),
        // Don't send actual phone number to Sentry (PII)
        // The ID is hashed and used for grouping
      });
    }

    // Set agent ID as tag if provided
    if (context?.agentId) {
      Sentry.setTag("agent_id", String(context.agentId));
    }

    // Set correlation ID for request tracing
    if (context?.correlationId) {
      Sentry.setTag("correlation_id", String(context.correlationId));
    }

    // Set channel tag (whatsapp, telegram, etc.)
    if (context?.channel) {
      Sentry.setTag("channel", String(context.channel));
    }

    // Add any additional context as extras
    if (context) {
      const extras = { ...context };
      // Remove fields already set as user/tags
      delete extras.phoneNumber;
      delete extras.agentId;
      delete extras.correlationId;
      delete extras.channel;

      if (Object.keys(extras).length > 0) {
        Sentry.setExtras(extras);
      }
    }

    // Capture the error
    Sentry.captureException(error);
  } catch (sentryError) {
    // Don't let Sentry errors break the application
    console.error("[Sentry] Failed to capture error:", sentryError);
  }
}

/**
 * Add a breadcrumb to track request flow before errors
 *
 * Breadcrumbs create a trail of events leading up to an error, making
 * debugging much easier. They show what the user did and what the system
 * processed before something went wrong.
 *
 * @param message - Human-readable description of the event
 * @param category - Breadcrumb category for filtering
 * @param data - Optional structured data about the event
 *
 * Categories:
 * - http: HTTP requests/responses (webhook received, API called)
 * - ai: AI operations (model called, response received)
 * - tool: Tool executions (tool name, arguments)
 * - database: Database operations (query, insert, update)
 * - user: User actions (message sent, button clicked)
 *
 * @example
 * ```typescript
 * // At webhook entry point
 * addBreadcrumb("WhatsApp webhook received", "http", {
 *   correlationId,
 *   phoneNumber: "[REDACTED]"
 * });
 *
 * // Before AI call
 * addBreadcrumb("Calling OpenRouter", "ai", {
 *   model: "google/gemini-3-flash-preview"
 * });
 *
 * // After tool execution
 * addBreadcrumb("Tool executed", "tool", {
 *   toolName: "createPropertyListing",
 *   success: true
 * });
 * ```
 */
export function addBreadcrumb(
  message: string,
  category: string,
  data?: Record<string, unknown>
): void {
  if (!sentryInitialized) {
    // Sentry not initialized - skip silently
    return;
  }

  try {
    Sentry.addBreadcrumb({
      message,
      category,
      level: "info",
      timestamp: Date.now() / 1000, // Sentry expects seconds
      data: data || {},
    });
  } catch (sentryError) {
    // Don't let Sentry errors break the application
    console.error("[Sentry] Failed to add breadcrumb:", sentryError);
  }
}

/**
 * Deno-compatible Telegram Bot API Client
 *
 * Minimal client for Edge Functions (sophia-bot, call-auditor, etc.).
 * Ported from lib/telegram/client.ts — no Node.js deps (no Buffer, no "server-only").
 *
 * Phase 12, Plan 01
 */

import { LogCategory, logger } from "../sophia-bot/utils/logger.ts";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SendMessageParams {
  chatId: number | string;
  text: string;
  replyToMessageId?: number;
  parseMode?: "Markdown" | "HTML" | "MarkdownV2";
}

export interface ChatInfo {
  id: number;
  type: "private" | "group" | "supergroup" | "channel";
  title?: string;
  username?: string;
  first_name?: string;
  last_name?: string;
}

// ---------------------------------------------------------------------------
// Client
// ---------------------------------------------------------------------------

export class TelegramBotClient {
  private readonly apiUrl: string;

  constructor(botToken: string) {
    if (!botToken) {
      throw new Error("TELEGRAM_BOT_TOKEN is required");
    }
    this.apiUrl = `https://api.telegram.org/bot${botToken}`;
  }

  /**
   * Send a text message to a Telegram chat.
   */
  async sendMessage({
    chatId,
    text,
    replyToMessageId,
    parseMode,
  }: SendMessageParams): Promise<unknown> {
    const body: Record<string, unknown> = {
      chat_id: chatId,
      text,
    };

    if (parseMode) {
      body.parse_mode = parseMode;
    }

    if (replyToMessageId) {
      body.reply_to_message_id = replyToMessageId;
    }

    const response = await fetch(`${this.apiUrl}/sendMessage`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });

    const data = await response.json();

    if (!data.ok) {
      logger.error(
        "Telegram sendMessage error",
        new Error(data.description ?? "Unknown error"),
        {
          category: LogCategory.GENERAL,
          chatId: String(chatId),
          errorCode: data.error_code,
        }
      );
      throw new Error(data.description || "Failed to send message");
    }

    return data.result;
  }

  /**
   * Get information about a chat (group, supergroup, private, or channel).
   */
  async getChat(chatId: number | string): Promise<ChatInfo | null> {
    try {
      const response = await fetch(`${this.apiUrl}/getChat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ chat_id: chatId }),
      });

      const data = await response.json();

      if (!data.ok) {
        logger.error(
          "Telegram getChat error",
          new Error(data.description ?? "Unknown error"),
          {
            category: LogCategory.GENERAL,
            chatId: String(chatId),
          }
        );
        return null;
      }

      return data.result as ChatInfo;
    } catch (error) {
      logger.error(
        "Error getting chat info",
        error instanceof Error ? error : new Error(String(error)),
        { category: LogCategory.GENERAL, chatId: String(chatId) }
      );
      return null;
    }
  }
}

// ---------------------------------------------------------------------------
// Singleton factory
// ---------------------------------------------------------------------------

let _instance: TelegramBotClient | null = null;

/**
 * Get the singleton Telegram bot client.
 * Reads TELEGRAM_BOT_TOKEN from Deno.env on first call.
 */
export function getTelegramBot(): TelegramBotClient {
  if (!_instance) {
    const token = Deno.env.get("TELEGRAM_BOT_TOKEN");
    if (!token) {
      throw new Error(
        "TELEGRAM_BOT_TOKEN env var is not set. Get your token from @BotFather on Telegram."
      );
    }
    _instance = new TelegramBotClient(token);
  }
  return _instance;
}

/**
 * Telegram Alert Sending Service
 *
 * Posts formatted missing-caller alerts to the "Zypress Others" Telegram group.
 * Used by the call audit pipeline when phone numbers aren't found in any
 * regional group's indexed messages.
 *
 * Phase 12, Plan 02
 */

import { LogCategory, logger } from "../sophia-bot/utils/logger.ts";
import { getTelegramBot } from "./telegram.ts";
import { ZYPRESS_OTHERS_CHAT_ID } from "./telegram-search.ts";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface MissingCallerInfo {
  phoneNumber: string;
  callTime: string; // HH:MM format
  callDate: string; // YYYY-MM-DD format
  searchedGroups: string[]; // Names of groups searched
}

// ---------------------------------------------------------------------------
// Phone Number Formatting
// ---------------------------------------------------------------------------

/**
 * Format a phone number for display with spaces for readability.
 *
 * Examples:
 *   +35722123456  -> +357 22 123 456
 *   35799123456   -> +357 99 123 456
 *   22123456      -> 22 123 456
 *   +4412345678   -> +44 1234 5678
 */
function formatPhoneDisplay(phone: string): string {
  // Strip all non-digit and non-plus characters
  const cleaned = phone.replace(/[^\d+]/g, "");

  // If it's a Cyprus number with +357 prefix
  if (cleaned.startsWith("+357") && cleaned.length === 12) {
    const local = cleaned.slice(4); // 8 digits
    return `+357 ${local.slice(0, 2)} ${local.slice(2, 5)} ${local.slice(5)}`;
  }

  // If it starts with 357 but no +, add it
  if (cleaned.startsWith("357") && cleaned.length === 11) {
    const local = cleaned.slice(3);
    return `+357 ${local.slice(0, 2)} ${local.slice(2, 5)} ${local.slice(5)}`;
  }

  // Local Cyprus number (8 digits starting with 2x or 9x or 7x)
  if (/^\d{8}$/.test(cleaned)) {
    return `${cleaned.slice(0, 2)} ${cleaned.slice(2, 5)} ${cleaned.slice(5)}`;
  }

  // Fallback: return as-is with + prefix if it looks international
  if (cleaned.startsWith("+")) {
    return cleaned;
  }

  return cleaned;
}

// ---------------------------------------------------------------------------
// Message Formatting
// ---------------------------------------------------------------------------

/**
 * Format a missing-caller alert message for Telegram.
 */
export function formatMissingCallerAlert(call: MissingCallerInfo): string {
  const displayPhone = formatPhoneDisplay(call.phoneNumber);
  const groupList =
    call.searchedGroups.length > 0
      ? call.searchedGroups.join(", ")
      : "all regional groups";

  return [
    "\u26a0\ufe0f MISSING CALLER ALERT",
    "",
    `Phone: ${displayPhone}`,
    `Call Time: ${call.callTime}`,
    `Date: ${call.callDate}`,
    "",
    "This number was NOT found in any regional Telegram group.",
    `Groups searched: ${groupList}`,
    "",
    "Please check if this caller has been attended to.",
  ].join("\n");
}

/**
 * Format a follow-up reminder for an unresolved alert.
 */
export function formatFollowUpReminder(
  call: MissingCallerInfo,
  daysSinceAlert: number
): string {
  const displayPhone = formatPhoneDisplay(call.phoneNumber);

  return [
    "\ud83d\udd14 REMINDER: Unresolved Missing Caller",
    "",
    `Phone: ${displayPhone}`,
    `Original Call: ${call.callDate} at ${call.callTime}`,
    `Days since alert: ${daysSinceAlert}`,
    "",
    "This caller has not been confirmed as attended to.",
    "Please respond if this number has been handled.",
  ].join("\n");
}

// ---------------------------------------------------------------------------
// Alert Sending
// ---------------------------------------------------------------------------

/**
 * Send a single missing-caller alert to the Zypress Others group.
 *
 * Returns the Telegram message ID on success (needed for response tracking).
 */
export async function sendMissingCallerAlert(
  call: MissingCallerInfo
): Promise<{ success: boolean; messageId?: number; error?: string }> {
  // Guard: fail loudly if chat ID is unconfigured
  if (ZYPRESS_OTHERS_CHAT_ID === 0) {
    throw new Error(
      "ZYPRESS_OTHERS_CHAT_ID is 0 (unconfigured) — configure before sending alerts"
    );
  }

  try {
    const message = formatMissingCallerAlert(call);
    const bot = getTelegramBot();

    const result = (await bot.sendMessage({
      chatId: ZYPRESS_OTHERS_CHAT_ID,
      text: message,
    })) as { message_id: number };

    const messageId = result.message_id;

    logger.info("Sent missing caller alert", {
      category: LogCategory.GENERAL,
      operation: "sendMissingCallerAlert",
      messageId: String(messageId),
      callDate: call.callDate,
    });

    return { success: true, messageId };
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error("Failed to send missing caller alert", err, {
      category: LogCategory.GENERAL,
      operation: "sendMissingCallerAlert",
      callDate: call.callDate,
    });
    return { success: false, error: err.message };
  }
}

/**
 * Send alerts for multiple missing callers with rate-limit-safe delays.
 *
 * Telegram Bot API allows ~20 messages/min to the same group.
 * We add a 1-second delay between messages to stay well within limits.
 */
export async function sendBatchMissingCallerAlerts(
  calls: MissingCallerInfo[]
): Promise<{ sent: number; failed: number; messageIds: number[] }> {
  let sent = 0;
  let failed = 0;
  const messageIds: number[] = [];

  for (let i = 0; i < calls.length; i++) {
    const result = await sendMissingCallerAlert(calls[i]);

    if (result.success && result.messageId) {
      sent++;
      messageIds.push(result.messageId);
    } else {
      failed++;
    }

    // Rate limit: 1-second delay between messages (except after the last one)
    if (i < calls.length - 1) {
      await new Promise((resolve) => setTimeout(resolve, 1000));
    }
  }

  logger.info("Batch alert sending complete", {
    category: LogCategory.GENERAL,
    operation: "sendBatchMissingCallerAlerts",
    sent: String(sent),
    failed: String(failed),
    total: String(calls.length),
  });

  return { sent, failed, messageIds };
}

/**
 * Shared Database Client & Operations
 *
 * Singleton Supabase client for all Edge Functions.
 * Includes chat history and message deduplication operations.
 */

import {
  createClient,
  type SupabaseClient,
} from "https://esm.sh/@supabase/supabase-js@2.39.0";
import { LogCategory, logger } from "../sophia-bot/utils/logger.ts";
import { withRetry } from "../sophia-bot/utils/retry.ts";
/** A single chat message in Gemini's expected format */
export interface ChatMessage {
  role: "user" | "model";
  parts: Array<{ text: string }>;
}

// Singleton client
let _client: SupabaseClient | null = null;

/**
 * Get the shared Supabase admin client (singleton)
 */
export const getSupabaseAdmin = (): SupabaseClient => {
  if (!_client) {
    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const supabaseKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!supabaseUrl || !supabaseKey) {
      throw new Error("Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY");
    }

    _client = createClient(supabaseUrl, supabaseKey);
  }
  return _client;
};

/**
 * Fetch the last 10 messages for a user, ordered chronologically (oldest to newest)
 * This is the format Gemini expects for conversation history
 */
export const getHistory = async (userId: string): Promise<ChatMessage[]> => {
  const supabase = getSupabaseAdmin();

  const { data, error } = await withRetry(
    async () => {
      const result = await supabase
        .from("chat_history")
        .select("role, parts")
        .eq("user_id", userId)
        .order("created_at", { ascending: false })
        .limit(10);
      if (result.error) throw result.error;
      return result;
    },
    { maxRetries: 2, baseDelayMs: 200 },
    "getHistory"
  );

  if (error) {
    logger.error("Error fetching history", error, {
      category: LogCategory.DATABASE,
      operation: "getHistory",
    });
    throw error;
  }

  // Reverse to get chronological order (oldest -> newest) for Gemini
  const reversed = (data || []).reverse();

  // Ensure parts is always an array of objects with text property
  return reversed.map((msg) => ({
    role: msg.role as "user" | "model",
    parts: Array.isArray(msg.parts) ? msg.parts : [{ text: String(msg.parts) }],
  }));
};

/**
 * Insert a new message into chat_history
 */
export const addMessage = async (
  userId: string,
  role: "user" | "model",
  text: string
): Promise<void> => {
  const supabase = getSupabaseAdmin();

  const { error } = await withRetry(
    async () => {
      const result = await supabase.from("chat_history").insert([
        {
          user_id: userId,
          role,
          parts: [{ text }],
        },
      ]);
      if (result.error) throw result.error;
      return result;
    },
    { maxRetries: 2, baseDelayMs: 200 },
    "addMessage"
  );

  if (error) {
    logger.error("Error adding message", error, {
      category: LogCategory.DATABASE,
      operation: "addMessage",
    });
    throw error;
  }
};

/**
 * Attempts to claim a message for processing using atomic INSERT.
 * Returns true if this request should process the message.
 * Returns false if another request already claimed it (duplicate).
 *
 * This uses the database's unique constraint to handle race conditions:
 * - First INSERT succeeds -> this request processes the message
 * - Subsequent INSERTs fail with 23505 -> duplicates, skip processing
 */
export const claimMessageForProcessing = async (
  messageKey: string,
  phoneNumber: string
): Promise<boolean> => {
  const supabase = getSupabaseAdmin();

  try {
    const { error } = await supabase.from("processed_webhooks").insert([
      {
        message_key: messageKey,
        phone_number: phoneNumber,
      },
    ]);

    if (error) {
      // Unique constraint violation (23505) = another request already claimed this message
      if (error.code === "23505") {
        logger.info("Message already claimed by another request", {
          category: LogCategory.DATABASE,
          operation: "claimMessageForProcessing",
          messageKey,
        });
        return false; // Don't process - it's a duplicate
      }

      // Other errors - log but allow processing (fail-open to avoid blocking messages)
      logger.error("Error claiming message", error, {
        category: LogCategory.DATABASE,
        operation: "claimMessageForProcessing",
        messageKey,
      });
      return true;
    }

    // Insert succeeded - this request should process the message
    logger.info("Successfully claimed message for processing", {
      category: LogCategory.DATABASE,
      operation: "claimMessageForProcessing",
      messageKey,
    });
    return true;
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error("Exception claiming message", err, {
      category: LogCategory.DATABASE,
      operation: "claimMessageForProcessing",
      messageKey,
    });
    // On exception, allow processing (fail-open)
    return true;
  }
};

/**
 * @deprecated Use claimMessageForProcessing() instead for race-condition-safe deduplication
 */
export const isMessageProcessed = async (
  messageKey: string
): Promise<boolean> => {
  const supabase = getSupabaseAdmin();

  try {
    const { data, error } = await supabase
      .from("processed_webhooks")
      .select("id")
      .eq("message_key", messageKey)
      .limit(1);

    if (error) {
      logger.error("Error checking processed webhooks", error, {
        category: LogCategory.DATABASE,
        operation: "isMessageProcessed",
        messageKey,
      });
      return false;
    }

    return data && data.length > 0;
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error("Exception checking processed webhooks", err, {
      category: LogCategory.DATABASE,
      operation: "isMessageProcessed",
      messageKey,
    });
    return false;
  }
};

/**
 * @deprecated Use claimMessageForProcessing() instead for race-condition-safe deduplication
 */
export const markMessageProcessed = async (
  messageKey: string,
  phoneNumber: string
): Promise<void> => {
  const supabase = getSupabaseAdmin();

  try {
    const { error } = await supabase.from("processed_webhooks").insert([
      {
        message_key: messageKey,
        phone_number: phoneNumber,
      },
    ]);

    if (error && error.code !== "23505") {
      logger.error("Error marking message as processed", error, {
        category: LogCategory.DATABASE,
        operation: "markMessageProcessed",
        messageKey,
      });
    }
  } catch (error) {
    const err = error instanceof Error ? error : new Error(String(error));
    logger.error("Exception marking message as processed", err, {
      category: LogCategory.DATABASE,
      operation: "markMessageProcessed",
      messageKey,
    });
  }
};

// =====================================================
// Document Tracking for Email Attachments
// =====================================================

export interface LastDocument {
  document_url: string;
  document_name: string;
  document_type: string | null;
  created_at: string;
}

/**
 * Save a generated document URL for later email attachment
 */
export const saveLastDocument = async (
  userId: string,
  documentUrl: string,
  documentName: string,
  documentType?: string
): Promise<void> => {
  const supabase = getSupabaseAdmin();

  // Delete old documents for this user (keep only recent ones)
  await supabase
    .from("last_documents")
    .delete()
    .eq("user_id", userId)
    .lt("created_at", new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString()); // Older than 24h

  // Insert new document
  const { error } = await supabase.from("last_documents").insert([
    {
      user_id: userId,
      document_url: documentUrl,
      document_name: documentName,
      document_type: documentType || null,
    },
  ]);

  if (error) {
    logger.error("Error saving last document", error, {
      category: LogCategory.DATABASE,
      operation: "saveLastDocument",
      documentName,
    });
  } else {
    logger.info("Saved document for user", {
      category: LogCategory.DATABASE,
      operation: "saveLastDocument",
      documentName,
    });
  }
};

/**
 * Get the most recent document for a user (for email attachment)
 */
export const getLastDocument = async (
  userId: string
): Promise<LastDocument | null> => {
  const supabase = getSupabaseAdmin();

  const { data, error } = await supabase
    .from("last_documents")
    .select("document_url, document_name, document_type, created_at")
    .eq("user_id", userId)
    .order("created_at", { ascending: false })
    .limit(1)
    .single();

  if (error || !data) {
    return null;
  }

  return data as LastDocument;
};

/**
 * Clear document after successful email send
 */
export const clearLastDocument = async (userId: string): Promise<void> => {
  const supabase = getSupabaseAdmin();

  await supabase.from("last_documents").delete().eq("user_id", userId);

  logger.info("Cleared documents for user", {
    category: LogCategory.DATABASE,
    operation: "clearLastDocument",
  });
};

// =====================================================
// Listing Upload Tracking (for publication notifications)
// =====================================================

/**
 * Track a successfully uploaded listing for later notification when published.
 * Table: listing_uploads (see SQL at bottom of this file)
 */
export const trackListingUpload = async (
  zyprusListingId: string,
  agentPhone: string,
  agentName: string,
  propertyTitle: string,
  listingUrl: string
): Promise<void> => {
  const supabase = getSupabaseAdmin();

  const { error } = await supabase.from("listing_uploads").insert([
    {
      zyprus_listing_id: zyprusListingId,
      agent_phone: agentPhone,
      agent_name: agentName,
      property_title: propertyTitle,
      listing_url: listingUrl,
      status: "draft",
    },
  ]);

  if (error) {
    // Non-critical — don't fail the upload over tracking
    logger.error("Error tracking listing upload", error, {
      category: LogCategory.DATABASE,
      operation: "trackListingUpload",
      zyprusListingId,
    });
  }
};

/**
 * Get all draft listings that haven't been checked recently.
 * Used by the polling function to avoid hammering the API.
 */
export const getPendingListingUploads = async (): Promise<
  Array<{
    id: string;
    zyprus_listing_id: string;
    agent_phone: string;
    agent_name: string;
    property_title: string;
    listing_url: string;
    created_at: string;
  }>
> => {
  const supabase = getSupabaseAdmin();

  // Only check listings that are still "draft" and were uploaded at least 5 min ago
  // (gives reviewer time to publish before we start polling)
  const fiveMinAgo = new Date(Date.now() - 5 * 60 * 1000).toISOString();

  const { data, error } = await supabase
    .from("listing_uploads")
    .select(
      "id, zyprus_listing_id, agent_phone, agent_name, property_title, listing_url, created_at"
    )
    .eq("status", "draft")
    .lt("created_at", fiveMinAgo)
    .order("created_at", { ascending: true })
    .limit(20);

  if (error || !data) {
    return [];
  }

  return data;
};

/**
 * Mark a listing as published (notification sent).
 */
export const markListingPublished = async (id: string): Promise<void> => {
  const supabase = getSupabaseAdmin();

  await supabase
    .from("listing_uploads")
    .update({ status: "published", notified_at: new Date().toISOString() })
    .eq("id", id);
};

/**
 * Mark a listing as expired (still draft after 30 days — stop checking).
 */
export const markListingExpired = async (id: string): Promise<void> => {
  const supabase = getSupabaseAdmin();

  await supabase
    .from("listing_uploads")
    .update({ status: "expired" })
    .eq("id", id);
};

